const book: BibleBook = {
  id: 'luke',
  name: 'Lucas',
  englishName: 'Luke',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Since many have undertaken to set in order a narrative concerning those matters which have been fulfilled among us,', pt: 'Visto que muitos têm empreendido fazer uma narração coordenada dos fatos que entre nós se realizaram,' },
      { v: 2, en: 'even as those who from the beginning were eyewitnesses and servants of the word delivered them to us,', pt: 'segundo no-los transmitiram os que desde o princípio foram testemunhas oculares e ministros da palavra,' },
      { v: 3, en: 'it seemed good to me also, having traced the course of all things accurately from the first, to write to you in order, most excellent Theophilus;', pt: 'também a mim, depois de haver investido tudo cuidadosamente desde o começo, pareceu-me bem, ó excelentíssimo Teófilo, escrever-te uma narração em ordem.' },
      { v: 4, en: 'that you might know the certainty concerning the things in which you were instructed.', pt: 'para que conheças plenamente a verdade das coisas em que foste instruído.' },
      { v: 5, en: 'There was in the days of Herod, the king of Judea, a certain priest named Zacharias, of the priestly division of Abijah. He had a wife of the daughters of Aaron, and her name was Elizabeth.', pt: 'Houve nos dias do Rei Herodes, rei da Judéia, um sacerdote chamado Zacarias, da turma de Abias; e sua mulher era descendente de Arão, e chamava-se Isabel.' },
      { v: 6, en: 'They were both righteous before God, walking blamelessly in all the commandments and ordinances of the Lord.', pt: 'Ambos eram justos diante de Deus, andando irrepreensíveis em todos os mandamentos e preceitos do Senhor.' },
      { v: 7, en: 'But they had no child, because Elizabeth was barren, and they both were well advanced in years.', pt: 'Mas não tinham filhos, porque Isabel era estéril, e ambos avançados em idade.' },
      { v: 8, en: 'Now while he executed the priest’s office before God in the order of his division,', pt: 'Ora, estando ele a exercer as funções sacerdotais perante Deus, na ordem da sua turma,' },
      { v: 9, en: 'according to the custom of the priest’s office, his lot was to enter into the temple of the Lord and burn incense.', pt: 'segundo o costume do sacerdócio, coube-lhe por sorte entrar no santuário do Senhor, para oferecer o incenso;' },
      { v: 10, en: 'The whole multitude of the people were praying outside at the hour of incense.', pt: 'e toda a multidão do povo orava da parte de fora, à hora do incenso.' },
      { v: 11, en: 'An angel of the Lord appeared to him, standing on the right side of the altar of incense.', pt: 'Apareceu-lhe, então, um anjo do Senhor, em pé à direita do altar do incenso.' },
      { v: 12, en: 'Zacharias was troubled when he saw him, and fear fell upon him.', pt: 'E Zacarias, vendo-o, ficou turbado, e o temor o assaltou.' },
      { v: 13, en: 'But the angel said to him, “Don’t be afraid, Zacharias, because your request has been heard, and your wife, Elizabeth, will bear you a son, and you shall call his name John.', pt: 'Mas o anjo lhe disse: Não temais, Zacarias; porque a tua oração foi ouvida, e Isabel, tua mulher, te dará à luz um filho, e lhe porás o nome de João;' },
      { v: 14, en: 'You will have joy and gladness; and many will rejoice at his birth.', pt: 'e terás alegria e regozijo, e muitos se alegrarão com o seu nascimento;' },
      { v: 15, en: 'For he will be great in the sight of the Lord, and he will drink no wine nor strong drink. He will be filled with the Holy Spirit, even from his mother’s womb.', pt: 'porque ele será grande diante do Senhor; não beberá vinho, nem bebida forte; e será cheio do Espírito Santo já desde o ventre de sua mãe;' },
      { v: 16, en: 'He will turn many of the children of Israel to the Lord, their God.', pt: 'converterá muitos dos filhos de Israel ao Senhor seu Deus;' },
      { v: 17, en: 'He will go before him in the spirit and power of Elijah, ‘to turn the hearts of the fathers to the children,’ and the disobedient to the wisdom of the just; to prepare a people prepared for the Lord.”', pt: 'irá adiante dele no espírito e poder de Elias, para converter os corações dos pais aos filhos, e os rebeldes à prudência dos justos, a fim de preparar para o Senhor um povo apercebido.' },
      { v: 18, en: 'Zacharias said to the angel, “How can I be sure of this? For I am an old man, and my wife is well advanced in years.”', pt: 'Disse então Zacarias ao anjo: Como terei certeza disso? pois eu sou velho, e minha mulher também está avançada em idade.' },
      { v: 19, en: 'The angel answered him, “I am Gabriel, who stands in the presence of God. I was sent to speak to you, and to bring you this good news.', pt: 'Ao que lhe respondeu o anjo: Eu sou Gabriel, que assisto diante de Deus, e fui enviado para te falar e te dar estas boas novas;' },
      { v: 20, en: 'Behold, you will be silent and not able to speak, until the day that these things will happen, because you didn’t believe my words, which will be fulfilled in their proper time.”', pt: 'e eis que ficarás mudo, e não poderás falar até o dia em que estas coisas aconteçam; porquanto não creste nas minhas palavras, que a seu tempo hão de cumprir-se.' },
      { v: 21, en: 'The people were waiting for Zacharias, and they marveled that he delayed in the temple.', pt: 'O povo estava esperando Zacarias, e se admirava da sua demora no santuário.' },
      { v: 22, en: 'When he came out, he could not speak to them, and they perceived that he had seen a vision in the temple. He continued making signs to them, and remained mute.', pt: 'Quando saiu, porém, não lhes podia falar, e perceberam que tivera uma visão no santuário. E falava-lhes por acenos, mas permanecia mudo.' },
      { v: 23, en: 'When the days of his service were fulfilled, he departed to his house.', pt: 'E, terminados os dias do seu ministério, voltou para casa.' },
      { v: 24, en: 'After these days Elizabeth, his wife, conceived, and she hid herself five months, saying,', pt: 'Depois desses dias Isabel, sua mulher, concebeu, e por cinco meses se ocultou, dizendo:' },
      { v: 25, en: '“Thus has the Lord done to me in the days in which he looked at me, to take away my reproach among men.”', pt: 'Assim me fez o Senhor nos dias em que atentou para mim, a fim de acabar com o meu opróbrio diante dos homens.' },
      { v: 26, en: 'Now in the sixth month, the angel Gabriel was sent from God to a city of Galilee, named Nazareth,', pt: 'Ora, no sexto mês, foi o anjo Gabriel enviado por Deus a uma cidade da Galiléia, chamada Nazaré,' },
      { v: 27, en: 'to a virgin pledged to be married to a man whose name was Joseph, of David’s house. The virgin’s name was Mary.', pt: 'a uma virgem desposada com um varão cujo nome era José, da casa de Davi; e o nome da virgem era Maria.' },
      { v: 28, en: 'Having come in, the angel said to her, “Rejoice, you highly favored one! The Lord is with you. Blessed are you among women!”', pt: 'E, entrando o anjo onde ela estava disse: Salve, agraciada; o Senhor é contigo.' },
      { v: 29, en: 'But when she saw him, she was greatly troubled at the saying, and considered what kind of salutation this might be.', pt: 'Ela, porém, ao ouvir estas palavras, turbou-se muito e pôs-se a pensar que saudação seria essa.' },
      { v: 30, en: 'The angel said to her, “Don’t be afraid, Mary, for you have found favor with God.', pt: 'Disse-lhe então o anjo: Não temas, Maria; pois achaste graça diante de Deus.' },
      { v: 31, en: 'Behold, you will conceive in your womb, and give birth to a son, and will call his name ‘Jesus.’', pt: 'Eis que conceberás e darás à luz um filho, ao qual porás o nome de Jesus.' },
      { v: 32, en: 'He will be great, and will be called the Son of the Most High. The Lord God will give him the throne of his father, David,', pt: 'Este será grande e será chamado filho do Altíssimo; o Senhor Deus lhe dará o trono de Davi seu pai;' },
      { v: 33, en: 'and he will reign over the house of Jacob forever. There will be no end to his Kingdom.”', pt: 'e reinará eternamente sobre a casa de Jacó, e o seu reino não terá fim.' },
      { v: 34, en: 'Mary said to the angel, “How can this be, seeing I am a virgin?”', pt: 'Então Maria perguntou ao anjo: Como se fará isso, uma vez que não conheço varão?' },
      { v: 35, en: 'The angel answered her, “The Holy Spirit will come on you, and the power of the Most High will overshadow you. Therefore also the holy one who is born from you will be called the Son of God.', pt: 'Respondeu-lhe o anjo: Virá sobre ti o Espírito Santo, e o poder do Altíssimo te cobrirá com a sua sombra; por isso o que há de nascer será chamado santo, Filho de Deus.' },
      { v: 36, en: 'Behold, Elizabeth, your relative, also has conceived a son in her old age; and this is the sixth month with her who was called barren.', pt: 'Eis que também Isabel, tua parenta concebeu um filho em sua velhice; e é este o sexto mês para aquela que era chamada estéril;' },
      { v: 37, en: 'For nothing spoken by God is impossible.”', pt: 'porque para Deus nada será impossível.' },
      { v: 38, en: 'Mary said, “Behold, the servant of the Lord; let it be done to me according to your word.” The angel departed from her.', pt: 'Disse então Maria. Eis aqui a serva do Senhor; cumpra-se em mim segundo a tua palavra. E o anjo ausentou-se dela.' },
      { v: 39, en: 'Mary arose in those days and went into the hill country with haste, into a city of Judah,', pt: 'Naqueles dias levantou-se Maria, foi apressadamente à região montanhosa, a uma cidade de Judá,' },
      { v: 40, en: 'and entered into the house of Zacharias and greeted Elizabeth.', pt: 'entrou em casa de Zacarias e saudou a Isabel.' },
      { v: 41, en: 'When Elizabeth heard Mary’s greeting, the baby leaped in her womb, and Elizabeth was filled with the Holy Spirit.', pt: 'Ao ouvir Isabel a saudação de Maria, saltou a criancinha no seu ventre, e Isabel ficou cheia do Espírito Santo,' },
      { v: 42, en: 'She called out with a loud voice, and said, “Blessed are you among women, and blessed is the fruit of your womb!', pt: 'e exclamou em alta voz: Bendita és tu entre as mulheres, e bendito é o fruto do teu ventre!' },
      { v: 43, en: 'Why am I so favored, that the mother of my Lord should come to me?', pt: 'E donde me provém isto, que venha visitar-me a mãe do meu Senhor?' },
      { v: 44, en: 'For behold, when the voice of your greeting came into my ears, the baby leaped in my womb for joy!', pt: 'Pois logo que me soou aos ouvidos a voz da tua saudação, a criancinha saltou de alegria dentro de mim.' },
      { v: 45, en: 'Blessed is she who believed, for there will be a fulfillment of the things which have been spoken to her from the Lord!”', pt: 'Bem-aventurada aquela que creu que se hão de cumprir as coisas que da parte do Senhor lhe foram ditas.' },
      { v: 46, en: 'Mary said, “My soul magnifies the Lord.', pt: 'Disse então Maria: A minha alma engrandece ao Senhor,' },
      { v: 47, en: 'My spirit has rejoiced in God my Savior,', pt: 'e o meu espírito exulta em Deus meu Salvador;' },
      { v: 48, en: 'for he has looked at the humble state of his servant. For behold, from now on, all generations will call me blessed.', pt: 'porque atentou na condição humilde de sua serva. Desde agora, pois, todas as gerações me chamarão bem-aventurada,' },
      { v: 49, en: 'For he who is mighty has done great things for me. Holy is his name.', pt: 'porque o Poderoso me fez grandes coisas; e santo é o seu nome.' },
      { v: 50, en: 'His mercy is for generations of generations on those who fear him.', pt: 'E a sua misericórdia vai de geração em geração sobre os que o temem.' },
      { v: 51, en: 'He has shown strength with his arm. He has scattered the proud in the imagination of their hearts.', pt: 'Com o seu braço manifestou poder; dissipou os que eram soberbos nos pensamentos de seus corações;' },
      { v: 52, en: 'He has put down princes from their thrones. And has exalted the lowly.', pt: 'depôs dos tronos os poderosos, e elevou os humildes.' },
      { v: 53, en: 'He has filled the hungry with good things. He has sent the rich away empty.', pt: 'Aos famintos encheu de bens, e vazios despediu os ricos.' },
      { v: 54, en: 'He has given help to Israel, his servant, that he might remember mercy,', pt: 'Auxiliou a Isabel, seu servo, lembrando-se de misericórdia' },
      { v: 55, en: 'As he spoke to our fathers, to Abraham and his offspring forever.”', pt: '(como falou a nossos pais) para com Abraão e a sua descendência para sempre.' },
      { v: 56, en: 'Mary stayed with her about three months, and then returned to her house.', pt: 'E Maria ficou com ela cerca de três meses; e depois voltou para sua casa.' },
      { v: 57, en: 'Now the time that Elizabeth should give birth was fulfilled, and she gave birth to a son.', pt: 'Ora, completou-se para Isabel o tempo de dar à luz, e teve um filho.' },
      { v: 58, en: 'Her neighbors and her relatives heard that the Lord had magnified his mercy towards her, and they rejoiced with her.', pt: 'Ouviram seus vizinhos e parentes que o Senhor lhe multiplicara a sua misericórdia, e se alegravam com ela.' },
      { v: 59, en: 'On the eighth day, they came to circumcise the child; and they would have called him Zacharias, after the name of his father.', pt: 'Sucedeu, pois, no oitavo dia, que vieram circuncidar o menino; e queriam dar-lhe o nome de seu pai, Zacarias.' },
      { v: 60, en: 'His mother answered, “Not so; but he will be called John.”', pt: 'Respondeu, porém, sua mãe: De modo nenhum, mas será chamado João.' },
      { v: 61, en: 'They said to her, “There is no one among your relatives who is called by this name.”', pt: 'Ao que lhe disseram: Ninguém há na tua parentela que se chame por este nome.' },
      { v: 62, en: 'They made signs to his father, what he would have him called.', pt: 'E perguntaram por acenos ao pai como queria que se chamasse.' },
      { v: 63, en: 'He asked for a writing tablet, and wrote, “His name is John.” They all marveled.', pt: 'E pedindo ele uma tabuinha, escreveu: Seu nome é João. E todos se admiraram.' },
      { v: 64, en: 'His mouth was opened immediately, and his tongue freed, and he spoke, blessing God.', pt: 'Imediatamente a boca se lhe abriu, e a língua se lhe soltou; louvando a Deus.' },
      { v: 65, en: 'Fear came on all who lived around them, and all these sayings were talked about throughout all the hill country of Judea.', pt: 'Então veio temor sobre todos os seus vizinhos; e em toda a região montanhosa da Judéia foram divulgadas todas estas coisas.' },
      { v: 66, en: 'All who heard them laid them up in their heart, saying, “What then will this child be?” The hand of the Lord was with him.', pt: 'E todos os que delas souberam as guardavam no coração, dizendo: Que virá a ser, então, este menino? Pois a mão do Senhor estava com ele.' },
      { v: 67, en: 'His father, Zacharias, was filled with the Holy Spirit, and prophesied, saying,', pt: 'Zacarias, seu pai, ficou cheio do Espírito Santo e profetizou, dizendo:' },
      { v: 68, en: '“Blessed be the Lord, the God of Israel, for he has visited and redeemed his people;', pt: 'Bendito, seja o Senhor Deus de Israel, porque visitou e remiu o seu povo,' },
      { v: 69, en: 'and has raised up a horn of salvation for us in the house of his servant David', pt: 'e para nós fez surgir uma salvação poderosa na casa de Davi, seu servo;' },
      { v: 70, en: '(as he spoke by the mouth of his holy prophets who have been from of old),', pt: 'assim como desde os tempos antigos tem anunciado pela boca dos seus santos profetas;' },
      { v: 71, en: 'salvation from our enemies, and from the hand of all who hate us;', pt: 'para nos livrar dos nossos inimigos e da mão de todos os que nos odeiam;' },
      { v: 72, en: 'to show mercy towards our fathers, to remember his holy covenant,', pt: 'para usar de misericórdia com nossos pais, e lembrar-se do seu santo pacto' },
      { v: 73, en: 'the oath which he swore to Abraham, our father,', pt: 'e do juramento que fez a Abrão, nosso pai,' },
      { v: 74, en: 'to grant to us that we, being delivered out of the hand of our enemies, should serve him without fear,', pt: 'de conceder-nos que, libertados da mão de nossos inimigos, o servíssemos sem temor,' },
      { v: 75, en: 'In holiness and righteousness before him all the days of our life.', pt: 'em santidade e justiça perante ele, todos os dias da nossa vida.' },
      { v: 76, en: 'And you, child, will be called a prophet of the Most High, for you will go before the face of the Lord to prepare his ways,', pt: 'E tu, menino, serás chamado profeta do Altíssimo, porque irás ante a face do Senhor, a preparar os seus caminhos;' },
      { v: 77, en: 'to give knowledge of salvation to his people by the remission of their sins,', pt: 'para dar ao seu povo conhecimento da salvação, na remissão dos seus pecados,' },
      { v: 78, en: 'because of the tender mercy of our God, whereby the dawn from on high will visit us,', pt: 'graças à entrenhável misericórdia do nosso Deus, pela qual nos há de visitar a aurora lá do alto,' },
      { v: 79, en: 'to shine on those who sit in darkness and the shadow of death; to guide our feet into the way of peace.”', pt: 'para alumiar aos que jazem nas trevas e na sombra da morte, a fim de dirigir os nossos pés no caminho da paz.' },
      { v: 80, en: 'The child was growing, and becoming strong in spirit, and was in the desert until the day of his public appearance to Israel.', pt: 'Ora, o menino crescia, e se robustecia em espírito; e habitava nos desertos até o dia da sua manifestação a Israel.' },
    ],
    2: [
      { v: 1, en: 'Now in those days, a decree went out from Caesar Augustus that all the world should be enrolled.', pt: 'Naqueles dias saiu um decreto da parte de César Augusto, para que todo o mundo fosse recenseado.' },
      { v: 2, en: 'This was the first enrollment made when Quirinius was governor of Syria.', pt: 'Este primeiro recenseamento foi feito quando Quirínio era governador da Síria.' },
      { v: 3, en: 'All went to enroll themselves, everyone to his own city.', pt: 'E todos iam alistar-se, cada um à sua própria cidade.' },
      { v: 4, en: 'Joseph also went up from Galilee, out of the city of Nazareth, into Judea, to David’s city, which is called Bethlehem, because he was of the house and family of David;', pt: 'Subiu também José, da Galiléia, da cidade de Nazaré, à cidade de Davi, chamada Belém, porque era da casa e família de Davi,' },
      { v: 5, en: 'to enroll himself with Mary, who was pledged to be married to him as wife, being pregnant.', pt: 'a fim de alistar-se com Maria, sua esposa, que estava grávida.' },
      { v: 6, en: 'While they were there, the day had come for her to give birth.', pt: 'Enquanto estavam ali, chegou o tempo em que ela havia de dar à luz,' },
      { v: 7, en: 'She gave birth to her firstborn son. She wrapped him in bands of cloth, and laid him in a feeding trough, because there was no room for them in the inn.', pt: 'e teve a seu filho primogênito; envolveu-o em faixas e o deitou em uma manjedoura, porque não havia lugar para eles na estalagem.' },
      { v: 8, en: 'There were shepherds in the same country staying in the field, and keeping watch by night over their flock.', pt: 'Ora, havia naquela mesma região pastores que estavam no campo, e guardavam durante as vigílias da noite o seu rebanho.' },
      { v: 9, en: 'Behold, an angel of the Lord stood by them, and the glory of the Lord shone around them, and they were terrified.', pt: 'E um anjo do Senhor apareceu-lhes, e a glória do Senhor os cercou de resplendor; pelo que se encheram de grande temor.' },
      { v: 10, en: 'The angel said to them, “Don’t be afraid, for behold, I bring you good news of great joy which will be to all the people.', pt: 'O anjo, porém, lhes disse: Não temais, porquanto vos trago novas de grande alegria que o será para todo o povo:' },
      { v: 11, en: 'For there is born to you today, in David’s city, a Savior, who is Christ the Lord.', pt: 'É que vos nasceu hoje, na cidade de Davi, o Salvador, que é Cristo, o Senhor.' },
      { v: 12, en: 'This is the sign to you: you will find a baby wrapped in strips of cloth, lying in a feeding trough.”', pt: 'E isto vos será por sinal: Achareis um menino envolto em faixas, e deitado em uma manjedoura.' },
      { v: 13, en: 'Suddenly, there was with the angel a multitude of the heavenly army praising God, and saying,', pt: 'Então, de repente, apareceu junto ao anjo grande multidão da milícia celestial, louvando a Deus e dizendo:' },
      { v: 14, en: '“Glory to God in the highest, on earth peace, good will toward men.”', pt: 'Glória a Deus nas maiores alturas, e paz na terra entre os homens de boa vontade.' },
      { v: 15, en: 'When the angels went away from them into the sky, the shepherds said to one another, “Let’s go to Bethlehem, now, and see this thing that has happened, which the Lord has made known to us.”', pt: 'E logo que os anjos se retiraram deles para o céu, diziam os pastores uns aos outros: Vamos já até Belém, e vejamos isso que aconteceu e que o Senhor nos deu a conhecer.' },
      { v: 16, en: 'They came with haste, and found both Mary and Joseph, and the baby was lying in the feeding trough.', pt: 'Foram, pois, a toda a pressa, e acharam Maria e José, e o menino deitado na manjedoura;' },
      { v: 17, en: 'When they saw it, they publicized widely the saying which was spoken to them about this child.', pt: 'e, vendo-o, divulgaram a palavra que acerca do menino lhes fora dita;' },
      { v: 18, en: 'All who heard it wondered at the things which were spoken to them by the shepherds.', pt: 'e todos os que a ouviram se admiravam do que os pastores lhes diziam.' },
      { v: 19, en: 'But Mary kept all these sayings, pondering them in her heart.', pt: 'Maria, porém, guardava todas estas coisas, meditando-as em seu coração.' },
      { v: 20, en: 'The shepherds returned, glorifying and praising God for all the things that they had heard and seen, just as it was told them.', pt: 'E voltaram os pastores, glorificando e louvando a Deus por tudo o que tinham ouvido e visto, como lhes fora dito.' },
      { v: 21, en: 'When eight days were fulfilled for the circumcision of the child, his name was called Jesus, which was given by the angel before he was conceived in the womb.', pt: 'Quando se completaram os oito dias para ser circuncidado o menino, foi-lhe dado o nome de Jesus, que pelo anjo lhe fora posto antes de ser concebido.' },
      { v: 22, en: 'When the days of their purification according to the law of Moses were fulfilled, they brought him up to Jerusalem, to present him to the Lord', pt: 'Terminados os dias da purificação, segundo a lei de Moisés, levaram-no a Jerusalém, para apresentá-lo ao Senhor' },
      { v: 23, en: '(as it is written in the law of the Lord, “Every male who opens the womb shall be called holy to the Lord”),', pt: '(conforme está escrito na lei do Senhor: Todo primogênito será consagrado ao Senhor),' },
      { v: 24, en: 'and to offer a sacrifice according to that which is said in the law of the Lord, “A pair of turtledoves, or two young pigeons.”', pt: 'e para oferecerem um sacrifício segundo o disposto na lei do Senhor: um par de rolas, ou dois pombinhos.' },
      { v: 25, en: 'Behold, there was a man in Jerusalem whose name was Simeon. This man was righteous and devout, looking for the consolation of Israel, and the Holy Spirit was on him.', pt: 'Ora, havia em Jerusalém um homem cujo nome era Simeão; e este homem, justo e temente a Deus, esperava a consolação de Israel; e o Espírito Santo estava sobre ele.' },
      { v: 26, en: 'It had been revealed to him by the Holy Spirit that he should not see death before he had seen the Lord’s Christ.', pt: 'E lhe fora revelado pelo Espírito Santo que ele não morreria antes de ver o Cristo do Senhor.' },
      { v: 27, en: 'He came in the Spirit into the temple. When the parents brought in the child, Jesus, that they might do concerning him according to the custom of the law,', pt: 'Assim pelo Espírito foi ao templo; e quando os pais trouxeram o menino Jesus, para fazerem por ele segundo o costume da lei,' },
      { v: 28, en: 'then he received him into his arms, and blessed God, and said,', pt: 'Simeão o tomou em seus braços, e louvou a Deus, e disse:' },
      { v: 29, en: '“Now you are releasing your servant, Master, according to your word, in peace;', pt: 'Agora, Senhor, despedes em paz o teu servo, segundo a tua palavra;' },
      { v: 30, en: 'for my eyes have seen your salvation,', pt: 'pois os meus olhos já viram a tua salvação,' },
      { v: 31, en: 'which you have prepared before the face of all peoples;', pt: 'a qual tu preparaste ante a face de todos os povos;' },
      { v: 32, en: 'a light for revelation to the nations, and the glory of your people Israel.”', pt: 'luz para revelação aos gentios, e para glória do teu povo Israel.' },
      { v: 33, en: 'Joseph and his mother were marveling at the things which were spoken concerning him,', pt: 'Enquanto isso, seu pai e sua mãe se admiravam das coisas que deles se diziam.' },
      { v: 34, en: 'and Simeon blessed them, and said to Mary, his mother, “Behold, this child is set for the falling and the rising of many in Israel, and for a sign which is spoken against.', pt: 'E Simeão os abençoou, e disse a Maria, mãe do menino: Eis que este é posto para queda e para levantamento de muitos em Israel, e para ser alvo de contradição,' },
      { v: 35, en: 'Yes, a sword will pierce through your own soul, that the thoughts of many hearts may be revealed.”', pt: 'sim, e uma espada traspassará a tua própria alma, para que se manifestem os pensamentos de muitos corações.' },
      { v: 36, en: 'There was one Anna, a prophetess, the daughter of Phanuel, of the tribe of Asher (she was of a great age, having lived with a husband seven years from her virginity,', pt: 'Havia também uma profetisa, Ana, filha de Fanuel, da tribo de Aser. Era já avançada em idade, tendo vivido com o marido sete anos desde a sua virgindade;' },
      { v: 37, en: 'and she had been a widow for about eighty-four years), who didn’t depart from the temple, worshiping with fastings and petitions night and day.', pt: 'e era viúva, de quase oitenta e quatro anos. Não se afastava do templo, servindo a Deus noite e dia em jejuns e orações.' },
      { v: 38, en: 'Coming up at that very hour, she gave thanks to the Lord, and spoke of him to all those who were looking for redemption in Jerusalem.', pt: 'Chegando ela na mesma hora, deu graças a Deus, e falou a respeito do menino a todos os que esperavam a redenção de Jerusalém.' },
      { v: 39, en: 'When they had accomplished all things that were according to the law of the Lord, they returned into Galilee, to their own city, Nazareth.', pt: 'Assim que cumpriram tudo segundo a lei do Senhor, voltaram à Galiléia, para sua cidade de Nazaré.' },
      { v: 40, en: 'The child was growing, and was becoming strong in spirit, being filled with wisdom, and the grace of God was upon him.', pt: 'E o menino ia crescendo e fortalecendo-se, ficando cheio de sabedoria; e a graça de Deus estava sobre ele.' },
      { v: 41, en: 'His parents went every year to Jerusalem at the feast of the Passover.', pt: 'Ora, seus pais iam todos os anos a Jerusalém, à festa da páscoa.' },
      { v: 42, en: 'When he was twelve years old, they went up to Jerusalem according to the custom of the feast,', pt: 'Quando Jesus completou doze anos, subiram eles segundo o costume da festa;' },
      { v: 43, en: 'and when they had fulfilled the days, as they were returning, the boy Jesus stayed behind in Jerusalem. Joseph and his mother didn’t know it,', pt: 'e, terminados aqueles dias, ao regressarem, ficou o menino Jesus em Jerusalém sem o saberem seus pais;' },
      { v: 44, en: 'but supposing him to be in the company, they went a day’s journey, and they looked for him among their relatives and acquaintances.', pt: 'julgando, porém, que estivesse entre os companheiros de viagem, andaram caminho de um dia, e o procuravam entre os parentes e conhecidos;' },
      { v: 45, en: 'When they didn’t find him, they returned to Jerusalem, looking for him.', pt: 'e não o achando, voltaram a Jerusalém em busca dele.' },
      { v: 46, en: 'After three days they found him in the temple, sitting in the middle of the teachers, both listening to them, and asking them questions.', pt: 'E aconteceu que, passados três dias, o acharam no templo, sentado no meio dos doutores, ouvindo-os, e interrogando-os.' },
      { v: 47, en: 'All who heard him were amazed at his understanding and his answers.', pt: 'E todos os que o ouviam se admiravam da sua inteligência e das suas respostas.' },
      { v: 48, en: 'When they saw him, they were astonished, and his mother said to him, “Son, why have you treated us this way? Behold, your father and I were anxiously looking for you.”', pt: 'Quando o viram, ficaram maravilhados, e disse-lhe sua mãe: Filho, por que procedeste assim para conosco? Eis que teu pai e eu ansiosos te procurávamos.' },
      { v: 49, en: 'He said to them, “Why were you looking for me? Didn’t you know that I must be in my Father’s house?”', pt: 'Respondeu-lhes ele: Por que me procuráveis? Não sabíeis que eu devia estar na casa de meu Pai?' },
      { v: 50, en: 'They didn’t understand the saying which he spoke to them.', pt: 'Eles, porém, não entenderam as palavras que lhes dissera.' },
      { v: 51, en: 'And he went down with them, and came to Nazareth. He was subject to them, and his mother kept all these sayings in her heart.', pt: 'Então, descendo com eles, foi para Nazaré, e era-lhes sujeito. E sua mãe guardava todas estas coisas em seu coração.' },
      { v: 52, en: 'And Jesus increased in wisdom and stature, and in favor with God and men.', pt: 'E crescia Jesus em sabedoria, em estatura e em graça diante de Deus e dos homens.' },
    ],
    3: [
      { v: 1, en: 'Now in the fifteenth year of the reign of Tiberius Caesar, Pontius Pilate being governor of Judea, and Herod being tetrarch of Galilee, and his brother Philip tetrarch of the region of Ituraea and Trachonitis, and Lysanias tetrarch of Abilene,', pt: 'No décimo quinto ano do reinado de Tibério César, sendo Pôncio Pilatos governador da Judéia, Herodes tetrarca da Galiléia, seu irmão Filipe tetrarca da região da Ituréia e de Traconites, e Lisânias tetrarca de Abilene,' },
      { v: 2, en: 'in the high priesthood of Annas and Caiaphas, the word of God came to John, the son of Zacharias, in the wilderness.', pt: 'sendo Anás e Caifás sumos sacerdotes, veio a palavra de Deus a João, filho de Zacarias, no deserto.' },
      { v: 3, en: 'He came into all the region around the Jordan, preaching the baptism of repentance for remission of sins.', pt: 'E ele percorreu toda a circunvizinhança do Jordão, pregando o batismo de arrependimento para remissão de pecados;' },
      { v: 4, en: 'As it is written in the book of the words of Isaiah the prophet, “The voice of one crying in the wilderness, ‘Make ready the way of the Lord. Make his paths straight.', pt: 'como está escrito no livro das palavras do profeta Isaías: Voz do que clama no deserto: Preparai o caminho do Senhor; endireitai as suas veredas.' },
      { v: 5, en: 'Every valley will be filled. Every mountain and hill will be brought low. The crooked will become straight, and the rough ways smooth.', pt: 'Todo vale se encherá, e se abaixará todo monte e outeiro; o que é tortuoso se endireitará, e os caminhos escabrosos se aplanarão;' },
      { v: 6, en: 'All flesh will see God’s salvation.’”', pt: 'e toda a carne verá a salvação de Deus.' },
      { v: 7, en: 'He said therefore to the multitudes who went out to be baptized by him, “You offspring of vipers, who warned you to flee from the wrath to come?', pt: 'João dizia, pois, às multidões que saíam para ser batizadas por ele: Raça de víboras, quem vos ensina a fugir da ira vindoura?' },
      { v: 8, en: 'Therefore produce fruits worthy of repentance, and don’t begin to say among yourselves, ‘We have Abraham for our father;’ for I tell you that God is able to raise up children to Abraham from these stones!', pt: 'Produzi, pois, frutos dignos de arrependimento; e não comeceis a dizer em vós mesmos: Temos por pai a Abrão; porque eu vos digo que até destas pedras Deus pode suscitar filhos a Abrão.' },
      { v: 9, en: 'Even now the ax also lies at the root of the trees. Every tree therefore that doesn’t produce good fruit is cut down, and thrown into the fire.”', pt: 'Também já está posto o machado à raiz das árvores; toda árvore, pois, que não produz bom fruto, é cortada e lançada no fogo.' },
      { v: 10, en: 'The multitudes asked him, “What then must we do?”', pt: 'Ao que lhe perguntavam as multidões: Que faremos, pois?' },
      { v: 11, en: 'He answered them, “He who has two coats, let him give to him who has none. He who has food, let him do likewise.”', pt: 'Respondia-lhes então: Aquele que tem duas túnicas, reparta com o que não tem nenhuma, e aquele que tem alimentos, faça o mesmo.' },
      { v: 12, en: 'Tax collectors also came to be baptized, and they said to him, “Teacher, what must we do?”', pt: 'Chegaram também uns publicanos para serem batizados, e perguntaram-lhe: Mestre, que havemos nós de fazer?' },
      { v: 13, en: 'He said to them, “Collect no more than that which is appointed to you.”', pt: 'Respondeu-lhes ele: Não cobreis além daquilo que vos foi prescrito.' },
      { v: 14, en: 'Soldiers also asked him, saying, “What about us? What must we do?” He said to them, “Extort from no one by violence, neither accuse anyone wrongfully. Be content with your wages.”', pt: 'Interrogaram-no também uns soldados: E nós, que faremos? Disse-lhes: A ninguém queirais extorquir coisa alguma; nem deis denúncia falsa; e contentai-vos com o vosso soldo.' },
      { v: 15, en: 'As the people were in expectation, and all men reasoned in their hearts concerning John, whether perhaps he was the Christ,', pt: 'Ora, estando o povo em expectativa e arrazoando todos em seus corações a respeito de João, se porventura seria ele o Cristo,' },
      { v: 16, en: 'John answered them all, “I indeed baptize you with water, but he comes who is mightier than I, the strap of whose sandals I am not worthy to loosen. He will baptize you in the Holy Spirit and fire,', pt: 'respondeu João a todos, dizendo: Eu, na verdade, vos batizo em água, mas vem aquele que é mais poderoso do que eu, de quem não sou digno de desatar a correia das alparcas; ele vos batizará no Espírito Santo e em fogo.' },
      { v: 17, en: 'whose fan is in his hand, and he will thoroughly cleanse his threshing floor, and will gather the wheat into his barn; but he will burn up the chaff with unquenchable fire.”', pt: 'A sua pá ele tem na mão para limpar bem a sua eira, e recolher o trigo ao seu celeiro; mas queimará a palha em fogo inextinguível.' },
      { v: 18, en: 'Then with many other exhortations he preached good news to the people,', pt: 'Assim pois, com muitas outras exortações ainda, anunciava o evangelho ao povo.' },
      { v: 19, en: 'but Herod the tetrarch, being reproved by him for Herodias, his brother’s wife, and for all the evil things which Herod had done,', pt: 'Mas o tetrarca Herodes, sendo repreendido por ele por causa de Herodias, mulher de seu irmão, e por todas as maldades que havia feito,' },
      { v: 20, en: 'added this also to them all, that he shut up John in prison.', pt: 'acrescentou a todas elas ainda esta, a de encerrar João no cárcere.' },
      { v: 21, en: 'Now when all the people were baptized, Jesus also had been baptized, and was praying. The sky was opened,', pt: 'Quando todo o povo fora batizado, tendo sido Jesus também batizado, e estando ele a orar, o céu se abriu;' },
      { v: 22, en: 'and the Holy Spirit descended in a bodily form like a dove on him; and a voice came out of the sky, saying “You are my beloved Son. In you I am well pleased.”', pt: 'e o Espírito Santo desceu sobre ele em forma corpórea, como uma pomba; e ouviu-se do céu esta voz: Tu és o meu Filho amado; em ti me comprazo.' },
      { v: 23, en: 'Jesus himself, when he began to teach, was about thirty years old, being the son (as was supposed) of Joseph, the son of Heli,', pt: 'Ora, Jesus, ao começar o seu ministério, tinha cerca de trinta anos; sendo (como se cuidava) filho de José, filho de Eli;' },
      { v: 24, en: 'the son of Matthat, the son of Levi, the son of Melchi, the son of Jannai, the son of Joseph,', pt: 'Eli de Matate, Matate de Levi, Levi de Melqui, Melqui de Janai, Janai de José,' },
      { v: 25, en: 'the son of Mattathias, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai,', pt: 'José de Matatias, Matatias de Amós, Amós de Naum, Naum de Esli, Esli de Nagai,' },
      { v: 26, en: 'the son of Maath, the son of Mattathias, the son of Semein, the son of Joseph, the son of Judah,', pt: 'Nagai de Maate, Maate de Matatias, Matatias de Semei, Semei de Joseque, Joseque de Jodá,' },
      { v: 27, en: 'the son of Joanan, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri,', pt: 'Jodá de Joanã, Joanã de Resa, Resa de Zorobabel, Zorobabel de Salatiel, Salatiel de Neri,' },
      { v: 28, en: 'the son of Melchi, the son of Addi, the son of Cosam, the son of Elmodam, the son of Er,', pt: 'Neri de Melqui, Melqui de Adi, Adi de Cosão, Cosão de Elmodã, Elmodão de Er,' },
      { v: 29, en: 'the son of Jose, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi,', pt: 'Er de Josué, Josué de Eliézer, Eliézer de Jorim, Jorim de Matate, Matate de Levi,' },
      { v: 30, en: 'the son of Simeon, the son of Judah, the son of Joseph, the son of Jonan, the son of Eliakim,', pt: 'Levi de Simeão, Simeão de Judá, Judá de José, José de Jonã, Jonã de Eliaquim,' },
      { v: 31, en: 'the son of Melea, the son of Menan, the son of Mattatha, the son of Nathan, the son of David,', pt: 'Eliaquim de Meleá, Meleá de Mená, Mená de Matatá, Matatá de Natã, Natã de Davi,' },
      { v: 32, en: 'the son of Jesse, the son of Obed, the son of Boaz, the son of Salmon, the son of Nahshon,', pt: 'Davi de Jessé, Jessé de Obede, Obede de Boaz, Boaz de Salá, Salá de Nasom,' },
      { v: 33, en: 'the son of Amminadab, the son of Aram, the son of Hezron, the son of Perez, the son of Judah,', pt: 'Nasom de Aminadabe, Aminadabe de Admim, Admim de Arni, Arni de Esrom, Esrom de Farés, Farés de Judá,' },
      { v: 34, en: 'the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,', pt: 'Judá de Jacó, Jacó de Isaque, Isaque de Abraão, Abraão de Tará, Tará de Naor,' },
      { v: 35, en: 'the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah,', pt: 'Naor de Seruque, Seruque de Ragaú, Ragaú de Faleque, Faleque de Eber, Eber de Salá,' },
      { v: 36, en: 'the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,', pt: 'Salá de Cainã, Cainã de Arfaxade, Arfaxade de Sem, Sem de Noé, Noé de Lameque,' },
      { v: 37, en: 'the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalaleel, the son of Cainan,', pt: 'Lameque de Matusalém, Matusalém de Enoque, Enoque de Jarede, Jarede de Maleleel, Maleleel de Cainã,' },
      { v: 38, en: 'the son of Enos, the son of Seth, the son of Adam, the son of God.', pt: 'Cainã de Enos, Enos de Sete, Sete de Adão, e Adão de Deus.' },
    ],
    4: [
      { v: 1, en: 'Jesus, full of the Holy Spirit, returned from the Jordan, and was led by the Spirit into the wilderness', pt: 'Jesus, pois, cheio do Espírito Santo, voltou do Jordão; e era levado pelo Espírito no deserto,' },
      { v: 2, en: 'for forty days, being tempted by the devil. He ate nothing in those days. Afterward, when they were completed, he was hungry.', pt: 'durante quarenta dias, sendo tentado pelo Diabo. E naqueles dias não comeu coisa alguma; e terminados eles, teve fome.' },
      { v: 3, en: 'The devil said to him, “If you are the Son of God, command this stone to become bread.”', pt: 'Disse-lhe então o Diabo: Se tu és Filho de Deus, manda a esta pedra que se torne em pão.' },
      { v: 4, en: 'Jesus answered him, saying, “It is written, ‘Man shall not live by bread alone, but by every word of God.’”', pt: 'Jesus, porém, lhe respondeu: Está escrito: Nem só de pão viverá o homem.' },
      { v: 5, en: 'The devil, leading him up on a high mountain, showed him all the kingdoms of the world in a moment of time.', pt: 'Então o Diabo, levando-o a um lugar elevado, mostrou-lhe num relance todos os reinos do mundo.' },
      { v: 6, en: 'The devil said to him, “I will give you all this authority, and their glory, for it has been delivered to me; and I give it to whomever I want.', pt: 'E disse-lhe: Dar-te-ei toda a autoridade e glória destes reinos, porque me foi entregue, e a dou a quem eu quiser;' },
      { v: 7, en: 'If you therefore will worship before me, it will all be yours.”', pt: 'se tu, me adorares, será toda tua.' },
      { v: 8, en: 'Jesus answered him, “Get behind me Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”', pt: 'Respondeu-lhe Jesus: Está escrito: Ao Senhor teu Deus adorarás, e só a ele servirás.' },
      { v: 9, en: 'He led him to Jerusalem, and set him on the pinnacle of the temple, and said to him, “If you are the Son of God, cast yourself down from here,', pt: 'Então o levou a Jerusalém e o colocou sobre o pináculo do templo e lhe disse: Se tu és Filho de Deus, lança-te daqui abaixo;' },
      { v: 10, en: 'for it is written, ‘He will put his angels in charge of you, to guard you;’', pt: 'porque está escrito: Aos seus anjos ordenará a teu respeito, que te guardem;' },
      { v: 11, en: 'and, ‘On their hands they will bear you up, lest perhaps you dash your foot against a stone.’”', pt: 'e: eles te susterão nas mãos, para que nunca tropeces em alguma pedra.' },
      { v: 12, en: 'Jesus answering, said to him, “It has been said, ‘You shall not tempt the Lord your God.’”', pt: 'Respondeu-lhe Jesus: Dito está: Não tentarás o Senhor teu Deus.' },
      { v: 13, en: 'When the devil had completed every temptation, he departed from him until another time.', pt: 'Assim, tendo o Diabo acabado toda sorte de tentação, retirou-se dele até ocasião oportuna.' },
      { v: 14, en: 'Jesus returned in the power of the Spirit into Galilee, and news about him spread through all the surrounding area.', pt: 'Então voltou Jesus para a Galiléia no poder do Espírito; e a sua fama correu por toda a circunvizinhança.' },
      { v: 15, en: 'He taught in their synagogues, being glorified by all.', pt: 'Ensinava nas sinagogas deles, e por todos era louvado.' },
      { v: 16, en: 'He came to Nazareth, where he had been brought up. He entered, as was his custom, into the synagogue on the Sabbath day, and stood up to read.', pt: 'Chegando a Nazaré, onde fora criado; entrou na sinagoga no dia de sábado, segundo o seu costume, e levantou-se para ler.' },
      { v: 17, en: 'The book of the prophet Isaiah was handed to him. He opened the book, and found the place where it was written,', pt: 'Foi-lhe entregue o livro do profeta Isaías; e abrindo-o, achou o lugar em que estava escrito:' },
      { v: 18, en: '“The Spirit of the Lord is on me, because he has anointed me to preach good news to the poor. He has sent me to heal the broken hearted, to proclaim release to the captives, recovering of sight to the blind, to deliver those who are crushed,', pt: 'O Espírito do Senhor está sobre mim, porquanto me ungiu para anunciar boas novas aos pobres; enviou-me para proclamar libertação aos cativos, e restauração da vista aos cegos, para pôr em liberdade os oprimidos,' },
      { v: 19, en: 'and to proclaim the acceptable year of the Lord.”', pt: 'e para proclamar o ano aceitável do Senhor.' },
      { v: 20, en: 'He closed the book, gave it back to the attendant, and sat down. The eyes of all in the synagogue were fastened on him.', pt: 'E fechando o livro, devolveu-o ao assistente e sentou-se; e os olhos de todos na sinagoga estavam fitos nele.' },
      { v: 21, en: 'He began to tell them, “Today, this Scripture has been fulfilled in your hearing.”', pt: 'Então começou a dizer-lhes: Hoje se cumpriu esta escritura aos vossos ouvidos.' },
      { v: 22, en: 'All testified about him, and wondered at the gracious words which proceeded out of his mouth, and they said, “Isn’t this Joseph’s son?”', pt: 'E todos lhe davam testemunho, e se admiravam das palavras de graça que saíam da sua boca; e diziam: Este não é filho de José?' },
      { v: 23, en: 'He said to them, “Doubtless you will tell me this parable, ‘Physician, heal yourself! Whatever we have heard done at Capernaum, do also here in your hometown.’”', pt: 'Disse-lhes Jesus: Sem dúvida me direis este provérbio: Médico, cura-te a ti mesmo; Tudo o que ouvimos teres feito em Cafarnaum, faze-o também aqui na tua terra.' },
      { v: 24, en: 'He said, “Most certainly I tell you, no prophet is acceptable in his hometown.', pt: 'E prosseguiu: Em verdade vos digo que nenhum profeta é aceito na sua terra.' },
      { v: 25, en: 'But truly I tell you, there were many widows in Israel in the days of Elijah, when the sky was shut up three years and six months, when a great famine came over all the land.', pt: 'Em verdade vos digo que muitas viúvas havia em Israel nos dias de Elias, quando céu se fechou por três anos e seis meses, de sorte que houve grande fome por toda a terra;' },
      { v: 26, en: 'Elijah was sent to none of them, except to Zarephath, in the land of Sidon, to a woman who was a widow.', pt: 'e a nenhuma delas foi enviado Elias, senão a uma viúva em Serepta de Sidom.' },
      { v: 27, en: 'There were many lepers in Israel in the time of Elisha the prophet, yet not one of them was cleansed, except Naaman, the Syrian.”', pt: 'Também muitos leprosos havia em Israel no tempo do profeta Elizeu, mas nenhum deles foi purificado senão Naamã, o sírio.' },
      { v: 28, en: 'They were all filled with wrath in the synagogue, as they heard these things.', pt: 'Todos os que estavam na sinagoga, ao ouvirem estas coisas, ficaram cheios de ira.' },
      { v: 29, en: 'They rose up, threw him out of the city, and led him to the brow of the hill that their city was built on, that they might throw him off the cliff.', pt: 'e, levantando-se, expulsaram-no da cidade e o levaram até o despenhadeiro do monte em que a sua cidade estava edificada, para dali o precipitarem.' },
      { v: 30, en: 'But he, passing through the middle of them, went his way.', pt: 'Ele, porém, passando pelo meio deles, seguiu o seu caminho.' },
      { v: 31, en: 'He came down to Capernaum, a city of Galilee. He was teaching them on the Sabbath day,', pt: 'Então desceu a Cafarnaum, cidade da Galiléia, e os ensinava no sábado.' },
      { v: 32, en: 'and they were astonished at his teaching, for his word was with authority.', pt: 'e maravilharam-se da sua doutrina, porque a sua palavra era com autoridade.' },
      { v: 33, en: 'In the synagogue there was a man who had a spirit of an unclean demon, and he cried out with a loud voice,', pt: 'Havia na sinagoga um homem que tinha o espírito de um demônio imundo; e gritou em alta voz:' },
      { v: 34, en: 'saying, “Ah! what have we to do with you, Jesus of Nazareth? Have you come to destroy us? I know you who you are: the Holy One of God!”', pt: 'Ah! que temos nós contigo, Jesus, nazareno? vieste destruir-nos? Bem sei quem é: o Santo de Deus.' },
      { v: 35, en: 'Jesus rebuked him, saying, “Be silent, and come out of him!” When the demon had thrown him down in the middle of them, he came out of him, having done him no harm.', pt: 'Mas Jesus o repreendeu, dizendo: Cala-te, e sai dele. E o demônio, tendo-o lançado por terra no meio do povo, saiu dele sem lhe fazer mal algum.' },
      { v: 36, en: 'Amazement came on all, and they spoke together, one with another, saying, “What is this word? For with authority and power he commands the unclean spirits, and they come out!”', pt: 'E veio espanto sobre todos, e falavam entre si, perguntando uns aos outros: Que palavra é esta, pois com autoridade e poder ordena aos espíritos imundos, e eles saem?' },
      { v: 37, en: 'News about him went out into every place of the surrounding region.', pt: 'E se divulgava a sua fama por todos os lugares da circunvizinhança.' },
      { v: 38, en: 'He rose up from the synagogue, and entered into Simon’s house. Simon’s mother-in-law was afflicted with a great fever, and they begged him for her.', pt: 'Ora, levantando-se Jesus, saiu da sinagoga e entrou em casa de Simão; e estando a sogra de Simão enferma com muita febre, rogaram-lhe por ela.' },
      { v: 39, en: 'He stood over her, and rebuked the fever; and it left her. Immediately she rose up and served them.', pt: 'E ele, inclinando-se para ela, repreendeu a febre, e esta a deixou. Imediatamente ela se levantou e os servia.' },
      { v: 40, en: 'When the sun was setting, all those who had any sick with various diseases brought them to him; and he laid his hands on every one of them, and healed them.', pt: 'Ao pôr do sol, todos os que tinham enfermos de várias doenças lhos traziam; e ele punha as mãos sobre cada um deles e os curava.' },
      { v: 41, en: 'Demons also came out of many, crying out, and saying, “You are the Christ, the Son of God!” Rebuking them, he didn’t allow them to speak, because they knew that he was the Christ.', pt: 'Também de muitos saíam demônios, gritando e dizendo: Tu és o Filho de Deus. Ele, porém, os repreendia, e não os deixava falar; pois sabiam que ele era o Cristo.' },
      { v: 42, en: 'When it was day, he departed and went into an uninhabited place, and the multitudes looked for him, and came to him, and held on to him, so that he wouldn’t go away from them.', pt: 'Ao romper do dia saiu, e foi a um lugar deserto; e as multidões procuravam-no e, vindo a ele, queriam detê-lo, para que não se ausentasse delas.' },
      { v: 43, en: 'But he said to them, “I must preach the good news of God’s Kingdom to the other cities also. For this reason I have been sent.”', pt: 'Ele, porém, lhes disse: É necessário que também às outras cidades eu anuncie o evangelho do reino de Deus; porque para isso é que fui enviado.' },
      { v: 44, en: 'He was preaching in the synagogues of Galilee.', pt: 'E pregava nas sinagogas da Judéia.' },
    ],
    5: [
      { v: 1, en: 'Now while the multitude pressed on him and heard the word of God, he was standing by the lake of Gennesaret.', pt: 'Certa vez, quando a multidão apertava Jesus para ouvir a palavra de Deus, ele estava junto ao lago de Genezaré;' },
      { v: 2, en: 'He saw two boats standing by the lake, but the fishermen had gone out of them, and were washing their nets.', pt: 'e viu dois barcos junto à praia do lago; mas os pescadores haviam descido deles, e estavam lavando as redes.' },
      { v: 3, en: 'He entered into one of the boats, which was Simon’s, and asked him to put out a little from the land. He sat down and taught the multitudes from the boat.', pt: 'Entrando ele num dos barcos, que era o de Simão, pediu-lhe que o afastasse um pouco da terra; e, sentando-se, ensinava do barco as multidões.' },
      { v: 4, en: 'When he had finished speaking, he said to Simon, “Put out into the deep, and let down your nets for a catch.”', pt: 'Quando acabou de falar, disse a Simão: Faze-te ao largo e lançai as vossas redes para a pesca.' },
      { v: 5, en: 'Simon answered him, “Master, we worked all night, and took nothing; but at your word I will let down the net.”', pt: 'Ao que disse Simão: Mestre, trabalhamos a noite toda, e nada apanhamos; mas, sobre tua palavra, lançarei as redes.' },
      { v: 6, en: 'When they had done this, they caught a great multitude of fish, and their net was breaking.', pt: 'Feito isto, apanharam uma grande quantidade de peixes, de modo que as redes se rompiam.' },
      { v: 7, en: 'They beckoned to their partners in the other boat, that they should come and help them. They came, and filled both boats, so that they began to sink.', pt: 'Acenaram então aos companheiros que estavam no outro barco, para virem ajudá-los. Eles, pois, vieram, e encheram ambos os barcos, de maneira tal que quase iam a pique.' },
      { v: 8, en: 'But Simon Peter, when he saw it, fell down at Jesus’ knees, saying, “Depart from me, for I am a sinful man, Lord.”', pt: 'Vendo isso Simão Pedro, prostrou-se aos pés de Jesus, dizendo: Retira-te de mim, Senhor, porque sou um homem pecador.' },
      { v: 9, en: 'For he was amazed, and all who were with him, at the catch of fish which they had caught;', pt: 'Pois, à vista da pesca que haviam feito, o espanto se apoderara dele e de todos os que com ele estavam,' },
      { v: 10, en: 'and so also were James and John, sons of Zebedee, who were partners with Simon. Jesus said to Simon, “Don’t be afraid. From now on you will be catching people alive.”', pt: 'bem como de Tiago e João, filhos de Zebedeu, que eram sócios de Simão. Disse Jesus a Simão: Não temas; de agora em diante serás pescador de homens.' },
      { v: 11, en: 'When they had brought their boats to land, they left everything, and followed him.', pt: 'E, levando eles os barcos para a terra, deixaram tudo e o seguiram.' },
      { v: 12, en: 'While he was in one of the cities, behold, there was a man full of leprosy. When he saw Jesus, he fell on his face, and begged him, saying, “Lord, if you want to, you can make me clean.”', pt: 'Estando ele numa das cidades, apareceu um homem cheio de lepra que, vendo a Jesus, prostrou-se com o rosto em terra e suplicou-lhe: Senhor, se quiseres, bem podes tornar-me limpo.' },
      { v: 13, en: 'He stretched out his hand, and touched him, saying, “I want to. Be made clean.” Immediately the leprosy left him.', pt: 'Jesus, pois, estendendo a mão, tocou-lhe, dizendo: Quero; sê limpo. No mesmo instante desapareceu dele a lepra.' },
      { v: 14, en: 'He commanded him to tell no one, “But go your way, and show yourself to the priest, and offer for your cleansing according to what Moses commanded, for a testimony to them.”', pt: 'Ordenou-lhe, então, que a ninguém contasse isto. Mas vai, disse ele, mostra-te ao sacerdote e faze a oferta pela tua purificação, conforme Moisés determinou, para lhes servir de testemunho.' },
      { v: 15, en: 'But the report concerning him spread much more, and great multitudes came together to hear, and to be healed by him of their infirmities.', pt: 'A sua fama, porém, se divulgava cada vez mais, e grandes multidões se ajuntavam para ouvi-lo e serem curadas das suas enfermidades.' },
      { v: 16, en: 'But he withdrew himself into the desert, and prayed.', pt: 'Mas ele se retirava para os desertos, e ali orava.' },
      { v: 17, en: 'On one of those days, he was teaching; and there were Pharisees and teachers of the law sitting by, who had come out of every village of Galilee, Judea, and Jerusalem. The power of the Lord was with him to heal them.', pt: 'Um dia, quando ele estava ensinando, achavam-se ali sentados fariseus e doutores da lei, que tinham vindo de todas as aldeias da Galiléia e da Judéia, e de Jerusalém; e o poder do Senhor estava com ele para curar.' },
      { v: 18, en: 'Behold, men brought a paralyzed man on a cot, and they sought to bring him in to lay before Jesus.', pt: 'E eis que uns homens, trazendo num leito um paralítico, procuravam introduzí-lo e pô-lo diante dele.' },
      { v: 19, en: 'Not finding a way to bring him in because of the multitude, they went up to the housetop, and let him down through the tiles with his cot into the middle before Jesus.', pt: 'Mas, não achando por onde o pudessem introduzir por causa da multidão, subiram ao eirado e, por entre as telhas, o baixaram com o leito, para o meio de todos, diante de Jesus.' },
      { v: 20, en: 'Seeing their faith, he said to him, “Man, your sins are forgiven you.”', pt: 'E vendo-lhes a fé, disse ele: Homem, são-te perdoados os teus pecados.' },
      { v: 21, en: 'The scribes and the Pharisees began to reason, saying, “Who is this that speaks blasphemies? Who can forgive sins, but God alone?”', pt: 'Então os escribas e os fariseus começaram a arrazoar, dizendo: Quem é este que profere blasfêmias? Quem é este que profere blasfêmias? Quem pode perdoar pecados, senão só Deus?' },
      { v: 22, en: 'But Jesus, perceiving their thoughts, answered them, “Why are you reasoning so in your hearts?', pt: 'Jesus, porém, percebendo os seus pensamentos, respondeu, e disse-lhes: Por que arrazoais em vossos corações?' },
      { v: 23, en: 'Which is easier to say, ‘Your sins are forgiven you;’ or to say, ‘Arise and walk?’', pt: 'Qual é mais fácil? dizer: São-te perdoados os teus pecados; ou dizer: Levanta-te, e anda?' },
      { v: 24, en: 'But that you may know that the Son of Man has authority on earth to forgive sins” (he said to the paralyzed man), “I tell you, arise, and take up your cot, and go to your house.”', pt: 'Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados (disse ao paralítico), a ti te digo: Levanta-te, toma o teu leito e vai para tua casa.' },
      { v: 25, en: 'Immediately he rose up before them, and took up that which he was laying on, and departed to his house, glorifying God.', pt: 'Imediatamente se levantou diante deles, tomou o leito em que estivera deitado e foi para sua casa, glorificando a Deus.' },
      { v: 26, en: 'Amazement took hold on all, and they glorified God. They were filled with fear, saying, “We have seen strange things today.”', pt: 'E, tomados de pasmo, todos glorificavam a Deus; e diziam, cheios de temor: Hoje vimos coisas extraordinárias.' },
      { v: 27, en: 'After these things he went out, and saw a tax collector named Levi sitting at the tax office, and said to him, “Follow me!”', pt: 'Depois disso saiu e, vendo um publicano chamado Levi, sentado na coletoria, disse-lhe: Segue-me.' },
      { v: 28, en: 'He left everything, and rose up and followed him.', pt: 'Este, deixando tudo, levantou-se e o seguiu.' },
      { v: 29, en: 'Levi made a great feast for him in his house. There was a great crowd of tax collectors and others who were reclining with them.', pt: 'Deu-lhe então Levi um lauto banquete em sua casa; havia ali grande número de publicanos e outros que estavam com eles à mesa.' },
      { v: 30, en: 'Their scribes and the Pharisees murmured against his disciples, saying, “Why do you eat and drink with the tax collectors and sinners?”', pt: 'Murmuravam, pois, os fariseus e seus escribas contra os discípulos, perguntando: Por que comeis e bebeis com publicanos e pecadores?' },
      { v: 31, en: 'Jesus answered them, “Those who are healthy have no need for a physician, but those who are sick do.', pt: 'Respondeu-lhes Jesus: Não necessitam de médico os sãos, mas sim os enfermos;' },
      { v: 32, en: 'I have not come to call the righteous, but sinners to repentance.”', pt: 'eu não vim chamar justos, mas pecadores, ao arrependimento.' },
      { v: 33, en: 'They said to him, “Why do John’s disciples often fast and pray, likewise also the disciples of the Pharisees, but yours eat and drink?”', pt: 'Disseram-lhe eles: Os discípulos de João jejuam frequentemente e fazem orações, como também os dos fariseus, mas os teus comem e bebem.' },
      { v: 34, en: 'He said to them, “Can you make the friends of the bridegroom fast, while the bridegroom is with them?', pt: 'Respondeu-lhes Jesus: Podeis, porventura, fazer jejuar os convidados às núpcias enquanto o noivo está com eles?' },
      { v: 35, en: 'But the days will come when the bridegroom will be taken away from them. Then they will fast in those days.”', pt: 'Dias virão, porém, em que lhes será tirado o noivo; naqueles dias, sim hão de jejuar.' },
      { v: 36, en: 'He also told a parable to them. “No one puts a piece from a new garment on an old garment, or else he will tear the new, and also the piece from the new will not match the old.', pt: 'Propôs-lhes também uma parábola: Ninguém tira um pedaço de um vestido novo para o coser em vestido velho; do contrário, não somente rasgará o novo, mas também o pedaço do novo não condirá com o velho.' },
      { v: 37, en: 'No one puts new wine into old wine skins, or else the new wine will burst the skins, and it will be spilled, and the skins will be destroyed.', pt: 'E ninguém deita vinho novo em odres velhos; do contrário, o vinho novo romperá os odres e se derramará, e os odres se perderão;' },
      { v: 38, en: 'But new wine must be put into fresh wine skins, and both are preserved.', pt: 'mas vinho novo deve ser deitado em odres novos.' },
      { v: 39, en: 'No man having drunk old wine immediately desires new, for he says, ‘The old is better.’”', pt: 'E ninguém, tendo bebido o velho, quer o novo; porque diz: O velho é bom.' },
    ],
    6: [
      { v: 1, en: 'Now on the second Sabbath after the first, he was going through the grain fields. His disciples plucked the heads of grain and ate, rubbing them in their hands.', pt: 'E sucedeu que, num dia de sábado, passava Jesus pelas searas; e seus discípulos iam colhendo espigas e, debulhando-as com as mãos, as comiam.' },
      { v: 2, en: 'But some of the Pharisees said to them, “Why do you do that which is not lawful to do on the Sabbath day?”', pt: 'Alguns dos fariseus, porém, perguntaram; Por que estais fazendo o que não é lícito fazer nos sábados?' },
      { v: 3, en: 'Jesus, answering them, said, “Haven’t you read what David did when he was hungry, he, and those who were with him;', pt: 'E Jesus, respondendo-lhes, disse: Nem ao menos tendes lido o que fez Davi quando teve fome, ele e seus companheiros?' },
      { v: 4, en: 'how he entered into God’s house, and took and ate the show bread, and gave also to those who were with him, which is not lawful to eat except for the priests alone?”', pt: 'Como entrou na casa de Deus, tomou os pães da proposição, dos quais não era lícito comer senão só aos sacerdotes, e deles comeu e deu também aos companheiros?' },
      { v: 5, en: 'He said to them, “The Son of Man is lord of the Sabbath.”', pt: 'Também lhes disse: O Filho do homem é Senhor do sábado.' },
      { v: 6, en: 'It also happened on another Sabbath that he entered into the synagogue and taught. There was a man there, and his right hand was withered.', pt: 'Ainda em outro sábado entrou na sinagoga, e pôs-se a ensinar. Estava ali um homem que tinha a mão direita atrofiada.' },
      { v: 7, en: 'The scribes and the Pharisees watched him, to see whether he would heal on the Sabbath, that they might find an accusation against him.', pt: 'E os escribas e os fariseus observavam-no, para ver se curaria em dia de sábado, para acharem de que o acusar.' },
      { v: 8, en: 'But he knew their thoughts; and he said to the man who had the withered hand, “Rise up, and stand in the middle.” He arose and stood.', pt: 'Mas ele, conhecendo-lhes os pensamentos, disse ao homem que tinha a mão atrofiada: Levanta-te, e fica em pé aqui no maio. E ele, levantando-se, ficou em pé.' },
      { v: 9, en: 'Then Jesus said to them, “I will ask you something: Is it lawful on the Sabbath to do good, or to do harm? To save a life, or to kill?”', pt: 'Disse-lhes, então, Jesus: Eu vos pergunto: É lícito no sábado fazer bem, ou fazer mal? salvar a vida, ou tirá-la?' },
      { v: 10, en: 'He looked around at them all, and said to the man, “Stretch out your hand.” He did, and his hand was restored as sound as the other.', pt: 'E olhando para todos em redor, disse ao homem: Estende a tua mão. Ele assim o fez, e a mão lhe foi restabelecida.' },
      { v: 11, en: 'But they were filled with rage, and talked with one another about what they might do to Jesus.', pt: 'Mas eles se encheram de furor; e uns com os outros conferenciam sobre o que fariam a Jesus.' },
      { v: 12, en: 'In these days, he went out to the mountain to pray, and he continued all night in prayer to God.', pt: 'Naqueles dias retirou-se para o monte a fim de orar; e passou a noite toda em oração a Deus.' },
      { v: 13, en: 'When it was day, he called his disciples, and from them he chose twelve, whom he also named apostles:', pt: 'Depois do amanhecer, chamou seus discípulos, e escolheu doze dentre eles, aos quais deu também o nome de apóstolos:' },
      { v: 14, en: 'Simon, whom he also named Peter; Andrew, his brother; James; John; Philip; Bartholomew;', pt: 'Simão, ao qual também chamou Pedro, e André, seu irmão; Tiago e João; Filipe e Bartolomeu;' },
      { v: 15, en: 'Matthew; Thomas; James, the son of Alphaeus; Simon, who was called the Zealot;', pt: 'Mateus e Tomé; Tiago, filho de Alfeu, e Simão, chamado Zelote;' },
      { v: 16, en: 'Judas the son of James; and Judas Iscariot, who also became a traitor.', pt: 'Judas, filho de Tiago; e Judas Iscariotes, que veio a ser o traidor.' },
      { v: 17, en: 'He came down with them, and stood on a level place, with a crowd of his disciples, and a great number of the people from all Judea and Jerusalem, and the sea coast of Tyre and Sidon, who came to hear him and to be healed of their diseases;', pt: 'E Jesus, descendo com eles, parou num lugar plano, onde havia não só grande número de seus discípulos, mas também grande multidão do povo, de toda a Judéia e Jerusalém, e do litoral de Tiro e de Sidom, que tinham vindo para ouví-lo e serem curados das suas doenças;' },
      { v: 18, en: 'as well as those who were troubled by unclean spirits, and they were being healed.', pt: 'e os que eram atormentados por espíritos imundos ficavam curados.' },
      { v: 19, en: 'All the multitude sought to touch him, for power came out of him and healed them all.', pt: 'E toda a multidão procurava tocar-lhe; porque saía dele poder que curava a todos.' },
      { v: 20, en: 'He lifted up his eyes to his disciples, and said, “Blessed are you who are poor, God’s Kingdom is yours.', pt: 'Então, levantando ele os olhos para os seus discípulos, dizia: Bem-aventurados vós, os pobres, porque vosso é o reino de Deus.' },
      { v: 21, en: 'Blessed are you who hunger now, for you will be filled. Blessed are you who weep now, for you will laugh.', pt: 'Bem-aventurados vós, que agora tendes fome, porque sereis fartos. Bem-aventurados vós, que agora chorais, porque haveis de rir.' },
      { v: 22, en: 'Blessed are you when men shall hate you, and when they shall exclude and mock you, and throw out your name as evil, for the Son of Man’s sake.', pt: 'Bem-aventurados sereis quando os homens vos odiarem, e quando vos expulsarem da sua companhia, e vos injuriarem, e rejeitarem o vosso nome como indigno, por causa do Filho do homem.' },
      { v: 23, en: 'Rejoice in that day, and leap for joy, for behold, your reward is great in heaven, for their fathers did the same thing to the prophets.', pt: 'Regozijai-vos nesse dia e exultai, porque eis que é grande o vosso galardão no céu; pois assim faziam os seus pais aos profetas.' },
      { v: 24, en: '“But woe to you who are rich! For you have received your consolation.', pt: 'Mas ai de vós que sois ricos! porque já recebestes a vossa consolação.' },
      { v: 25, en: 'Woe to you, you who are full now, for you will be hungry. Woe to you who laugh now, for you will mourn and weep.', pt: 'Ai de vós, os que agora estais fartos! porque tereis fome. Ai de vós, os que agora rides! porque vos lamentareis e chorareis.' },
      { v: 26, en: 'Woe, when men speak well of you, for their fathers did the same thing to the false prophets.', pt: 'Ai de vós, quando todos os homens vos louvarem! porque assim faziam os seus pais aos falsos profetas.' },
      { v: 27, en: '“But I tell you who hear: love your enemies, do good to those who hate you,', pt: 'Mas a vós que ouvis, digo: Amai a vossos inimigos, fazei bem aos que vos odeiam,' },
      { v: 28, en: 'bless those who curse you, and pray for those who mistreat you.', pt: 'bendizei aos que vos maldizem, e orai pelos que vos caluniam.' },
      { v: 29, en: 'To him who strikes you on the cheek, offer also the other; and from him who takes away your cloak, don’t withhold your coat also.', pt: 'Ao que te ferir numa face, oferece-lhe também a outra; e ao que te houver tirado a capa, não lhe negues também a túnica.' },
      { v: 30, en: 'Give to everyone who asks you, and don’t ask him who takes away your goods to give them back again.', pt: 'Dá a todo o que te pedir; e ao que tomar o que é teu, não lho reclames.' },
      { v: 31, en: '“As you would like people to do to you, do exactly so to them.', pt: 'Assim como quereis que os homens vos façam, do mesmo modo lhes fazei vós também.' },
      { v: 32, en: 'If you love those who love you, what credit is that to you? For even sinners love those who love them.', pt: 'Se amardes aos que vos amam, que mérito há nisso? Pois também os pecadores amam aos que os amam.' },
      { v: 33, en: 'If you do good to those who do good to you, what credit is that to you? For even sinners do the same.', pt: 'E se fizerdes bem aos que vos fazem bem, que mérito há nisso? Também os pecadores fazem o mesmo.' },
      { v: 34, en: 'If you lend to those from whom you hope to receive, what credit is that to you? Even sinners lend to sinners, to receive back as much.', pt: 'E se emprestardes àqueles de quem esperais receber, que mérito há nisso? Também os pecadores emprestam aos pecadores, para receberem outro tanto.' },
      { v: 35, en: 'But love your enemies, and do good, and lend, expecting nothing back; and your reward will be great, and you will be children of the Most High; for he is kind toward the unthankful and evil.', pt: 'Amai, porém a vossos inimigos, fazei bem e emprestai, nunca desanimado; e grande será a vossa recompensa, e sereis filhos do Altíssimo; porque ele é benigno até para com os integrantes e maus.' },
      { v: 36, en: '“Therefore be merciful, even as your Father is also merciful.', pt: 'Sede misericordiosos, como também vosso Pai é misericordioso.' },
      { v: 37, en: 'Don’t judge, and you won’t be judged. Don’t condemn, and you won’t be condemned. Set free, and you will be set free.', pt: 'Não julgueis, e não sereis julgados; não condeneis, e não sereis condenados; perdoai, e sereis perdoados.' },
      { v: 38, en: '“Give, and it will be given to you: good measure, pressed down, shaken together, and running over, will be given to you. For with the same measure you measure it will be measured back to you.”', pt: 'Dai, e ser-vos-á dado; boa medida, recalcada, sacudida e transbordando vos deitarão no regaço; porque com a mesma medida com que medis, vos medirão a vós.' },
      { v: 39, en: 'He spoke a parable to them. “Can the blind guide the blind? Won’t they both fall into a pit?', pt: 'E propôs-lhes também uma parábola: Pode porventura um cego guiar outro cego? não cairão ambos no barranco?' },
      { v: 40, en: 'A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher.', pt: 'Não é o discípulo mais do que o seu mestre; mas todo o que for bem instruído será como o seu mestre.' },
      { v: 41, en: 'Why do you see the speck of chaff that is in your brother’s eye, but don’t consider the beam that is in your own eye?', pt: 'Por que vês o argueiro no olho de teu irmão, e não reparas na trave que está no teu próprio olho?' },
      { v: 42, en: 'Or how can you tell your brother, ‘Brother, let me remove the speck of chaff that is in your eye,’ when you yourself don’t see the beam that is in your own eye? You hypocrite! First remove the beam from your own eye, and then you can see clearly to remove the speck of chaff that is in your brother’s eye.', pt: 'Ou como podes dizer a teu irmão: Irmão, deixa-me tirar o argueiro que está no teu olho, não vendo tu mesmo a trave que está no teu? Hipócrita! tira primeiro a trave do teu olho; e então verás bem para tirar o argueiro que está no olho de teu irmão.' },
      { v: 43, en: 'For there is no good tree that produces rotten fruit; nor again a rotten tree that produces good fruit.', pt: 'Porque não há árvore boa que dê mau fruto nem tampouco árvore má que dê bom fruto.' },
      { v: 44, en: 'For each tree is known by its own fruit. For people don’t gather figs from thorns, nor do they gather grapes from a bramble bush.', pt: 'Porque cada árvore se conhece pelo seu próprio fruto; pois dos espinheiros não se colhem figos, nem dos abrolhos se vindimam uvas.' },
      { v: 45, en: 'The good man out of the good treasure of his heart brings out that which is good, and the evil man out of the evil treasure of his heart brings out that which is evil, for out of the abundance of the heart, his mouth speaks.', pt: 'O homem bom, do bom tesouro do seu coração tira o bem; e o homem mau, do seu mau tesouro tira o mal; pois do que há em abundância no coração, disso fala a boca.' },
      { v: 46, en: '“Why do you call me, ‘Lord, Lord,’ and don’t do the things which I say?', pt: 'E por que me chamais: Senhor, Senhor, e não fazeis o que eu vos digo?' },
      { v: 47, en: 'Everyone who comes to me, and hears my words, and does them, I will show you who he is like.', pt: 'Todo aquele que vem a mim, e ouve as minhas palavras, e as pratica, eu vos mostrarei a quem é semelhante:' },
      { v: 48, en: 'He is like a man building a house, who dug and went deep, and laid a foundation on the rock. When a flood arose, the stream broke against that house, and could not shake it, because it was founded on the rock.', pt: 'É semelhante ao homem que, edificando uma casa, cavou, abriu profunda vala, e pôs os alicerces sobre a rocha; e vindo a enchente, bateu com ímpeto a torrente naquela casa, e não a pôde abalar, porque tinha sido bem edificada.' },
      { v: 49, en: 'But he who hears, and doesn’t do, is like a man who built a house on the earth without a foundation, against which the stream broke, and immediately it fell, and the ruin of that house was great.”', pt: 'Mas o que ouve e não pratica é semelhante a um homem que edificou uma casa sobre terra, sem alicerces, na qual bateu com ímpeto a torrente, e logo caiu; e foi grande a ruína daquela casa.' },
    ],
    7: [
      { v: 1, en: 'After he had finished speaking in the hearing of the people, he entered into Capernaum.', pt: 'Quando acabou de proferir todas estas palavras aos ouvidos do povo, entrou em Cafarnaum.' },
      { v: 2, en: 'A certain centurion’s servant, who was dear to him, was sick and at the point of death.', pt: 'E um servo de certo centurião, de quem era muito estimado, estava doente, quase à morte.' },
      { v: 3, en: 'When he heard about Jesus, he sent to him elders of the Jews, asking him to come and save his servant.', pt: 'O centurião, pois, ouvindo falar de Jesus, enviou-lhes uns anciãos dos judeus, a pedir-lhe que viesse curar o seu servo.' },
      { v: 4, en: 'When they came to Jesus, they begged him earnestly, saying, “He is worthy for you to do this for him,', pt: 'E chegando eles junto de Jesus, rogavam-lhe com instância, dizendo: É digno de que lhe concedas isto;' },
      { v: 5, en: 'for he loves our nation, and he built our synagogue for us.”', pt: 'porque ama à nossa nação, e ele mesmo nos edificou a sinagoga.' },
      { v: 6, en: 'Jesus went with them. When he was now not far from the house, the centurion sent friends to him, saying to him, “Lord, don’t trouble yourself, for I am not worthy for you to come under my roof.', pt: 'Ia, pois, Jesus com eles; mas, quando já estava perto da casa, enviou o centurião uns amigos a dizer-lhe: Senhor, não te incomodes; porque não sou digno de que entres debaixo do meu telhado;' },
      { v: 7, en: 'Therefore I didn’t even think myself worthy to come to you; but say the word, and my servant will be healed.', pt: 'por isso nem ainda me julguei digno de ir à tua presença; dize, porém, uma palavra, e seja o meu servo curado.' },
      { v: 8, en: 'For I also am a man placed under authority, having under myself soldiers. I tell this one, ‘Go!’ and he goes; and to another, ‘Come!’ and he comes; and to my servant, ‘Do this,’ and he does it.”', pt: 'Pois também eu sou homem sujeito à autoridade, e tenho soldados às minhas ordens; e digo a este: Vai, e ele vai; e a outro: Vem, e ele vem; e ao meu servo: Faze isto, e ele o faz.' },
      { v: 9, en: 'When Jesus heard these things, he marveled at him, and turned and said to the multitude who followed him, “I tell you, I have not found such great faith, no, not in Israel.”', pt: 'Jesus, ouvindo isso, admirou-se dele e, voltando-se para a multidão que o seguia, disse: Eu vos afirmo que nem mesmo em Israel encontrei tamanha fé.' },
      { v: 10, en: 'Those who were sent, returning to the house, found that the servant who had been sick was well.', pt: 'E voltando para casa os que haviam sido enviados, encontraram o servo com saúde.' },
      { v: 11, en: 'Soon afterwards, he went to a city called Nain. Many of his disciples, along with a great multitude, went with him.', pt: 'Pouco depois seguiu ele viagem para uma cidade chamada Naim; e iam com ele seus discípulos e uma grande multidão.' },
      { v: 12, en: 'Now when he came near to the gate of the city, behold, one who was dead was carried out, the only son of his mother, and she was a widow. Many people of the city were with her.', pt: 'Quando chegou perto da porta da cidade, eis que levavam para fora um defunto, filho único de sua mãe, que era viúva; e com ela ia uma grande multidão da cidade.' },
      { v: 13, en: 'When the Lord saw her, he had compassion on her, and said to her, “Don’t cry.”', pt: 'Logo que o Senhor a viu, encheu-se de compaixão por ela, e disse-lhe: Não chores.' },
      { v: 14, en: 'He came near and touched the coffin, and the bearers stood still. He said, “Young man, I tell you, arise!”', pt: 'Então, chegando-se, tocou no esquife e, quando pararam os que o levavam, disse: Moço, a ti te digo: Levanta-te.' },
      { v: 15, en: 'He who was dead sat up, and began to speak. And he gave him to his mother.', pt: 'O que estivera morto sentou-se e começou a falar. Então Jesus o entregou à sua mãe.' },
      { v: 16, en: 'Fear took hold of all, and they glorified God, saying, “A great prophet has arisen among us!” and, “God has visited his people!”', pt: 'O medo se apoderou de todos, e glorificavam a Deus, dizendo: Um grande profeta se levantou entre nós; e: Deus visitou o seu povo.' },
      { v: 17, en: 'This report went out concerning him in the whole of Judea, and in all the surrounding region.', pt: 'E correu a notícia disto por toda a Judéia e por toda a região circunvizinha.' },
      { v: 18, en: 'The disciples of John told him about all these things.', pt: 'Ora, os discípulos de João anunciaram-lhe todas estas coisas.' },
      { v: 19, en: 'John, calling to himself two of his disciples, sent them to Jesus, saying, “Are you the one who is coming, or should we look for another?”', pt: 'E João, chamando a dois deles, enviou-os ao Senhor para perguntar-lhe: És tu aquele que havia de vir, ou havemos de esperar outro?' },
      { v: 20, en: 'When the men had come to him, they said, “John the Baptizer has sent us to you, saying, ‘Are you he who comes, or should we look for another?’”', pt: 'Quando aqueles homens chegaram junto dele, disseram: João, o Batista, enviou-nos a perguntar-te: És tu aquele que havia de vir, ou havemos de esperar outro?' },
      { v: 21, en: 'In that hour he cured many of diseases and plagues and evil spirits; and to many who were blind he gave sight.', pt: 'Naquela mesma hora, curou a muitos de doenças, de moléstias e de espíritos malignos; e deu vista a muitos cegos.' },
      { v: 22, en: 'Jesus answered them, “Go and tell John the things which you have seen and heard: that the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them.', pt: 'Então lhes respondeu: Ide, e contai a João o que tens visto e ouvido: os cegos vêem, os coxos andam, os leprosos são purificados, e os surdos ouvem; os mortos são ressuscitados, e aos pobres é anunciado o evangelho.' },
      { v: 23, en: 'Blessed is he who finds no occasion for stumbling in me.”', pt: 'E bem-aventurado aquele que não se escandalizar de mim.' },
      { v: 24, en: 'When John’s messengers had departed, he began to tell the multitudes about John, “What did you go out into the wilderness to see? A reed shaken by the wind?', pt: 'E, tendo-se retirado os mensageiros de João, Jesus começou a dizer às multidões a respeito de João: Que saístes a ver no deserto? um caniço agitado pelo vento?' },
      { v: 25, en: 'But what did you go out to see? A man clothed in soft clothing? Behold, those who are gorgeously dressed, and live delicately, are in kings’ courts.', pt: 'Mas que saístes a ver? um homem trajado de vestes luxuosas? Eis que aqueles que trajam roupas preciosas, e vivem em delícias, estão nos paços reais.' },
      { v: 26, en: 'But what did you go out to see? A prophet? Yes, I tell you, and much more than a prophet.', pt: 'Mas que saístes a ver? um profeta? Sim, vos digo, e muito mais do que profeta.' },
      { v: 27, en: 'This is he of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’', pt: 'Este é aquele de quem está escrito: Eis aí envio ante a tua face o meu mensageiro, que há de preparar adiante de ti o teu caminho.' },
      { v: 28, en: '“For I tell you, among those who are born of women there is not a greater prophet than John the Baptizer, yet he who is least in God’s Kingdom is greater than he.”', pt: 'Pois eu vos digo que, entre os nascidos de mulher, não há nenhum maior do que João; mas aquele que é o menor no re medida com é maior do que ele.' },
      { v: 29, en: 'When all the people and the tax collectors heard this, they declared God to be just, having been baptized with John’s baptism.', pt: 'E todo o povo que o ouviu, e até os publicanos, reconheceram a justiça de Deus, recebendo o batismo de João.' },
      { v: 30, en: 'But the Pharisees and the lawyers rejected the counsel of God, not being baptized by him themselves.', pt: 'Mas os fariseus e os doutores da lei rejeitaram o conselho de Deus quando a si mesmos, não sendo batizados por ele.' },
      { v: 31, en: '“To what then will I liken the people of this generation? What are they like?', pt: 'A que, pois, compararei os homens desta geração, e a que são semelhantes?' },
      { v: 32, en: 'They are like children who sit in the marketplace, and call to one another, saying, ‘We piped to you, and you didn’t dance. We mourned, and you didn’t weep.’', pt: 'São semelhantes aos meninos que, sentados nas praças, gritam uns para os outros: Tocamo-vos flauta, e não dançastes; cantamos lamentações, e não chorastes.' },
      { v: 33, en: 'For John the Baptizer came neither eating bread nor drinking wine, and you say, ‘He has a demon.’', pt: 'Porquanto veio João, o Batista, não comendo pão nem bebendo vinho, e dizeis: Tem demônio;' },
      { v: 34, en: 'The Son of Man has come eating and drinking, and you say, ‘Behold, a gluttonous man, and a drunkard; a friend of tax collectors and sinners!’', pt: 'veio o Filho do homem, comendo e bebendo, e dizeis: Eis aí um comilão e bebedor de vinho, amigo de publicanos e pecadores.' },
      { v: 35, en: 'Wisdom is justified by all her children.”', pt: 'Mas a sabedoria é justificada por todos os seus filhos.' },
      { v: 36, en: 'One of the Pharisees invited him to eat with him. He entered into the Pharisee’s house, and sat at the table.', pt: 'Um dos fariseus convidou-o para comer com ele; e entrando em casa do fariseu, reclinou-se à mesa.' },
      { v: 37, en: 'Behold, a woman in the city who was a sinner, when she knew that he was reclining in the Pharisee’s house, brought an alabaster jar of ointment.', pt: 'E eis que uma mulher pecadora que havia na cidade, quando soube que ele estava à mesa em casa do fariseu, trouxe um vaso de alabastro com bálsamo;' },
      { v: 38, en: 'Standing behind at his feet weeping, she began to wet his feet with her tears, and she wiped them with the hair of her head, kissed his feet, and anointed them with the ointment.', pt: 'e estando por detrás, aos seus pés, chorando, começou a regar-lhe os pés com lágrimas e os enxugava com os cabelos da sua cabeça; e beijava-lhe os pés e ungia-os com o bálsamo.' },
      { v: 39, en: 'Now when the Pharisee who had invited him saw it, he said to himself, “This man, if he were a prophet, would have perceived who and what kind of woman this is who touches him, that she is a sinner.”', pt: 'Mas, ao ver isso, o fariseu que o convidara falava consigo, dizendo: Se este homem fosse profeta, saberia quem e de que qualidade é essa mulher que o toca, pois é uma pecadora.' },
      { v: 40, en: 'Jesus answered him, “Simon, I have something to tell you.” He said, “Teacher, say on.”', pt: 'E respondendo Jesus, disse-lhe: Simão, tenho uma coisa a dizer-te. Respondeu ele: Dize-a, Mestre.' },
      { v: 41, en: '“A certain lender had two debtors. The one owed five hundred denarii, and the other fifty.', pt: 'Certo credor tinha dois devedores; um lhe devia quinhentos denários, e outro cinquenta.' },
      { v: 42, en: 'When they couldn’t pay, he forgave them both. Which of them therefore will love him most?”', pt: 'Não tendo eles com que pagar, perdoou a ambos. Qual deles, pois, o amará mais?' },
      { v: 43, en: 'Simon answered, “He, I suppose, to whom he forgave the most.” He said to him, “You have judged correctly.”', pt: 'Respondeu Simão: Suponho que é aquele a quem mais perdoou. Replicou-lhe Jesus: Julgaste bem.' },
      { v: 44, en: 'Turning to the woman, he said to Simon, “Do you see this woman? I entered into your house, and you gave me no water for my feet, but she has wet my feet with her tears, and wiped them with the hair of her head.', pt: 'E, voltando-se para a mulher, disse a Simão: Vês tu esta mulher? Entrei em tua casa, e não me deste água para os pés; mas esta com suas lágrimas os regou e com seus cabelos os enxugou.' },
      { v: 45, en: 'You gave me no kiss, but she, since the time I came in, has not ceased to kiss my feet.', pt: 'Não me deste ósculo; ela, porém, desde que entrei, não tem cessado de beijar-me os pés.' },
      { v: 46, en: 'You didn’t anoint my head with oil, but she has anointed my feet with ointment.', pt: 'Não me ungiste a cabeça com óleo; mas esta com bálsamo ungiu-me os pés.' },
      { v: 47, en: 'Therefore I tell you, her sins, which are many, are forgiven, for she loved much. But to whom little is forgiven, the same loves little.”', pt: 'Por isso te digo: Perdoados lhe são os pecados, que são muitos; porque ela muito amou; mas aquele a quem pouco se perdoa, pouco ama.' },
      { v: 48, en: 'He said to her, “Your sins are forgiven.”', pt: 'E disse a ela: Perdoados são os teus pecados.' },
      { v: 49, en: 'Those who sat at the table with him began to say to themselves, “Who is this who even forgives sins?”', pt: 'Mas os que estavam com ele à mesa começaram a dizer entre si: Quem é este que até perdoa pecados?' },
      { v: 50, en: 'He said to the woman, “Your faith has saved you. Go in peace.”', pt: 'Jesus, porém, disse à mulher: A tua fé te salvou; vai-te em paz.' },
    ],
    8: [
      { v: 1, en: 'Soon afterwards, he went about through cities and villages, preaching and bringing the good news of God’s Kingdom. With him were the twelve,', pt: 'Logo depois disso, andava Jesus de cidade em cidade, e de aldeia em aldeia, pregando e anunciando o evangelho do reino de Deus; e iam com ele os doze,' },
      { v: 2, en: 'and certain women who had been healed of evil spirits and infirmities: Mary who was called Magdalene, from whom seven demons had gone out;', pt: 'bem como algumas mulheres que haviam sido curadas de espíritos malignos e de enfermidades: Maria, chamada Madalena, da qual tinham saído sete demônios.' },
      { v: 3, en: 'and Joanna, the wife of Chuzas, Herod’s steward; Susanna; and many others; who served them from their possessions.', pt: 'Joana, mulher de Cuza, procurador de Herodes, Susana, e muitas outras que os serviam com os seus bens.' },
      { v: 4, en: 'When a great multitude came together, and people from every city were coming to him, he spoke by a parable.', pt: 'Ora, ajuntando-se uma grande multidão, e vindo ter com ele gente de todas as cidades, disse Jesus por parábola:' },
      { v: 5, en: '“The farmer went out to sow his seed. As he sowed, some fell along the road, and it was trampled under foot, and the birds of the sky devoured it.', pt: 'Saiu o semeador a semear a sua semente. E quando semeava, uma parte da semente caiu à beira do caminho; e foi pisada, e as aves do céu a comeram.' },
      { v: 6, en: 'Other seed fell on the rock, and as soon as it grew, it withered away, because it had no moisture.', pt: 'Outra caiu sobre pedra; e, nascida, secou-se porque não havia umidade.' },
      { v: 7, en: 'Other fell amid the thorns, and the thorns grew with it, and choked it.', pt: 'E outra caiu no meio dos espinhos; e crescendo com ela os espinhos, sufocaram-na.' },
      { v: 8, en: 'Other fell into the good ground, and grew, and produced one hundred times as much fruit.” As he said these things, he called out, “He who has ears to hear, let him hear!”', pt: 'Mas outra caiu em boa terra; e, nascida, produziu fruto, cem por um. Dizendo ele estas coisas, clamava: Quem tem ouvidos para ouvir, ouça.' },
      { v: 9, en: 'Then his disciples asked him, “What does this parable mean?”', pt: 'Perguntaram-lhe então seus discípulos o que significava essa parábola.' },
      { v: 10, en: 'He said, “To you it is given to know the mysteries of God’s Kingdom, but to the rest in parables; that ‘seeing they may not see, and hearing they may not understand.’', pt: 'Respondeu ele: A vós é dado conhecer os mistérios do reino de Deus; mas aos outros se fala por parábolas; para que vendo, não vejam, e ouvindo, não entendam.' },
      { v: 11, en: 'Now the parable is this: The seed is the word of God.', pt: 'É, pois, esta a parábola: A semente é a palavra de Deus.' },
      { v: 12, en: 'Those along the road are those who hear, then the devil comes, and takes away the word from their heart, that they may not believe and be saved.', pt: 'Os que estão à beira do caminho são os que ouvem; mas logo vem o Diabo e tira-lhe do coração a palavra, para que não suceda que, crendo, sejam salvos.' },
      { v: 13, en: 'Those on the rock are they who, when they hear, receive the word with joy; but these have no root, who believe for a while, then fall away in time of temptation.', pt: 'Os que estão sobre a pedra são os que, ouvindo a palavra, a recebem com alegria; mas estes não têm raiz, apenas crêem por algum tempo, mas na hora da provação se desviam.' },
      { v: 14, en: 'That which fell among the thorns, these are those who have heard, and as they go on their way they are choked with cares, riches, and pleasures of life, and bring no fruit to maturity.', pt: 'A parte que caiu entre os espinhos são os que ouviram e, indo seu caminho, são sufocados pelos cuidados, riquezas, e deleites desta vida e não dão fruto com perfeição.' },
      { v: 15, en: 'Those in the good ground, these are those who with an honest and good heart, having heard the word, hold it tightly, and produce fruit with perseverance.', pt: 'Mas a que caiu em boa terra são os que, ouvindo a palavra com coração reto e bom, a retêm e dão fruto com perseverança.' },
      { v: 16, en: '“No one, when he has lit a lamp, covers it with a container, or puts it under a bed; but puts it on a stand, that those who enter in may see the light.', pt: 'Ninguém, pois, acende uma candeia e a cobre com algum vaso, ou a põe debaixo da cama; mas põe-na no velador, para que os que entram vejam a luz.' },
      { v: 17, en: 'For nothing is hidden, that will not be revealed; nor anything secret, that will not be known and come to light.', pt: 'Porque não há coisa encoberta que não haja de manifestar-se, nem coisa secreta que não haja de saber-se e vir à luz.' },
      { v: 18, en: 'Be careful therefore how you hear. For whoever has, to him will be given; and whoever doesn’t have, from him will be taken away even that which he thinks he has.”', pt: 'Vede, pois, como ouvis; porque a qualquer que tiver lhe será dado, e a qualquer que não tiver, até o que parece ter lhe será tirado.' },
      { v: 19, en: 'His mother and brothers came to him, and they could not come near him for the crowd.', pt: 'Vieram, então, ter com ele sua mãe e seus irmãos, e não podiam aproximar-se dele por causa da multidão.' },
      { v: 20, en: 'Some people told him, “Your mother and your brothers stand outside, desiring to see you.”', pt: 'Foi-lhe dito: Tua mãe e teus irmãos estão lá fora, e querem ver-te.' },
      { v: 21, en: 'But he answered them, “My mother and my brothers are these who hear the word of God, and do it.”', pt: 'Ele, porém, lhes respondeu: Minha mãe e meus irmãos são estes que ouvem a palavra de Deus e a observam.' },
      { v: 22, en: 'Now on one of those days, he entered into a boat, himself and his disciples, and he said to them, “Let’s go over to the other side of the lake.” So they launched out.', pt: 'Ora, aconteceu certo dia que entrou num barco com seus discípulos, e disse-lhes: Passemos à outra margem do lago. E partiram.' },
      { v: 23, en: 'But as they sailed, he fell asleep. A wind storm came down on the lake, and they were taking on dangerous amounts of water.', pt: 'Enquanto navegavam, ele adormeceu; e desceu uma tempestade de vento sobre o lago; e o barco se enchia de água, de sorte que perigavam.' },
      { v: 24, en: 'They came to him, and awoke him, saying, “Master, master, we are dying!” He awoke, and rebuked the wind and the raging of the water, and they ceased, and it was calm.', pt: 'Chegando-se a ele, o despertaram, dizendo: Mestre, Mestre, estamos perecendo. E ele, levantando-se, repreendeu o vento e a fúria da água; e cessaram, e fez-se bonança.' },
      { v: 25, en: 'He said to them, “Where is your faith?” Being afraid they marveled, saying to one another, “Who is this then, that he commands even the winds and the water, and they obey him?”', pt: 'Então lhes perguntou: Onde está a vossa fé? Eles, atemorizados, admiraram-se, dizendo uns aos outros: Quem, pois, é este, que até aos ventos e à água manda, e lhe obedecem?' },
      { v: 26, en: 'They arrived at the country of the Gadarenes, which is opposite Galilee.', pt: 'Apontaram à terra dos gerasenos, que está defronte da Galiléia.' },
      { v: 27, en: 'When Jesus stepped ashore, a certain man out of the city who had demons for a long time met him. He wore no clothes, and didn’t live in a house, but in the tombs.', pt: 'Logo que saltou em terra, saiu-lhe ao encontro um homem da cidade, possesso de demônios, que havia muito tempo não vestia roupa, nem morava em casa, mas nos sepulcros.' },
      { v: 28, en: 'When he saw Jesus, he cried out, and fell down before him, and with a loud voice said, “What do I have to do with you, Jesus, you Son of the Most High God? I beg you, don’t torment me!”', pt: 'Quando ele viu a Jesus, gritou, prostrou-se diante dele, e com grande voz exclamou: Que tenho eu contigo, Jesus, Filho do Deus Altíssimo? Rogo-te que não me atormentes.' },
      { v: 29, en: 'For Jesus was commanding the unclean spirit to come out of the man. For the unclean spirit had often seized the man. He was kept under guard, and bound with chains and fetters. Breaking the bonds apart, he was driven by the demon into the desert.', pt: 'Porque Jesus ordenara ao espírito imundo que saísse do homem. Pois já havia muito tempo que se apoderara dele; e guardavam-no preso com grilhões e cadeias; mas ele, quebrando as prisões, era impelido pelo demônio para os desertos.' },
      { v: 30, en: 'Jesus asked him, “What is your name?” He said, “Legion,” for many demons had entered into him.', pt: 'Perguntou-lhe Jesus: Qual é o teu nome? Respondeu ele: Legião; porque tinham entrado nele muitos demônios.' },
      { v: 31, en: 'They begged him that he would not command them to go into the abyss.', pt: 'E rogavam-lhe que não os mandasse para o abismo.' },
      { v: 32, en: 'Now there was there a herd of many pigs feeding on the mountain, and they begged him that he would allow them to enter into those. He allowed them.', pt: 'Ora, andava ali pastando no monte uma grande manada de porcos; rogaram-lhe, pois que lhes permitisse entrar neles, e lho permitiu.' },
      { v: 33, en: 'The demons came out of the man, and entered into the pigs, and the herd rushed down the steep bank into the lake, and were drowned.', pt: 'E tendo os demônios saído do homem, entraram nos porcos; e a manada precipitou-se pelo despenhadeiro no lago, e afogou-se.' },
      { v: 34, en: 'When those who fed them saw what had happened, they fled, and told it in the city and in the country.', pt: 'Quando os pastores viram o que acontecera, fugiram, e foram anunciá-lo na cidade e nos campos.' },
      { v: 35, en: 'People went out to see what had happened. They came to Jesus, and found the man from whom the demons had gone out, sitting at Jesus’ feet, clothed and in his right mind; and they were afraid.', pt: 'Saíram, pois, a ver o que tinha acontecido, e foram ter com Jesus, a cujos pés acharam sentado, vestido e em perfeito juízo, o homem de quem havia saído os demônios; e se atemorizaram.' },
      { v: 36, en: 'Those who saw it told them how he who had been possessed by demons was healed.', pt: 'Os que tinham visto aquilo contaram-lhes como fora curado o endemoninhado.' },
      { v: 37, en: 'All the people of the surrounding country of the Gadarenes asked him to depart from them, for they were very much afraid. He entered into the boat, and returned.', pt: 'Então todo o povo da região dos gerasenos rogou-lhe que se retirasse deles; porque estavam possuídos de grande medo. Pelo que ele entrou no barco, e voltou.' },
      { v: 38, en: 'But the man from whom the demons had gone out begged him that he might go with him, but Jesus sent him away, saying,', pt: 'Pedia-lhe, porém, o homem de quem haviam saído os demônios que o deixasse estar com ele; mas Jesus o despediu, dizendo:' },
      { v: 39, en: '“Return to your house, and declare what great things God has done for you.” He went his way, proclaiming throughout the whole city what great things Jesus had done for him.', pt: 'Volta para tua casa, e conta tudo quanto Deus te fez. E ele se retirou, publicando por toda a cidade tudo quanto Jesus lhe fizera.' },
      { v: 40, en: 'When Jesus returned, the multitude welcomed him, for they were all waiting for him.', pt: 'Quando Jesus voltou, a multidão o recebeu; porque todos o estavam esperando.' },
      { v: 41, en: 'Behold, there came a man named Jairus, and he was a ruler of the synagogue. He fell down at Jesus’ feet, and begged him to come into his house,', pt: 'E eis que veio um homem chamado Jairo, que era chefe da sinagoga; e prostrando-se aos pés de Jesus, rogava-lhe que fosse a sua casa;' },
      { v: 42, en: 'for he had an only daughter, about twelve years of age, and she was dying. But as he went, the multitudes pressed against him.', pt: 'porque tinha uma filha única, de cerca de doze anos, que estava à morte. Enquanto, pois, ele ia, apertavam-no as multidões.' },
      { v: 43, en: 'A woman who had a flow of blood for twelve years, who had spent all her living on physicians, and could not be healed by any,', pt: 'E certa mulher, que tinha uma hemorragia havia doze anos [e gastara com os médicos todos os seus haveres] e por ninguém pudera ser curada,' },
      { v: 44, en: 'came behind him, and touched the fringe of his cloak, and immediately the flow of her blood stopped.', pt: 'chegando-se por detrás, tocou-lhe a orla do manto, e imediatamente cessou a sua hemorragia.' },
      { v: 45, en: 'Jesus said, “Who touched me?” When all denied it, Peter and those with him said, “Master, the multitudes press and jostle you, and you say, ‘Who touched me?’ ”', pt: 'Perguntou Jesus: Quem é que me tocou? Como todos negassem, disse-lhe Pedro: Mestre, as multidões te apertam e te oprimem.' },
      { v: 46, en: 'But Jesus said, “Someone did touch me, for I perceived that power has gone out of me.”', pt: 'Mas disse Jesus: Alguém me tocou; pois percebi que de mim saiu poder.' },
      { v: 47, en: 'When the woman saw that she was not hidden, she came trembling, and falling down before him declared to him in the presence of all the people the reason why she had touched him, and how she was healed immediately.', pt: 'Então, vendo a mulher que não passara despercebida, aproximou-se tremendo e, prostrando-se diante dele, declarou-lhe perante todo o povo a causa por que lhe havia tocado, e como fora imediatamente curada.' },
      { v: 48, en: 'He said to her, “Daughter, cheer up. Your faith has made you well. Go in peace.”', pt: 'Disse-lhe ele: Filha, a tua fé te salvou; vai-te em paz.' },
      { v: 49, en: 'While he still spoke, one from the ruler of the synagogue’s house came, saying to him, “Your daughter is dead. Don’t trouble the Teacher.”', pt: 'Enquanto ainda falava, veio alguém da casa do chefe da sinagoga dizendo: A tua filha já está morta; não incomodes mais o Mestre.' },
      { v: 50, en: 'But Jesus hearing it, answered him, “Don’t be afraid. Only believe, and she will be healed.”', pt: 'Jesus, porém, ouvindo-o, respondeu-lhe: Não temas: crê somente, e será salva.' },
      { v: 51, en: 'When he came to the house, he didn’t allow anyone to enter in, except Peter, John, James, the father of the child, and her mother.', pt: 'Tendo chegado à casa, a ninguém deixou entrar com ele, senão a Pedro, João, Tiago, e o pai e a mãe da menina.' },
      { v: 52, en: 'All were weeping and mourning her, but he said, “Don’t weep. She isn’t dead, but sleeping.”', pt: 'E todos choravam e pranteavam; ele, porém, disse: Não choreis; ela não está morta, mas dorme.' },
      { v: 53, en: 'They were ridiculing him, knowing that she was dead.', pt: 'E riam-se dele, sabendo que ela estava morta.' },
      { v: 54, en: 'But he put them all outside, and taking her by the hand, he called, saying, “Child, arise!”', pt: 'Então ele, tomando-lhe a mão, exclamou: Menina, levanta-te.' },
      { v: 55, en: 'Her spirit returned, and she rose up immediately. He commanded that something be given to her to eat.', pt: 'E o seu espírito voltou, e ela se levantou imediatamente; e Jesus mandou que lhe desse de comer.' },
      { v: 56, en: 'Her parents were amazed, but he commanded them to tell no one what had been done.', pt: 'E seus pais ficaram maravilhados; e ele mandou-lhes que a ninguém contassem o que havia sucedido.' },
    ],
    9: [
      { v: 1, en: 'He called the twelve together, and gave them power and authority over all demons, and to cure diseases.', pt: 'Reunindo os doze, deu-lhes poder e autoridade sobre todos os demônios, e para curarem doenças;' },
      { v: 2, en: 'He sent them out to preach God’s Kingdom and to heal the sick.', pt: 'e enviou-os a pregar o reino de Deus, e fazer curas,' },
      { v: 3, en: 'He said to them, “Take nothing for your journey—neither staffs, nor wallet, nor bread, nor money; neither have two coats each.', pt: 'dizendo-lhes: Nada leveis para o caminho, nem bordão, nem alforje, nem pão, nem dinheiro; nem tenhais duas túnicas.' },
      { v: 4, en: 'Into whatever house you enter, stay there, and depart from there.', pt: 'Em qualquer casa em que entrardes, nela ficai, e dali partireis.' },
      { v: 5, en: 'As many as don’t receive you, when you depart from that city, shake off even the dust from your feet for a testimony against them.”', pt: 'Mas, onde quer que não vos receberem, saindo daquela cidade, sacudi o pó dos vossos pés, em testemunho contra eles.' },
      { v: 6, en: 'They departed, and went throughout the villages, preaching the Good News, and healing everywhere.', pt: 'Saindo, pois, os discípulos percorreram as aldeias, anunciando o evangelho e fazendo curas por toda parte.' },
      { v: 7, en: 'Now Herod the tetrarch heard of all that was done by him; and he was very perplexed, because it was said by some that John had risen from the dead,', pt: 'Ora, o tetrarca Herodes soube de tudo o que se passava, e ficou muito perplexo, porque diziam uns: João ressuscitou dos mortos;' },
      { v: 8, en: 'and by some that Elijah had appeared, and by others that one of the old prophets had risen again.', pt: 'outros: Elias apareceu; e outros: Um dos antigos profetas se levantou.' },
      { v: 9, en: 'Herod said, “John I beheaded, but who is this, about whom I hear such things?” He sought to see him.', pt: 'Herodes, porém, disse: A João eu mandei degolar; quem é, pois, este a respeito de quem ouço tais coisas? E procurava vê-lo.' },
      { v: 10, en: 'The apostles, when they had returned, told him what things they had done. He took them, and withdrew apart to a desert region of a city called Bethsaida.', pt: 'Quando os apóstolos voltaram, contaram-lhe tudo o que havia feito. E ele, levando-os consigo, retirou-se à parte para uma cidade chamada Betsaida.' },
      { v: 11, en: 'But the multitudes, perceiving it, followed him. He welcomed them, and spoke to them of God’s Kingdom, and he cured those who needed healing.', pt: 'Mas as multidões, percebendo isto, seguiram-no; e ele as recebeu, e falava-lhes do reino de Deus, e sarava os que necessitavam de cura.' },
      { v: 12, en: 'The day began to wear away; and the twelve came, and said to him, “Send the multitude away, that they may go into the surrounding villages and farms, and lodge, and get food, for we are here in a deserted place.”', pt: 'Ora, quando o dia começava a declinar, aproximando-se os doze, disseram-lhe: Despede a multidão, para que, indo às aldeias e aos sítios em redor, se hospedem, e achem o que comer; porque aqui estamos em lugar deserto.' },
      { v: 13, en: 'But he said to them, “You give them something to eat.” They said, “We have no more than five loaves and two fish, unless we should go and buy food for all these people.”', pt: 'Mas ele lhes disse: Dai-lhes vós de comer. Responderam eles: Não temos senão cinco pães e dois peixes; salvo se nós formos comprar comida para todo este povo.' },
      { v: 14, en: 'For they were about five thousand men. He said to his disciples, “Make them sit down in groups of about fifty each.”', pt: 'Pois eram cerca de cinco mil homens. Então disse a seus discípulos: Fazei-os reclinar-se em grupos de cerca de cinquenta cada um.' },
      { v: 15, en: 'They did so, and made them all sit down.', pt: 'Assim o fizeram, mandando que todos se reclinassem.' },
      { v: 16, en: 'He took the five loaves and the two fish, and looking up to the sky, he blessed them, and broke them, and gave them to the disciples to set before the multitude.', pt: 'E tomando Jesus os cinco pães e os dois peixes, e olhando para o céu, os abençoou e partiu, e os entregava aos seus discípulos para os porem diante da multidão.' },
      { v: 17, en: 'They ate, and were all filled. They gathered up twelve baskets of broken pieces that were left over.', pt: 'Todos, pois, comeram e se fartaram; e foram levantados, do que lhes sobejou, doze cestos de pedaços.' },
      { v: 18, en: 'As he was praying alone, the disciples were with him, and he asked them, “Who do the multitudes say that I am?”', pt: 'Enquanto ele estava orando à parte achavam-se com ele somente seus discípulos; e perguntou-lhes: Quem dizem as multidões que eu sou?' },
      { v: 19, en: 'They answered, “‘John the Baptizer,’ but others say, ‘Elijah,’ and others, that one of the old prophets is risen again.”', pt: 'Responderam eles: Uns dizem: João, o Batista; outros: Elias; e ainda outros, que um dos antigos profetas se levantou.' },
      { v: 20, en: 'He said to them, “But who do you say that I am?” Peter answered, “The Christ of God.”', pt: 'Então lhes perguntou: Mas vós, quem dizeis que eu sou? Respondendo Pedro, disse: O Cristo de Deus.' },
      { v: 21, en: 'But he warned them, and commanded them to tell this to no one,', pt: 'Jesus, porém, advertindo-os, mandou que não contassem isso a ninguém;' },
      { v: 22, en: 'saying, “The Son of Man must suffer many things, and be rejected by the elders, chief priests, and scribes, and be killed, and the third day be raised up.”', pt: 'e disse-lhes: É necessário que o Filho do homem padeça muitas coisas, que seja rejeitado pelos anciãos, pelos principais sacerdotes e escribas, que seja morto, e que ao terceiro dia ressuscite.' },
      { v: 23, en: 'He said to all, “If anyone desires to come after me, let him deny himself, take up his cross, and follow me.', pt: 'Em seguida dizia a todos: Se alguém quer vir após mim, negue-se a si mesmo, tome cada dia a sua cruz, e siga-me.' },
      { v: 24, en: 'For whoever desires to save his life will lose it, but whoever will lose his life for my sake, the same will save it.', pt: 'Pois quem quiser salvar a sua vida, perdê-la-á; mas quem perder a sua vida por amor de mim, esse a salvará.' },
      { v: 25, en: 'For what does it profit a man if he gains the whole world, and loses or forfeits his own self?', pt: 'Pois, que aproveita ao homem ganhar o mundo inteiro, e perder-se, ou prejudicar-se a si mesmo?' },
      { v: 26, en: 'For whoever will be ashamed of me and of my words, of him will the Son of Man be ashamed, when he comes in his glory, and the glory of the Father, and of the holy angels.', pt: 'Porque, quem se envergonhar de mim e das minhas palavras, dele se envergonhará o Filho do homem, quando vier na sua glória, e na do Pai e dos santos anjos.' },
      { v: 27, en: 'But I tell you the truth: There are some of those who stand here, who will in no way taste of death, until they see God’s Kingdom.”', pt: 'Mas em verdade vos digo: Alguns há, dos que estão aqui, que de modo nenhum provarão a morte até que vejam o reino de Deus.' },
      { v: 28, en: 'About eight days after these sayings, he took with him Peter, John, and James, and went up onto the mountain to pray.', pt: 'Cerca de oito dias depois de ter proferido essas palavras, tomou Jesus consigo a Pedro, a João e a Tiago, e subiu ao monte para orar.' },
      { v: 29, en: 'As he was praying, the appearance of his face was altered, and his clothing became white and dazzling.', pt: 'Enquanto ele orava, mudou-se a aparência do seu rosto, e a sua roupa tornou-se branca e resplandecente.' },
      { v: 30, en: 'Behold, two men were talking with him, who were Moses and Elijah,', pt: 'E eis que estavam falando com ele dois varões, que eram Moisés e Elias,' },
      { v: 31, en: 'who appeared in glory, and spoke of his departure, which he was about to accomplish at Jerusalem.', pt: 'os quais apareceram com glória, e falavam da sua partida que estava para cumprir-se em Jerusalém.' },
      { v: 32, en: 'Now Peter and those who were with him were heavy with sleep, but when they were fully awake, they saw his glory, and the two men who stood with him.', pt: 'Ora, Pedro e os que estavam com ele se haviam deixado vencer pelo sono; despertando, porém, viram a sua glória e os dois varões que estavam com ele.' },
      { v: 33, en: 'As they were parting from him, Peter said to Jesus, “Master, it is good for us to be here. Let’s make three tents: one for you, and one for Moses, and one for Elijah,” not knowing what he said.', pt: 'E, quando estes se apartavam dele, disse Pedro a Jesus: Mestre, bom é estarmos nós aqui: façamos, pois, três cabanas, uma para ti, uma para Moisés, e uma para Elias, não sabendo o que dizia.' },
      { v: 34, en: 'While he said these things, a cloud came and overshadowed them, and they were afraid as they entered into the cloud.', pt: 'Enquanto ele ainda falava, veio uma nuvem que os cobriu; e se atemorizaram ao entrarem na nuvem.' },
      { v: 35, en: 'A voice came out of the cloud, saying, “This is my beloved Son. Listen to him!”', pt: 'E da nuvem saiu uma voz que dizia: Este é o meu Filho, o meu eleito; a ele ouvi.' },
      { v: 36, en: 'When the voice came, Jesus was found alone. They were silent, and told no one in those days any of the things which they had seen.', pt: 'Ao soar esta voz, Jesus foi achado sozinho; e eles calaram-se, e por aqueles dias não contaram a ninguém nada do que tinham visto.' },
      { v: 37, en: 'On the next day, when they had come down from the mountain, a great multitude met him.', pt: 'No dia seguinte, quando desceram do monte, veio-lhe ao encontro uma grande multidão.' },
      { v: 38, en: 'Behold, a man from the crowd called out, saying, “Teacher, I beg you to look at my son, for he is my only child.', pt: 'E eis que um homem dentre a multidão clamou, dizendo: Mestre, peço-te que olhes para meu filho, porque é o único que tenho;' },
      { v: 39, en: 'Behold, a spirit takes him, he suddenly cries out, and it convulses him so that he foams, and it hardly departs from him, bruising him severely.', pt: 'pois um espírito se apodera dele, fazendo-o gritar subitamente, convulsiona-o até escumar e, mesmo depois de o ter quebrantado, dificilmente o larga.' },
      { v: 40, en: 'I begged your disciples to cast it out, and they couldn’t.”', pt: 'E roguei aos teus discípulos que o expulsassem, mas não puderam.' },
      { v: 41, en: 'Jesus answered, “Faithless and perverse generation, how long shall I be with you and bear with you? Bring your son here.”', pt: 'Respondeu Jesus: Ó geração incrédula e perversa! até quando estarei convosco e vos sofrerei? Traze-me cá o teu filho.' },
      { v: 42, en: 'While he was still coming, the demon threw him down and convulsed him violently. But Jesus rebuked the unclean spirit, and healed the boy, and gave him back to his father.', pt: 'Ainda quando ele vinha chegando, o demônio o derribou e o convulsionou; mas Jesus repreendeu o espírito imundo, curou o menino e o entregou a seu pai.' },
      { v: 43, en: 'They were all astonished at the majesty of God. But while all were marveling at all the things which Jesus did, he said to his disciples,', pt: 'E todos se maravilhavam da majestade de Deus. E admirando-se todos de tudo o que Jesus fazia, disse ele a seus discípulos:' },
      { v: 44, en: '“Let these words sink into your ears, for the Son of Man will be delivered up into the hands of men.”', pt: 'Ponde vós estas palavras em vossos ouvidos; pois o Filho do homem está para ser entregue nas mãos dos homens.' },
      { v: 45, en: 'But they didn’t understand this saying. It was concealed from them, that they should not perceive it, and they were afraid to ask him about this saying.', pt: 'Eles, porém, não entendiam essa palavra, cujo sentido lhes era encoberto para que não o compreendessem; e temiam interrogá-lo a esse respeito.' },
      { v: 46, en: 'There arose an argument among them about which of them was the greatest.', pt: 'E suscitou-se entre eles uma discussão sobre qual deles seria o maior.' },
      { v: 47, en: 'Jesus, perceiving the reasoning of their hearts, took a little child, and set him by his side,', pt: 'Mas Jesus, percebendo o pensamento de seus corações, tomou uma criança, pô-la junto de si,' },
      { v: 48, en: 'and said to them, “Whoever receives this little child in my name receives me. Whoever receives me receives him who sent me. For whoever is least among you all, this one will be great.”', pt: 'e disse-lhes: Qualquer que receber esta criança em meu nome, a mim me recebe; e qualquer que me receber a mim, recebe aquele que me enviou; pois aquele que entre vós todos é o menor, esse é grande.' },
      { v: 49, en: 'John answered, “Master, we saw someone casting out demons in your name, and we forbade him, because he doesn’t follow with us.”', pt: 'Disse-lhe João: Mestre, vimos um homem que em teu nome expulsava demônios; e lho proibimos, porque não segue conosco.' },
      { v: 50, en: 'Jesus said to him, “Don’t forbid him, for he who is not against us is for us.”', pt: 'Respondeu-lhe Jesus: Não lho proibais; porque quem não é contra vós é por vós.' },
      { v: 51, en: 'It came to pass, when the days were near that he should be taken up, he intently set his face to go to Jerusalem,', pt: 'Ora, quando se completavam os dias para a sua assunção, manifestou o firme propósito de ir a Jerusalém.' },
      { v: 52, en: 'and sent messengers before his face. They went, and entered into a village of the Samaritans, so as to prepare for him.', pt: 'Enviou, pois, mensageiros adiante de si. Indo eles, entraram numa aldeia de samaritanos para lhe prepararem pousada.' },
      { v: 53, en: 'They didn’t receive him, because he was traveling with his face set towards Jerusalem.', pt: 'Mas não o receberam, porque viajava em direção a Jerusalém.' },
      { v: 54, en: 'When his disciples, James and John, saw this, they said, “Lord, do you want us to command fire to come down from the sky, and destroy them, just as Elijah did?”', pt: 'Vendo isto os discípulos Tiago e João, disseram: Senhor, queres que mandemos descer fogo do céu para os consumir [como Elias também fez?]' },
      { v: 55, en: 'But he turned and rebuked them, “You don’t know of what kind of spirit you are.', pt: 'Ele porém, voltando-se, repreendeu-os, [e disse: Vós não sabeis de que espírito sois.]' },
      { v: 56, en: 'For the Son of Man didn’t come to destroy men’s lives, but to save them.” They went to another village.', pt: '[Pois o Filho do Homem não veio para destruir as vidas dos homens, mas para salvá-las.] E foram para outra aldeia.' },
      { v: 57, en: 'As they went on the way, a certain man said to him, “I want to follow you wherever you go, Lord.”', pt: 'Quando iam pelo caminho, disse-lhe um homem: Seguir-te-ei para onde quer que fores.' },
      { v: 58, en: 'Jesus said to him, “The foxes have holes, and the birds of the sky have nests, but the Son of Man has no place to lay his head.”', pt: 'Respondeu-lhe Jesus: As raposas têm covis, e as aves do céu têm ninhos; mas o Filho do homem não tem onde reclinar a cabeça.' },
      { v: 59, en: 'He said to another, “Follow me!” But he said, “Lord, allow me first to go and bury my father.”', pt: 'E a outro disse: Segue-me. Ao que este respondeu: Permite-me ir primeiro sepultar meu pai.' },
      { v: 60, en: 'But Jesus said to him, “Leave the dead to bury their own dead, but you go and announce God’s Kingdom.”', pt: 'Replicou-lhe Jesus: Deixa os mortos sepultar os seus próprios mortos; tu, porém, vai e anuncia o reino de Deus.' },
      { v: 61, en: 'Another also said, “I want to follow you, Lord, but first allow me to say good-bye to those who are at my house.”', pt: 'Jesus, porém, lhe respondeu: Ninguém que lança mão do arado e olha para trás é apto para o reino de Deus.' },
      { v: 62, en: 'But Jesus said to him, “No one, having put his hand to the plow, and looking back, is fit for God’s Kingdom.”', pt: 'But Jesus said to him, “No one, having put his hand to the plow, and looking back, is fit for God’s Kingdom.”' },
    ],
    10: [
      { v: 1, en: 'Now after these things, the Lord also appointed seventy others, and sent them two by two ahead of him into every city and place, where he was about to come.', pt: 'Depois disso designou o Senhor outros setenta, e os enviou adiante de si, de dois em dois, a todas as cidades e lugares aonde ele havia de ir.' },
      { v: 2, en: 'Then he said to them, “The harvest is indeed plentiful, but the laborers are few. Pray therefore to the Lord of the harvest, that he may send out laborers into his harvest.', pt: 'E dizia-lhes: Na verdade, a seara é grande, mas os trabalhadores são poucos; rogai, pois, ao Senhor da seara que mande trabalhadores para a sua seara.' },
      { v: 3, en: 'Go your ways. Behold, I send you out as lambs among wolves.', pt: 'Ide; eis que vos envio como cordeiros ao meio de lobos.' },
      { v: 4, en: 'Carry no purse, nor wallet, nor sandals. Greet no one on the way.', pt: 'Não leveis bolsa, nem alforge, nem alparcas; e a ninguém saudeis pelo caminho.' },
      { v: 5, en: 'Into whatever house you enter, first say, ‘Peace be to this house.’', pt: 'Em qualquer casa em que entrardes, dizei primeiro: Paz seja com esta casa.' },
      { v: 6, en: 'If a son of peace is there, your peace will rest on him; but if not, it will return to you.', pt: 'E se ali houver um filho da paz, repousará sobre ele a vossa paz; e se não, voltará para vós.' },
      { v: 7, en: 'Remain in that same house, eating and drinking the things they give, for the laborer is worthy of his wages. Don’t go from house to house.', pt: 'Ficai nessa casa, comendo e bebendo do que eles tiverem; pois digno é o trabalhador do seu salário. Não andeis de casa em casa.' },
      { v: 8, en: 'Into whatever city you enter, and they receive you, eat the things that are set before you.', pt: 'Também, em qualquer cidade em que entrardes, e vos receberem, comei do que puserem diante de vós.' },
      { v: 9, en: 'Heal the sick who are therein, and tell them, ‘God’s Kingdom has come near to you.’', pt: 'Curai os enfermos que nela houver, e dizer-lhes: É chegado a vós o reino de Deus.' },
      { v: 10, en: 'But into whatever city you enter, and they don’t receive you, go out into its streets and say,', pt: 'Mas em qualquer cidade em que entrardes, e vos não receberem, saíndo pelas ruas, dizei:' },
      { v: 11, en: '‘Even the dust from your city that clings to us, we wipe off against you. Nevertheless know this, that God’s Kingdom has come near to you.’', pt: 'Até o pó da vossa cidade, que se nos pegou aos pés, sacudimos contra vós. Contudo, sabei isto: que o reino de Deus é chegado.' },
      { v: 12, en: 'I tell you, it will be more tolerable in that day for Sodom than for that city.', pt: 'Digo-vos que naquele dia haverá menos rigor para Sodoma, do que para aquela cidade.' },
      { v: 13, en: '“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago, sitting in sackcloth and ashes.', pt: 'Ai de ti, Corazim! ai de ti, Betsaida! Porque, se em Tiro e em Sidom se tivessem operado os milagres que em vós se operaram, há muito, sentadas em cilício e cinza, elas se teriam arrependido.' },
      { v: 14, en: 'But it will be more tolerable for Tyre and Sidon in the judgment than for you.', pt: 'Contudo, para Tiro e Sidom haverá menos rigor no juízo do que para vós.' },
      { v: 15, en: 'You, Capernaum, who are exalted to heaven, will be brought down to Hades.', pt: 'E tu, Cafarnaum, porventura serás elevada até o céu? até o hades descerás.' },
      { v: 16, en: 'Whoever listens to you listens to me, and whoever rejects you rejects me. Whoever rejects me rejects him who sent me.”', pt: 'Quem vos ouve, a mim me ouve; e quem vos rejeita, a mim me rejeita; e quem a mim me rejeita, rejeita aquele que me enviou.' },
      { v: 17, en: 'The seventy returned with joy, saying, “Lord, even the demons are subject to us in your name!”', pt: 'Voltaram depois os setenta com alegria, dizendo: Senhor, em teu nome, até os demônios se nos submetem.' },
      { v: 18, en: 'He said to them, “I saw Satan having fallen like lightning from heaven.', pt: 'Respondeu-lhes ele: Eu via Satanás, como raio, cair do céu.' },
      { v: 19, en: 'Behold, I give you authority to tread on serpents and scorpions, and over all the power of the enemy. Nothing will in any way hurt you.', pt: 'Eis que vos dei autoridade para pisar serpentes e escorpiões, e sobre todo o poder do inimigo; e nada vos fará dano algum.' },
      { v: 20, en: 'Nevertheless, don’t rejoice in this, that the spirits are subject to you, but rejoice that your names are written in heaven.”', pt: 'Contudo, não vos alegreis porque se vos submetem os espíritos; alegrai-vos antes por estarem os vossos nomes escritos nos céus.' },
      { v: 21, en: 'In that same hour Jesus rejoiced in the Holy Spirit, and said, “I thank you, O Father, Lord of heaven and earth, that you have hidden these things from the wise and understanding, and revealed them to little children. Yes, Father, for so it was well-pleasing in your sight.”', pt: 'Naquela mesma hora exultou Jesus no Espírito Santo, e disse: Graças te dou, ó Pai, Senhor do céu e da terra, porque ocultaste estas coisas aos sábios e entendidos, e as revelaste aos pequeninos; sim, ó Pai, porque assim foi do teu agrado.' },
      { v: 22, en: 'Turning to the disciples, he said, “All things have been delivered to me by my Father. No one knows who the Son is, except the Father, and who the Father is, except the Son, and he to whomever the Son desires to reveal him.”', pt: 'Todas as coisas me foram entregues por meu Pai; e ninguém conhece quem é o Filho senão o Pai, nem quem é o Pai senão o Filho, e aquele a quem o Filho o quiser revelar.' },
      { v: 23, en: 'Turning to the disciples, he said privately, “Blessed are the eyes which see the things that you see,', pt: 'E voltando-se para os discípulos, disse-lhes em particular: Bem-aventurados os olhos que vêem o que vós vedes.' },
      { v: 24, en: 'for I tell you that many prophets and kings desired to see the things which you see, and didn’t see them, and to hear the things which you hear, and didn’t hear them.”', pt: 'Pois vos digo que muitos profetas e reis desejaram ver o que vós vedes, e não o viram; e ouvir o que ouvis, e não o ouviram.' },
      { v: 25, en: 'Behold, a certain lawyer stood up and tested him, saying, “Teacher, what shall I do to inherit eternal life?”', pt: 'E eis que se levantou certo doutor da lei e, para o experimentar, disse: Mestre, que farei para herdar a vida eterna?' },
      { v: 26, en: 'He said to him, “What is written in the law? How do you read it?”', pt: 'Perguntou-lhe Jesus: Que está escrito na lei? Como lês tu?' },
      { v: 27, en: 'He answered, “You shall love the Lord your God with all your heart, with all your soul, with all your strength, and with all your mind; and your neighbor as yourself.”', pt: 'Respondeu-lhe ele: Amarás ao Senhor teu Deus de todo o teu coração, de toda a tua alma, de todas as tuas forças e de todo o teu entendimento, e ao teu próximo como a ti mesmo.' },
      { v: 28, en: 'He said to him, “You have answered correctly. Do this, and you will live.”', pt: 'Tornou-lhe Jesus: Respondeste bem; faze isso, e viverás.' },
      { v: 29, en: 'But he, desiring to justify himself, asked Jesus, “Who is my neighbor?”', pt: 'Ele, porém, querendo justificar-se, perguntou a Jesus: E quem é o meu próximo?' },
      { v: 30, en: 'Jesus answered, “A certain man was going down from Jerusalem to Jericho, and he fell among robbers, who both stripped him and beat him, and departed, leaving him half dead.', pt: 'Jesus, prosseguindo, disse: Um homem descia de Jerusalém a Jericó, e caiu nas mãos de salteadores, os quais o despojaram e espancando-o, se retiraram, deixando-o meio morto.' },
      { v: 31, en: 'By chance a certain priest was going down that way. When he saw him, he passed by on the other side.', pt: 'Casualmente, descia pelo mesmo caminho certo sacerdote; e vendo-o, passou de largo.' },
      { v: 32, en: 'In the same way a Levite also, when he came to the place, and saw him, passed by on the other side.', pt: 'De igual modo também um levita chegou àquele lugar, viu-o, e passou de largo.' },
      { v: 33, en: 'But a certain Samaritan, as he traveled, came where he was. When he saw him, he was moved with compassion,', pt: 'Mas um samaritano, que ia de viagem, chegou perto dele e, vendo-o, encheu-se de compaixão;' },
      { v: 34, en: 'came to him, and bound up his wounds, pouring on oil and wine. He set him on his own animal, and brought him to an inn, and took care of him.', pt: 'e aproximando-se, atou-lhe as feridas, deitando nelas azeite e vinho; e pondo-o sobre a sua cavalgadura, levou-o para uma estalagem e cuidou dele.' },
      { v: 35, en: 'On the next day, when he departed, he took out two denarii, and gave them to the host, and said to him, ‘Take care of him. Whatever you spend beyond that, I will repay you when I return.’', pt: 'No dia seguinte tirou dois denários, deu-os ao hospedeiro e disse-lhe: Cuida dele; e tudo o que gastares a mais, eu to pagarei quando voltar.' },
      { v: 36, en: 'Now which of these three do you think seemed to be a neighbor to him who fell among the robbers?”', pt: 'Qual, pois, destes três te parece ter sido o próximo daquele que caiu nas mãos dos salteadores?' },
      { v: 37, en: 'He said, “He who showed mercy on him.” Then Jesus said to him, “Go and do likewise.”', pt: 'Respondeu o doutor da lei: Aquele que usou de misericórdia para com ele. Disse-lhe, pois, Jesus: Vai, e faze tu o mesmo.' },
      { v: 38, en: 'As they went on their way, he entered into a certain village, and a certain woman named Martha received him into her house.', pt: 'Ora, quando iam de caminho, entrou Jesus numa aldeia; e certa mulher, por nome Marta, o recebeu em sua casa.' },
      { v: 39, en: 'She had a sister called Mary, who also sat at Jesus’ feet, and heard his word.', pt: 'Tinha esta uma irmã chamada Maria, a qual, sentando-se aos pés do Senhor, ouvia a sua palavra.' },
      { v: 40, en: 'But Martha was distracted with much serving, and she came up to him, and said, “Lord, don’t you care that my sister left me to serve alone? Ask her therefore to help me.”', pt: 'Marta, porém, andava preocupada com muito serviço; e aproximando-se, disse: Senhor, não se te dá que minha irmã me tenha deixado a servir sozinha? Dize-lhe, pois, que me ajude.' },
      { v: 41, en: 'Jesus answered her, “Martha, Martha, you are anxious and troubled about many things,', pt: 'Respondeu-lhe o Senhor: Marta, Marta, estás ansiosa e perturbada com muitas coisas;' },
      { v: 42, en: 'but one thing is needed. Mary has chosen the good part, which will not be taken away from her.”', pt: 'entretanto poucas são necessárias, ou mesmo uma só; e Maria escolheu a boa parte, a qual não lhe será tirada.' },
    ],
    11: [
      { v: 1, en: 'When he finished praying in a certain place, one of his disciples said to him, “Lord, teach us to pray, just as John also taught his disciples.”', pt: 'Estava Jesus em certo lugar orando e, quando acabou, disse-lhe um dos seus discípulos: Senhor, ensina-nos a orar, como também João ensinou aos seus discípulos.' },
      { v: 2, en: 'He said to them, “When you pray, say, ‘Our Father in heaven, may your name be kept holy. May your Kingdom come. May your will be done on earth, as it is in heaven.', pt: 'Ao que ele lhes disse: Quando orardes, dizei: Pai, santificado seja o teu nome; venha o teu reino;' },
      { v: 3, en: 'Give us day by day our daily bread.', pt: 'dá-nos cada dia o nosso pão cotidiano;' },
      { v: 4, en: 'Forgive us our sins, for we ourselves also forgive everyone who is indebted to us. Bring us not into temptation, but deliver us from the evil one.’”', pt: 'e perdoa-nos os nossos pecados, pois também nós perdoamos a todo aquele que nos deve; e não nos deixes entrar em tentação, [mas livra-nos do mal.]' },
      { v: 5, en: 'He said to them, “Which of you, if you go to a friend at midnight, and tell him, ‘Friend, lend me three loaves of bread,', pt: 'Disse-lhes também: Se um de vós tiver um amigo, e se for procurá-lo à meia-noite e lhe disser: Amigo, empresta-me três pães,' },
      { v: 6, en: 'for a friend of mine has come to me from a journey, and I have nothing to set before him,’', pt: 'pois que um amigo meu, estando em viagem, chegou a minha casa, e não tenho o que lhe oferecer;' },
      { v: 7, en: 'and he from within will answer and say, ‘Don’t bother me. The door is now shut, and my children are with me in bed. I can’t get up and give it to you’?', pt: 'e se ele, de dentro, responder: Não me incomodes; já está a porta fechada, e os meus filhos estão comigo na cama; não posso levantar-me para te atender;' },
      { v: 8, en: 'I tell you, although he will not rise and give it to him because he is his friend, yet because of his persistence, he will get up and give him as many as he needs.', pt: 'digo-vos que, ainda que se levante para lhos dar por ser seu amigo, todavia, por causa da sua importunação, se levantará e lhe dará quantos pães ele precisar.' },
      { v: 9, en: '“I tell you, keep asking, and it will be given you. Keep seeking, and you will find. Keep knocking, and it will be opened to you.', pt: 'Pelo que eu vos digo: Pedi, e dar-se-vos-á; buscai e achareis; batei, e abrir-se-vos-á;' },
      { v: 10, en: 'For everyone who asks receives. He who seeks finds. To him who knocks it will be opened.', pt: 'pois todo o que pede, recebe; e quem busca acha; e ao que bate, abrir-se-lhe-á.' },
      { v: 11, en: '“Which of you fathers, if your son asks for bread, will give him a stone? Or if he asks for a fish, he won’t give him a snake instead of a fish, will he?', pt: 'E qual o pai dentre vós que, se o filho lhe pedir pão, lhe dará uma pedra? Ou, se lhe pedir peixe, lhe dará por peixe uma serpente?' },
      { v: 12, en: 'Or if he asks for an egg, he won’t give him a scorpion, will he?', pt: 'Ou, se pedir um ovo, lhe dará um escorpião?' },
      { v: 13, en: 'If you then, being evil, know how to give good gifts to your children, how much more will your heavenly Father give the Holy Spirit to those who ask him?”', pt: 'Se vós, pois, sendo maus, sabeis dar boas dádivas aos vossos filhos, quanto mais dará o Pai celestial o Espírito Santo àqueles que lho pedirem?' },
      { v: 14, en: 'He was casting out a demon, and it was mute. When the demon had gone out, the mute man spoke; and the multitudes marveled.', pt: 'Estava Jesus expulsando um demônio, que era mudo; e aconteceu que, saindo o demônio, o mudo falou; e as multidões se admiraram.' },
      { v: 15, en: 'But some of them said, “He casts out demons by Beelzebul, the prince of the demons.”', pt: 'Mas alguns deles disseram: É por Belzebu, o príncipe dos demônios, que ele expulsa os demônios.' },
      { v: 16, en: 'Others, testing him, sought from him a sign from heaven.', pt: 'E outros, experimentando-o, lhe pediam um sinal do céu.' },
      { v: 17, en: 'But he, knowing their thoughts, said to them, “Every kingdom divided against itself is brought to desolation. A house divided against itself falls.', pt: 'Ele, porém, conhecendo-lhes os pensamentos, disse-lhes: Todo reino dividido contra si mesmo será assolado, e casa sobre casa cairá.' },
      { v: 18, en: 'If Satan also is divided against himself, how will his kingdom stand? For you say that I cast out demons by Beelzebul.', pt: 'Ora, pois, se Satanás está dividido contra si mesmo, como subsistirá o seu reino? Pois dizeis que eu expulso dos demônios por Belzebu.' },
      { v: 19, en: 'But if I cast out demons by Beelzebul, by whom do your children cast them out? Therefore will they be your judges.', pt: 'E, se eu expulso os demônios por Belzebu, por quem os expulsam os vossos filhos? Por isso eles mesmos serão os vossos juizes.' },
      { v: 20, en: 'But if I by God’s finger cast out demons, then God’s Kingdom has come to you.', pt: 'Mas, se é pelo dedo de Deus que eu expulso os demônios, logo é chegado a vós o reino de Deus.' },
      { v: 21, en: '“When the strong man, fully armed, guards his own dwelling, his goods are safe.', pt: 'Quando o valente guarda, armado, a sua casa, em segurança estão os seus bens;' },
      { v: 22, en: 'But when someone stronger attacks him and overcomes him, he takes from him his whole armor in which he trusted, and divides his plunder.', pt: 'mas, sobrevindo outro mais valente do que ele, e vencendo-o, tira-lhe toda a armadura em que confiava, e reparte os seus despojos.' },
      { v: 23, en: '“He that is not with me is against me. He who doesn’t gather with me scatters.', pt: 'Quem não é comigo, é contra mim; e quem comigo não ajunta, espalha.' },
      { v: 24, en: 'The unclean spirit, when he has gone out of the man, passes through dry places, seeking rest, and finding none, he says, ‘I will turn back to my house from which I came out.’', pt: 'Ora, havendo o espírito imundo saíndo do homem, anda por lugares áridos, buscando repouso; e não o encontrando, diz: Voltarei para minha casa, donde saí.' },
      { v: 25, en: 'When he returns, he finds it swept and put in order.', pt: 'E chegando, acha-a varrida e adornada.' },
      { v: 26, en: 'Then he goes, and takes seven other spirits more evil than himself, and they enter in and dwell there. The last state of that man becomes worse than the first.”', pt: 'Então vai, e leva consigo outros sete espíritos piores do que ele e, entrando, habitam ali; e o último estado desse homem vem a ser pior do que o primeiro.' },
      { v: 27, en: 'It came to pass, as he said these things, a certain woman out of the multitude lifted up her voice, and said to him, “Blessed is the womb that bore you, and the breasts which nursed you!”', pt: 'Ora, enquanto ele dizia estas coisas, certa mulher dentre a multidão levantou a voz e lhe disse: Bem-aventurado o ventre que te trouxe e os peitos em que te amamentaste.' },
      { v: 28, en: 'But he said, “On the contrary, blessed are those who hear the word of God, and keep it.”', pt: 'Mas ele respondeu: Antes bem-aventurados os que ouvem a palavra de Deus, e a observam.' },
      { v: 29, en: 'When the multitudes were gathering together to him, he began to say, “This is an evil generation. It seeks after a sign. No sign will be given to it but the sign of Jonah, the prophet.', pt: 'Como afluíssem as multidões, começou ele a dizer: Geração perversa é esta; ela pede um sinal; e nenhum sinal se lhe dará, senão o de Jonas;' },
      { v: 30, en: 'For even as Jonah became a sign to the Ninevites, so will also the Son of Man be to this generation.', pt: 'porquanto, assim como Jonas foi sinal para os ninivitas, também o Filho do homem o será para esta geração.' },
      { v: 31, en: 'The Queen of the South will rise up in the judgment with the men of this generation, and will condemn them: for she came from the ends of the earth to hear the wisdom of Solomon; and behold, one greater than Solomon is here.', pt: 'A rainha do sul se levantará no juízo com os homens desta geração, e os condenará; porque veio dos confins da terra para ouvir a sabedoria de Salomão; e eis, aqui quem é maior do que Salomão.' },
      { v: 32, en: 'The men of Nineveh will stand up in the judgment with this generation, and will condemn it: for they repented at the preaching of Jonah, and behold, one greater than Jonah is here.', pt: 'Os homens de Nínive se levantarão no juízo com esta geração, e a condenarão; porque se arrependeram com a pregação de Jonas; e eis aqui quem é maior do que Jonas.' },
      { v: 33, en: '“No one, when he has lit a lamp, puts it in a cellar or under a basket, but on a stand, that those who come in may see the light.', pt: 'Ninguém, depois de acender uma candeia, a põe em lugar oculto, nem debaixo do alqueire, mas no velador, para que os que entram vejam a luz.' },
      { v: 34, en: 'The lamp of the body is the eye. Therefore when your eye is good, your whole body is also full of light; but when it is evil, your body also is full of darkness.', pt: 'A candeia do corpo são os olhos. Quando, pois, os teus olhos forem bons, todo o teu corpo será luminoso; mas, quando forem maus, o teu corpo será tenebroso.' },
      { v: 35, en: 'Therefore see whether the light that is in you isn’t darkness.', pt: 'Vê, então, que a luz que há em ti não sejam trevas.' },
      { v: 36, en: 'If therefore your whole body is full of light, having no part dark, it will be wholly full of light, as when the lamp with its bright shining gives you light.”', pt: 'Se, pois, todo o teu corpo estiver iluminado, sem ter parte alguma em trevas, será inteiramente luminoso, como quando a candeia te alumia com o seu resplendor.' },
      { v: 37, en: 'Now as he spoke, a certain Pharisee asked him to dine with him. He went in, and sat at the table.', pt: 'Acabando Jesus de falar, um fariseu o convidou para almoçar com ele; e havendo Jesus entrado, reclinou-se à mesa.' },
      { v: 38, en: 'When the Pharisee saw it, he marveled that he had not first washed himself before dinner.', pt: 'O fariseu admirou-se, vendo que ele não se lavara antes de almoçar.' },
      { v: 39, en: 'The Lord said to him, “Now you Pharisees cleanse the outside of the cup and of the platter, but your inward part is full of extortion and wickedness.', pt: 'Ao que o Senhor lhe disse: Ora vós, os fariseus, limpais o exterior do corpo e do prato; mas o vosso interior do copo e do prato; mas o vosso interior está cheio de rapina e maldade.' },
      { v: 40, en: 'You foolish ones, didn’t he who made the outside make the inside also?', pt: 'Loucos! quem fez o exterior, não fez também o inferior?' },
      { v: 41, en: 'But give for gifts to the needy those things which are within, and behold, all things will be clean to you.', pt: 'Dai, porém, de esmola o que está dentro do copo e do prato, e eis que todas as coisas vos serão limpas.' },
      { v: 42, en: 'But woe to you Pharisees! For you tithe mint and rue and every herb, but you bypass justice and God’s love. You ought to have done these, and not to have left the other undone.', pt: 'Mas ai de vós, fariseus! porque dais o dízimo da hortelã, e da arruda, e de toda hortaliça, e desprezais a justiça e o amor de Deus. Ora, estas coisas importava fazer, sem deixar aquelas.' },
      { v: 43, en: 'Woe to you Pharisees! For you love the best seats in the synagogues, and the greetings in the marketplaces.', pt: 'Ai de vós, fariseus! porque gostais dos primeiros assentos nas sinagogas, e das saudações nas praças.' },
      { v: 44, en: 'Woe to you, scribes and Pharisees, hypocrites! For you are like hidden graves, and the men who walk over them don’t know it.”', pt: 'Ai de vós! porque sois como as sepulturas que não aparecem, sobre as quais andam os homens sem o saberem.' },
      { v: 45, en: 'One of the lawyers answered him, “Teacher, in saying this you insult us also.”', pt: 'Disse-lhe, então, um dos doutores da lei: Mestre, quando dizes isso, também nos afrontas a nós.' },
      { v: 46, en: 'He said, “Woe to you lawyers also! For you load men with burdens that are difficult to carry, and you yourselves won’t even lift one finger to help carry those burdens.', pt: 'Ele, porém, respondeu: Ai de vós também, doutores da lei! porque carregais os homens com fardos difíceis de suportar, e vós mesmos nem ainda com um dos vossos dedos tocais nesses fardos.' },
      { v: 47, en: 'Woe to you! For you build the tombs of the prophets, and your fathers killed them.', pt: 'Ai de vós! porque edificais os túmulos dos profetas, e vossos pais os mataram.' },
      { v: 48, en: 'So you testify and consent to the works of your fathers. For they killed them, and you build their tombs.', pt: 'Assim sois testemunhas e aprovais as obras de vossos pais; porquanto eles os mataram, e vós lhes edificais os túmulos.' },
      { v: 49, en: 'Therefore also the wisdom of God said, ‘I will send to them prophets and apostles; and some of them they will kill and persecute,', pt: 'Por isso diz também a sabedoria de Deus: Profetas e apóstolos lhes mandarei; e eles matarão uns, e perseguirão outros;' },
      { v: 50, en: 'that the blood of all the prophets, which was shed from the foundation of the world, may be required of this generation;', pt: 'para que a esta geração se peçam contas do sangue de todos os profetas que, desde a fundação do mundo, foi derramado;' },
      { v: 51, en: 'from the blood of Abel to the blood of Zachariah, who perished between the altar and the sanctuary.’ Yes, I tell you, it will be required of this generation.', pt: 'desde o sangue de Abel, até o sangue de Zacarias, que foi morto entre o altar e o santuário; sim, eu vos digo, a esta geração se pedirão contas.' },
      { v: 52, en: 'Woe to you lawyers! For you took away the key of knowledge. You didn’t enter in yourselves, and those who were entering in, you hindered.”', pt: 'Ai de vós, doutores da lei! porque tirastes a chave da ciência; vós mesmos não entrastes, e impedistes aos que entravam.' },
      { v: 53, en: 'As he said these things to them, the scribes and the Pharisees began to be terribly angry, and to draw many things out of him;', pt: 'Ao sair ele dali, começaram os escribas e os fariseus a apertá-lo fortemente, e a interrogá-lo acerca de muitas coisas,' },
      { v: 54, en: 'lying in wait for him, and seeking to catch him in something he might say, that they might accuse him.', pt: 'armando-lhe ciladas, a fim de o apanharem em alguma coisa que dissesse.' },
    ],
    12: [
      { v: 1, en: 'Meanwhile, when a multitude of many thousands had gathered together, so much so that they trampled on each other, he began to tell his disciples first of all, “Beware of the yeast of the Pharisees, which is hypocrisy.', pt: 'Ajuntando-se entretanto muitos milhares de pessoas, de sorte que se atropelavam uns aos outros, começou Jesus a dizer primeiro aos seus discípulos: Acautelai-vos do fermento dos fariseus, que é a hipocrisia.' },
      { v: 2, en: 'But there is nothing covered up, that will not be revealed, nor hidden, that will not be known.', pt: 'Mas nada há encoberto, que não haja de ser descoberto; nem oculto, que não haja de ser conhecido.' },
      { v: 3, en: 'Therefore whatever you have said in the darkness will be heard in the light. What you have spoken in the ear in the inner rooms will be proclaimed on the housetops.', pt: 'Porquanto tudo o que em trevas dissestes, à luz será ouvido; e o que falaste ao ouvido no gabinete, dos eirados será apregoado.' },
      { v: 4, en: '“I tell you, my friends, don’t be afraid of those who kill the body, and after that have no more that they can do.', pt: 'Digo-vos, amigos meus: Não temais os que matam o corpo, e depois disso nada mais podem fazer.' },
      { v: 5, en: 'But I will warn you whom you should fear. Fear him, who after he has killed, has power to cast into Gehenna. Yes, I tell you, fear him.', pt: 'Mas eu vos mostrarei a quem é que deveis temer; temei aquele que, depois de matar, tem poder para lançar no inferno; sim, digo, a esse temei.' },
      { v: 6, en: '“Aren’t five sparrows sold for two assaria coins ? Not one of them is forgotten by God.', pt: 'Não se vendem cinco passarinhos por dois asses? E nenhum deles está esquecido diante de Deus.' },
      { v: 7, en: 'But the very hairs of your head are all counted. Therefore don’t be afraid. You are of more value than many sparrows.', pt: 'Mas até os cabelos da vossa cabeça estão todos contados. Não temais, pois mais valeis vós do que muitos passarinhos.' },
      { v: 8, en: '“I tell you, everyone who confesses me before men, him will the Son of Man also confess before the angels of God;', pt: 'E digo-vos que todo aquele que me confessar diante dos homens, também o Filho do homem o confessará diante dos anjos de Deus;' },
      { v: 9, en: 'but he who denies me in the presence of men will be denied in the presence of the angels of God.', pt: 'mas quem me negar diante dos homens, será negado diante dos anjos de Deus.' },
      { v: 10, en: 'Everyone who speaks a word against the Son of Man will be forgiven, but those who blaspheme against the Holy Spirit will not be forgiven.', pt: 'E a todo aquele que proferir uma palavra contra o Filho do homem, isso lhe será perdoado; mas ao que blasfemar contra o Espírito Santo, não lhe será perdoado.' },
      { v: 11, en: 'When they bring you before the synagogues, the rulers, and the authorities, don’t be anxious how or what you will answer, or what you will say;', pt: 'Quando, pois, vos levarem às sinagogas, aos magistrados e às autoridades, não estejais solícitos de como ou do que haveis de responder, nem do que haveis de dizer.' },
      { v: 12, en: 'for the Holy Spirit will teach you in that same hour what you must say.”', pt: 'Porque o Espírito Santo vos ensinará na mesma hora o que deveis dizer.' },
      { v: 13, en: 'One of the multitude said to him, “Teacher, tell my brother to divide the inheritance with me.”', pt: 'Disse-lhe alguém dentre a multidão: Mestre, dize a meu irmão que reparte comigo a herança.' },
      { v: 14, en: 'But he said to him, “Man, who made me a judge or an arbitrator over you?”', pt: 'Mas ele lhe respondeu: Homem, quem me constituiu a mim juiz ou repartidor entre vós?' },
      { v: 15, en: 'He said to them, “Beware! Keep yourselves from covetousness, for a man’s life doesn’t consist of the abundance of the things which he possesses.”', pt: 'E disse ao povo: Acautelai-vos e guardai-vos de toda espécie de cobiça; porque a vida do homem não consiste na abundância das coisas que possui.' },
      { v: 16, en: 'He spoke a parable to them, saying, “The ground of a certain rich man produced abundantly.', pt: 'Propôs-lhes então uma parábola, dizendo: O campo de um homem rico produzira com abundância;' },
      { v: 17, en: 'He reasoned within himself, saying, ‘What will I do, because I don’t have room to store my crops?’', pt: 'e ele arrazoava consigo, dizendo: Que farei? Pois não tenho onde recolher os meus frutos.' },
      { v: 18, en: 'He said, ‘This is what I will do. I will pull down my barns, and build bigger ones, and there I will store all my grain and my goods.', pt: 'Disse então: Farei isto: derribarei os meus celeiros e edificarei outros maiores, e ali recolherei todos os meus cereais e os meus bens;' },
      { v: 19, en: 'I will tell my soul, “Soul, you have many goods laid up for many years. Take your ease, eat, drink, be merry.”’', pt: 'e direi à minha alma: Alma, tens em depósito muitos bens para muitos anos; descansa, come, bebe, regala-te.' },
      { v: 20, en: '“But God said to him, ‘You foolish one, tonight your soul is required of you. The things which you have prepared—whose will they be?’', pt: 'Mas Deus lhe disse: Insensato, esta noite te pedirão a tua alma; e o que tens preparado, para quem será?' },
      { v: 21, en: 'So is he who lays up treasure for himself, and is not rich toward God.”', pt: 'Assim é aquele que para si ajunta tesouros, e não é rico para com Deus.' },
      { v: 22, en: 'He said to his disciples, “Therefore I tell you, don’t be anxious for your life, what you will eat, nor yet for your body, what you will wear.', pt: 'E disse aos seus discípulos: Por isso vos digo: Não estejais ansiosos quanto à vossa vida, pelo que haveis de comer, nem quanto ao corpo, pelo que haveis de vestir.' },
      { v: 23, en: 'Life is more than food, and the body is more than clothing.', pt: 'Pois a vida é mais do que o alimento, e o corpo mais do que o vestuário.' },
      { v: 24, en: 'Consider the ravens: they don’t sow, they don’t reap, they have no warehouse or barn, and God feeds them. How much more valuable are you than birds!', pt: 'Considerai os corvos, que não semeiam nem ceifam; não têm despensa nem celeiro; contudo, Deus os alimenta. Quanto mais não valeis vós do que as aves!' },
      { v: 25, en: 'Which of you by being anxious can add a cubit to his height?', pt: 'Ora, qual de vós, por mais ansioso que esteja, pode acrescentar um côvado à sua estatura?' },
      { v: 26, en: 'If then you aren’t able to do even the least things, why are you anxious about the rest?', pt: 'Porquanto, se não podeis fazer nem as coisas mínimas, por que estais ansiosos pelas outras?' },
      { v: 27, en: 'Consider the lilies, how they grow. They don’t toil, neither do they spin; yet I tell you, even Solomon in all his glory was not arrayed like one of these.', pt: 'Considerai os lírios, como crescem; não trabalham, nem fiam; contudo vos digo que nem mesmo Salomão, em toda a sua glória, se vestiu como um deles.' },
      { v: 28, en: 'But if this is how God clothes the grass in the field, which today exists, and tomorrow is cast into the oven, how much more will he clothe you, O you of little faith?', pt: 'Se, pois, Deus assim veste a erva que hoje está no campo e amanhã é lançada no forno, quanto mais vós, homens de pouca fé?' },
      { v: 29, en: 'Don’t seek what you will eat or what you will drink; neither be anxious.', pt: 'Não procureis, pois, o que haveis de comer, ou o que haveis de beber, e não andeis preocupados.' },
      { v: 30, en: 'For the nations of the world seek after all of these things, but your Father knows that you need these things.', pt: 'Porque a todas estas coisas os povos do mundo procuram; mas vosso Pai sabe que precisais delas.' },
      { v: 31, en: 'But seek God’s Kingdom, and all these things will be added to you.', pt: 'Buscai antes o seu reino, e estas coisas vos serão acrescentadas.' },
      { v: 32, en: 'Don’t be afraid, little flock, for it is your Father’s good pleasure to give you the Kingdom.', pt: 'Não temas, ó pequeno rebanho! porque a vosso Pai agradou dar-vos o reino.' },
      { v: 33, en: 'Sell that which you have, and give gifts to the needy. Make for yourselves purses which don’t grow old, a treasure in the heavens that doesn’t fail, where no thief approaches, neither moth destroys.', pt: 'Vendei o que possuís, e dai esmolas. Fazei para vós bolsas que não envelheçam; tesouro nos céus que jamais acabe, aonde não chega ladrão e a traça não rói.' },
      { v: 34, en: 'For where your treasure is, there will your heart be also.', pt: 'Porque, onde estiver o vosso tesouro, aí estará também o vosso coração.' },
      { v: 35, en: '“Let your waist be dressed and your lamps burning.', pt: 'Estejam cingidos os vossos lombos e acesas as vossas candeias;' },
      { v: 36, en: 'Be like men watching for their lord, when he returns from the marriage feast; that, when he comes and knocks, they may immediately open to him.', pt: 'e sede semelhantes a homens que esperam o seu senhor, quando houver de voltar das bodas, para que, quando vier e bater, logo possam abrir-lhe.' },
      { v: 37, en: 'Blessed are those servants, whom the lord will find watching when he comes. Most certainly I tell you, that he will dress himself, and make them recline, and will come and serve them.', pt: 'Bem-aventurados aqueles servos, aos quais o senhor, quando vier, achar vigiando! Em verdade vos digo que se cingirá, e os fará reclinar-se à mesa e, chegando-se, os servirá.' },
      { v: 38, en: 'They will be blessed if he comes in the second or third watch, and finds them so.', pt: 'Quer venha na segunda vigília, quer na terceira, bem-aventurados serão eles, se assim os achar.' },
      { v: 39, en: 'But know this, that if the master of the house had known in what hour the thief was coming, he would have watched, and not allowed his house to be broken into.', pt: 'Sabei, porém, isto: se o dono da casa soubesse a que hora havia de vir o ladrão, vigiaria e não deixaria minar a sua casa.' },
      { v: 40, en: 'Therefore be ready also, for the Son of Man is coming in an hour that you don’t expect him.”', pt: 'Estai vós também apercebidos; porque, numa hora em que não penseis, virá o Filho do homem.' },
      { v: 41, en: 'Peter said to him, “Lord, are you telling this parable to us, or to everybody?”', pt: 'Então Pedro perguntou: Senhor, dizes essa parábola a nós, ou também a todos?' },
      { v: 42, en: 'The Lord said, “Who then is the faithful and wise steward, whom his lord will set over his household, to give them their portion of food at the right times?', pt: 'Respondeu o Senhor: Qual é, pois, o mordomo fiel e prudente, que o Senhor porá sobre os seus servos, para lhes dar a tempo a ração?' },
      { v: 43, en: 'Blessed is that servant whom his lord will find doing so when he comes.', pt: 'Bem-aventurado aquele servo a quem o seu senhor, quando vier, achar fazendo assim.' },
      { v: 44, en: 'Truly I tell you, that he will set him over all that he has.', pt: 'Em verdade vos digo que o porá sobre todos os seus bens.' },
      { v: 45, en: 'But if that servant says in his heart, ‘My lord delays his coming,’ and begins to beat the menservants and the maidservants, and to eat and drink, and to be drunken,', pt: 'Mas, se aquele servo disser em teu coração: O meu senhor tarda em vir; e começar a espancar os criados e as criadas, e a comer, a beber e a embriagar-se,' },
      { v: 46, en: 'then the lord of that servant will come in a day when he isn’t expecting him, and in an hour that he doesn’t know, and will cut him in two, and place his portion with the unfaithful.', pt: 'virá o senhor desse servo num dia em que não o espera, e numa hora de que não sabe, e cortá-lo-á pelo meio, e lhe dará a sua parte com os infiéis.' },
      { v: 47, en: 'That servant, who knew his lord’s will, and didn’t prepare, nor do what he wanted, will be beaten with many stripes,', pt: 'O servo que soube a vontade do seu senhor, e não se aprontou, nem fez conforme a sua vontade, será castigado com muitos açoites;' },
      { v: 48, en: 'but he who didn’t know, and did things worthy of stripes, will be beaten with few stripes. To whomever much is given, of him will much be required; and to whom much was entrusted, of him more will be asked.', pt: 'mas o que não a soube, e fez coisas que mereciam castigo, com poucos açoites será castigado. Daquele a quem muito é dado, muito se lhe requererá; e a quem muito é confiado, mais ainda se lhe pedirá.' },
      { v: 49, en: '“I came to throw fire on the earth. I wish it were already kindled.', pt: 'Vim lançar fogo à terra; e que mais quero, se já está aceso?' },
      { v: 50, en: 'But I have a baptism to be baptized with, and how distressed I am until it is accomplished!', pt: 'Há um batismo em que hei de ser batizado; e como me angustio até que venha a cumprir-se!' },
      { v: 51, en: 'Do you think that I have come to give peace in the earth? I tell you, no, but rather division.', pt: 'Cuidais vós que vim trazer paz à terra? Não, eu vos digo, mas antes dissensão:' },
      { v: 52, en: 'For from now on, there will be five in one house divided, three against two, and two against three.', pt: 'pois daqui em diante estarão cinco pessoas numa casa divididas, três contra duas, e duas contra três;' },
      { v: 53, en: 'They will be divided, father against son, and son against father; mother against daughter, and daughter against her mother; mother-in-law against her daughter-in-law, and daughter-in-law against her mother-in-law.”', pt: 'estarão divididos: pai contra filho, e filho contra pai; mãe contra filha, e filha contra mãe; sogra contra nora, e nora contra sogra.' },
      { v: 54, en: 'He said to the multitudes also, “When you see a cloud rising from the west, immediately you say, ‘A shower is coming,’ and so it happens.', pt: 'Dizia também às multidões: Quando vedes subir uma nuvem do ocidente, logo dizeis: Lá vem chuva; e assim sucede;' },
      { v: 55, en: 'When a south wind blows, you say, ‘There will be a scorching heat,’ and it happens.', pt: 'e quando vedes soprar o vento sul dizeis; Haverá calor; e assim sucede.' },
      { v: 56, en: 'You hypocrites! You know how to interpret the appearance of the earth and the sky, but how is it that you don’t interpret this time?', pt: 'Hipócritas, sabeis discernir a face da terra e do céu; como não sabeis então discernir este tempo?' },
      { v: 57, en: 'Why don’t you judge for yourselves what is right?', pt: 'E por que não julgais também por vós mesmos o que é justo?' },
      { v: 58, en: 'For when you are going with your adversary before the magistrate, try diligently on the way to be released from him, lest perhaps he drag you to the judge, and the judge deliver you to the officer, and the officer throw you into prison.', pt: 'Quando, pois, vais com o teu adversário ao magistrado, procura fazer as pazes com ele no caminho; para que não suceda que ele te arraste ao juiz, e o juiz te entregue ao meirinho, e o meirinho te lance na prisão' },
      { v: 59, en: 'I tell you, you will by no means get out of there, until you have paid the very last penny. ”', pt: 'Digo-te que não sairás dali enquanto não pagares o derradeiro lepto.' },
    ],
    13: [
      { v: 1, en: 'Now there were some present at the same time who told him about the Galileans, whose blood Pilate had mixed with their sacrifices.', pt: 'Ora, naquele mesmo tempo estavam presentes alguns que lhe falavam dos galileus cujo sangue Pilatos misturara com os sacrifícios deles.' },
      { v: 2, en: 'Jesus answered them, “Do you think that these Galileans were worse sinners than all the other Galileans, because they suffered such things?', pt: 'Respondeu-lhes Jesus: Pensais vós que esses foram maiores pecadores do que todos os galileus, por terem padecido tais coisas?' },
      { v: 3, en: 'I tell you, no, but unless you repent, you will all perish in the same way.', pt: 'Não, eu vos digo; antes, se não vos arrependerdes, todos de igual modo perecereis.' },
      { v: 4, en: 'Or those eighteen, on whom the tower in Siloam fell, and killed them; do you think that they were worse offenders than all the men who dwell in Jerusalem?', pt: 'Ou pensais que aqueles dezoito, sobre os quais caiu a torre de Siloé e os matou, foram mais culpados do que todos os outros habitantes de Jerusalém?' },
      { v: 5, en: 'I tell you, no, but, unless you repent, you will all perish in the same way.”', pt: 'Não, eu vos digo; antes, se não vos arrependerdes, todos de igual modo perecereis.' },
      { v: 6, en: 'He spoke this parable. “A certain man had a fig tree planted in his vineyard, and he came seeking fruit on it, and found none.', pt: 'E passou a narrar esta parábola: Certo homem tinha uma figueira plantada na sua vinha; e indo procurar fruto nela, e não o achou.' },
      { v: 7, en: 'He said to the vine dresser, ‘Behold, these three years I have come looking for fruit on this fig tree, and found none. Cut it down. Why does it waste the soil?’', pt: 'Disse então ao viticultor: Eis que há três anos venho procurar fruto nesta figueira, e não o acho; corta-a; para que ocupa ela ainda a terra inutilmente?' },
      { v: 8, en: 'He answered, ‘Lord, leave it alone this year also, until I dig around it, and fertilize it.', pt: 'Respondeu-lhe ele: Senhor, deixa-a este ano ainda, até que eu cave em derredor, e lhe deite estrume;' },
      { v: 9, en: 'If it bears fruit, fine; but if not, after that, you can cut it down.’”', pt: 'e se no futuro der fruto, bem; mas, se não, cortá-la-ás.' },
      { v: 10, en: 'He was teaching in one of the synagogues on the Sabbath day.', pt: 'Jesus estava ensinando numa das sinagogas no sábado.' },
      { v: 11, en: 'Behold, there was a woman who had a spirit of infirmity eighteen years, and she was bent over, and could in no way straighten herself up.', pt: 'E estava ali uma mulher que tinha um espírito de enfermidade havia já dezoito anos; e andava encurvada, e não podia de modo algum endireitar-se.' },
      { v: 12, en: 'When Jesus saw her, he called her, and said to her, “Woman, you are freed from your infirmity.”', pt: 'Vendo-a Jesus, chamou-a, e disse-lhe: Mulher, estás livre da tua enfermidade;' },
      { v: 13, en: 'He laid his hands on her, and immediately she stood up straight, and glorified God.', pt: 'e impôs-lhe as mãos e imediatamente ela se endireitou, e glorificava a Deus.' },
      { v: 14, en: 'The ruler of the synagogue, being indignant because Jesus had healed on the Sabbath, said to the multitude, “There are six days in which men ought to work. Therefore come on those days and be healed, and not on the Sabbath day!”', pt: 'Então o chefe da sinagoga, indignado porque Jesus curara no sábado, tomando a palavra disse à multidão: Seis dias há em que se deve trabalhar; vinde, pois, neles para serdes curados, e não no dia de sábado.' },
      { v: 15, en: 'Therefore the Lord answered him, “You hypocrites! Doesn’t each one of you free his ox or his donkey from the stall on the Sabbath, and lead him away to water?', pt: 'Respondeu-lhe, porém, o Senhor: Hipócritas, no sábado não desprende da manjedoura cada um de vós o seu boi, ou jumento, para o levar a beber?' },
      { v: 16, en: 'Ought not this woman, being a daughter of Abraham, whom Satan had bound eighteen long years, be freed from this bondage on the Sabbath day?”', pt: 'E não devia ser solta desta prisão, no dia de sábado, esta que é filha de Abraão, a qual há dezoito anos Satanás tinha presa?' },
      { v: 17, en: 'As he said these things, all his adversaries were disappointed, and all the multitude rejoiced for all the glorious things that were done by him.', pt: 'E dizendo ele essas coisas, todos os seus adversário ficavam envergonhados; e todo o povo se alegrava por todas as coisas gloriosas que eram feitas por ele.' },
      { v: 18, en: 'He said, “What is God’s Kingdom like? To what shall I compare it?', pt: 'Ele, pois, dizia: A que é semelhante o reino de Deus, e a que o compararei?' },
      { v: 19, en: 'It is like a grain of mustard seed, which a man took, and put in his own garden. It grew, and became a large tree, and the birds of the sky live in its branches.”', pt: 'É semelhante a um grão de mostarda que um homem tomou e lançou na sua horta; cresceu, e fez-se árvore, e em seus ramos se aninharam as aves do céu.' },
      { v: 20, en: 'Again he said, “To what shall I compare God’s Kingdom?', pt: 'E disse outra vez: A que compararei o reino de Deus?' },
      { v: 21, en: 'It is like yeast, which a woman took and hid in three measures of flour, until it was all leavened.”', pt: 'É semelhante ao fermento que uma mulher tomou e misturou com três medidas de farinha, até ficar toda ela levedada.' },
      { v: 22, en: 'He went on his way through cities and villages, teaching, and traveling on to Jerusalem.', pt: 'Assim percorria Jesus as cidades e as aldeias, ensinando, e caminhando para Jerusalém.' },
      { v: 23, en: 'One said to him, “Lord, are they few who are saved?” He said to them,', pt: 'E alguém lhe perguntou: Senhor, são poucos os que se salvam? Ao que ele lhes respondeu:' },
      { v: 24, en: '“Strive to enter in by the narrow door, for many, I tell you, will seek to enter in, and will not be able.', pt: 'Porfiai por entrar pela porta estreita; porque eu vos digo que muitos procurarão entrar, e não poderão.' },
      { v: 25, en: 'When once the master of the house has risen up, and has shut the door, and you begin to stand outside, and to knock at the door, saying, ‘Lord, Lord, open to us!’ then he will answer and tell you, ‘I don’t know you or where you come from.’', pt: 'Quando o dono da casa se tiver levantado e cerrado a porta, e vós começardes, de fora, a bater à porta, dizendo: Senhor, abre-nos; e ele vos responder: Não sei donde vós sois;' },
      { v: 26, en: 'Then you will begin to say, ‘We ate and drank in your presence, and you taught in our streets.’', pt: 'então começareis a dizer: Comemos e bebemos na tua presença, e tu ensinaste nas nossas ruas;' },
      { v: 27, en: 'He will say, ‘I tell you, I don’t know where you come from. Depart from me, all you workers of iniquity.’', pt: 'e ele vos responderá: Não sei donde sois; apartaivos de mim, vós todos os que praticais a iniqüidade.' },
      { v: 28, en: 'There will be weeping and gnashing of teeth, when you see Abraham, Isaac, Jacob, and all the prophets, in God’s Kingdom, and yourselves being thrown outside.', pt: 'Ali haverá choro e ranger de dentes quando virdes Abraão, Isaque, Jacó e todos os profetas no reino de Deus, e vós lançados fora.' },
      { v: 29, en: 'They will come from the east, west, north, and south, and will sit down in God’s Kingdom.', pt: 'Muitos virão do oriente e do ocidente, do norte e do sul, e reclinar-se-ão à mesa no reino de Deus.' },
      { v: 30, en: 'Behold, there are some who are last who will be first, and there are some who are first who will be last.”', pt: 'Pois há últimos que serão primeiros, e primeiros que serão últimos.' },
      { v: 31, en: 'On that same day, some Pharisees came, saying to him, “Get out of here, and go away, for Herod wants to kill you.”', pt: 'Naquela mesma hora chegaram alguns fariseus que lhe disseram: Sai, e retira-te daqui, porque Herodes quer matar-te.' },
      { v: 32, en: 'He said to them, “Go and tell that fox, ‘Behold, I cast out demons and perform cures today and tomorrow, and the third day I complete my mission.', pt: 'Respondeu-lhes Jesus: Ide e dizei a essa raposa: Eis que vou expulsando demônios e fazendo curas, hoje e amanhã, e no terceiro dia serei consumado.' },
      { v: 33, en: 'Nevertheless I must go on my way today and tomorrow and the next day, for it can’t be that a prophet would perish outside of Jerusalem.’', pt: 'Importa, contudo, caminhar hoje, amanhã, e no dia seguinte; porque não convém que morra um profeta fora de Jerusalém.' },
      { v: 34, en: '“Jerusalem, Jerusalem, that kills the prophets, and stones those who are sent to her! How often I wanted to gather your children together, like a hen gathers her own brood under her wings, and you refused!', pt: 'Jerusalém, Jerusalém, que matas os profetas, e apedrejas os que a ti são enviados! Quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta a sua ninhada debaixo das asas, e não quiseste!' },
      { v: 35, en: 'Behold, your house is left to you desolate. I tell you, you will not see me, until you say, ‘Blessed is he who comes in the name of the Lord!’”', pt: 'Eis aí, abandonada vos é a vossa casa. E eu vos digo que não me vereis até que venha o tempo em que digais: Bendito aquele que vem em nome do Senhor.' },
    ],
    14: [
      { v: 1, en: 'When he went into the house of one of the rulers of the Pharisees on a Sabbath to eat bread, they were watching him.', pt: 'Tendo Jesus entrado, num sábado, em casa de um dos chefes dos fariseus para comer pão, eles o estavam observando.' },
      { v: 2, en: 'Behold, a certain man who had dropsy was in front of him.', pt: 'Achava-se ali diante dele certo homem hidrópico.' },
      { v: 3, en: 'Jesus, answering, spoke to the lawyers and Pharisees, saying, “Is it lawful to heal on the Sabbath?”', pt: 'E Jesus, tomando a palavra, falou aos doutores da lei e aos fariseus, e perguntou: É lícito curar no sábado, ou não?' },
      { v: 4, en: 'But they were silent. He took him, and healed him, and let him go.', pt: 'Eles, porém, ficaram calados. E Jesus, pegando no homem, o curou, e o despediu.' },
      { v: 5, en: 'He answered them, “Which of you, if your son or an ox fell into a well, wouldn’t immediately pull him out on a Sabbath day?”', pt: 'Então lhes perguntou: Qual de vós, se lhe cair num poço um filho, ou um boi, não o tirará logo, mesmo em dia de sábado?' },
      { v: 6, en: 'They couldn’t answer him regarding these things.', pt: 'A isto nada puderam responder.' },
      { v: 7, en: 'He spoke a parable to those who were invited, when he noticed how they chose the best seats, and said to them,', pt: 'Ao notar como os convidados escolhiam os primeiros lugares, propôs-lhes esta parábola:' },
      { v: 8, en: '“When you are invited by anyone to a marriage feast, don’t sit in the best seat, since perhaps someone more honorable than you might be invited by him,', pt: 'Quando por alguém fores convidado às bodas, não te reclines no primeiro lugar; não aconteça que esteja convidado outro mais digno do que tu;' },
      { v: 9, en: 'and he who invited both of you would come and tell you, ‘Make room for this person.’ Then you would begin, with shame, to take the lowest place.', pt: 'e vindo o que te convidou a ti e a ele, te diga: Dá o lugar a este; e então, com vergonha, tenhas de tomar o último lugar.' },
      { v: 10, en: 'But when you are invited, go and sit in the lowest place, so that when he who invited you comes, he may tell you, ‘Friend, move up higher.’ Then you will be honored in the presence of all who sit at the table with you.', pt: 'Mas, quando fores convidado, vai e reclina-te no último lugar, para que, quando vier o que te convidou, te diga: Amigo, sobe mais para cima. Então terás honra diante de todos os que estiverem contigo à mesa.' },
      { v: 11, en: 'For everyone who exalts himself will be humbled, and whoever humbles himself will be exalted.”', pt: 'Porque todo o que a si mesmo se exaltar será humilhado, e aquele que a si mesmo se humilhar será exaltado.' },
      { v: 12, en: 'He also said to the one who had invited him, “When you make a dinner or a supper, don’t call your friends, nor your brothers, nor your kinsmen, nor rich neighbors, or perhaps they might also return the favor, and pay you back.', pt: 'Disse também ao que o havia convidado: Quando deres um jantar, ou uma ceia, não convides teus amigos, nem teus irmãos, nem teus parentes, nem os vizinhos ricos, para que não suceda que também eles te tornem a convidar, e te seja isso retribuído.' },
      { v: 13, en: 'But when you make a feast, ask the poor, the maimed, the lame, or the blind;', pt: 'Mas quando deres um banquete, convida os pobres, os aleijados, os mancos e os cegos;' },
      { v: 14, en: 'and you will be blessed, because they don’t have the resources to repay you. For you will be repaid in the resurrection of the righteous.”', pt: 'e serás bem-aventurado; porque eles não têm com que te retribuir; pois retribuído te será na ressurreição dos justos.' },
      { v: 15, en: 'When one of those who sat at the table with him heard these things, he said to him, “Blessed is he who will feast in God’s Kingdom!”', pt: 'Ao ouvir isso um dos que estavam com ele à mesa, disse-lhe: Bem-aventurado aquele que comer pão no reino de Deus.' },
      { v: 16, en: 'But he said to him, “A certain man made a great supper, and he invited many people.', pt: 'Jesus, porém, lhe disse: Certo homem dava uma grande ceia, e convidou a muitos.' },
      { v: 17, en: 'He sent out his servant at supper time to tell those who were invited, ‘Come, for everything is ready now.’', pt: 'E à hora da ceia mandou o seu servo dizer aos convidados: vinde, porque tudo já está preparado.' },
      { v: 18, en: 'They all as one began to make excuses. “The first said to him, ‘I have bought a field, and I must go and see it. Please have me excused.’', pt: 'Mas todos à uma começaram a escusar-se. Disse-lhe o primeiro: Comprei um campo, e preciso ir vê-lo; rogo-te que me dês por escusado.' },
      { v: 19, en: '“Another said, ‘I have bought five yoke of oxen, and I must go try them out. Please have me excused.’', pt: 'Outro disse: Comprei cinco juntas de bois, e vou experimentá-los; rogo-te que me dês por escusado.' },
      { v: 20, en: '“Another said, ‘I have married a wife, and therefore I can’t come.’', pt: 'Ainda outro disse: Casei-me e portanto não posso ir.' },
      { v: 21, en: '“That servant came, and told his lord these things. Then the master of the house, being angry, said to his servant, ‘Go out quickly into the streets and lanes of the city, and bring in the poor, maimed, blind, and lame.’', pt: 'Voltou o servo e contou tudo isto a seu senhor: Então o dono da casa, indignado, disse a seu servo: Sai depressa para as ruas e becos da cidade e traze aqui os pobres, os aleijados, os cegos e os coxos.' },
      { v: 22, en: '“The servant said, ‘Lord, it is done as you commanded, and there is still room.’', pt: 'Depois disse o servo: Senhor, feito está como o ordenaste, e ainda há lugar.' },
      { v: 23, en: '“The lord said to the servant, ‘Go out into the highways and hedges, and compel them to come in, that my house may be filled.', pt: 'Respondeu o senhor ao servo: Sai pelos caminhos e valados, e obriga-os a entrar, para que a minha casa se encha.' },
      { v: 24, en: 'For I tell you that none of those men who were invited will taste of my supper.’”', pt: 'Pois eu vos digo que nenhum daqueles homens que foram convidados provará a minha ceia.' },
      { v: 25, en: 'Now great multitudes were going with him. He turned and said to them,', pt: 'Ora, iam com ele grandes multidões; e, voltando-se, disse-lhes:' },
      { v: 26, en: '“If anyone comes to me, and doesn’t disregard his own father, mother, wife, children, brothers, and sisters, yes, and his own life also, he can’t be my disciple.', pt: 'Se alguém vier a mim, e não aborrecer a pai e mãe, a mulher e filhos, a irmãos e irmãs, e ainda também à própria vida, não pode ser meu discípulo.' },
      { v: 27, en: 'Whoever doesn’t bear his own cross, and come after me, can’t be my disciple.', pt: 'Quem não leva a sua cruz e não me segue, não pode ser meu discípulo.' },
      { v: 28, en: 'For which of you, desiring to build a tower, doesn’t first sit down and count the cost, to see if he has enough to complete it?', pt: 'Pois qual de vós, querendo edificar uma torre, não se senta primeiro a calcular as despesas, para ver se tem com que a acabar?' },
      { v: 29, en: 'Or perhaps, when he has laid a foundation, and is not able to finish, everyone who sees begins to mock him,', pt: 'Para não acontecer que, depois de haver posto os alicerces, e não a podendo acabar, todos os que a virem comecem a zombar dele,' },
      { v: 30, en: 'saying, ‘This man began to build, and wasn’t able to finish.’', pt: 'dizendo: Este homem começou a edificar e não pode acabar.' },
      { v: 31, en: 'Or what king, as he goes to encounter another king in war, will not sit down first and consider whether he is able with ten thousand to meet him who comes against him with twenty thousand?', pt: 'Ou qual é o rei que, indo entrar em guerra contra outro rei, não se senta primeiro a consultar se com dez mil pode sair ao encontro do que vem contra ele com vinte mil?' },
      { v: 32, en: 'Or else, while the other is yet a great way off, he sends an envoy, and asks for conditions of peace.', pt: 'No caso contrário, enquanto o outro ainda está longe, manda embaixadores, e pede condições de paz.' },
      { v: 33, en: 'So therefore whoever of you who doesn’t renounce all that he has, he can’t be my disciple.', pt: 'Assim, pois, todo aquele dentre vós que não renuncia a tudo quanto possui, não pode ser meu discípulo.' },
      { v: 34, en: 'Salt is good, but if the salt becomes flat and tasteless, with what do you season it?', pt: 'Bom é o sal; mas se o sal se tornar insípido, com que se há de restaurar-lhe o sabor?' },
      { v: 35, en: 'It is fit neither for the soil nor for the manure pile. It is thrown out. He who has ears to hear, let him hear.”', pt: 'Não presta nem para terra, nem para adubo; lançam-no fora. Quem tem ouvidos para ouvir, ouça.' },
    ],
    15: [
      { v: 1, en: 'Now all the tax collectors and sinners were coming close to him to hear him.', pt: 'Ora, chegavam-se a ele todos os publicanos e pecadores para o ouvir.' },
      { v: 2, en: 'The Pharisees and the scribes murmured, saying, “This man welcomes sinners, and eats with them.”', pt: 'E os fariseus e os escribas murmuravam, dizendo: Este recebe pecadores, e come com eles.' },
      { v: 3, en: 'He told them this parable.', pt: 'Então ele lhes propôs esta parábola:' },
      { v: 4, en: '“Which of you men, if you had one hundred sheep, and lost one of them, wouldn’t leave the ninety-nine in the wilderness, and go after the one that was lost, until he found it?', pt: 'Qual de vós é o homem que, possuindo cem ovelhas, e perdendo uma delas, não deixa as noventa e nove no deserto, e não vai após a perdida até que a encontre?' },
      { v: 5, en: 'When he has found it, he carries it on his shoulders, rejoicing.', pt: 'E achando-a, põe-na sobre os ombros, cheio de júbilo;' },
      { v: 6, en: 'When he comes home, he calls together his friends and his neighbors, saying to them, ‘Rejoice with me, for I have found my sheep which was lost!’', pt: 'e chegando a casa, reúne os amigos e vizinhos e lhes diz: Alegrai-vos comigo, porque achei a minha ovelha que se havia perdido.' },
      { v: 7, en: 'I tell you that even so there will be more joy in heaven over one sinner who repents, than over ninety-nine righteous people who need no repentance.', pt: 'Digo-vos que assim haverá maior alegria no céu por um pecador que se arrepende, do que por noventa e nove justos que não necessitam de arrependimento.' },
      { v: 8, en: 'Or what woman, if she had ten drachma coins, if she lost one drachma coin, wouldn’t light a lamp, sweep the house, and seek diligently until she found it?', pt: 'Ou qual é a mulher que, tendo dez dracmas e perdendo uma dracma, não acende a candeia, e não varre a casa, buscando com diligência até encontrá-la?' },
      { v: 9, en: 'When she has found it, she calls together her friends and neighbors, saying, ‘Rejoice with me, for I have found the drachma which I had lost.’', pt: 'E achando-a, reúne as amigas e vizinhas, dizendo: Alegrai-vos comigo, porque achei a dracma que eu havia perdido.' },
      { v: 10, en: 'Even so, I tell you, there is joy in the presence of the angels of God over one sinner repenting.”', pt: 'Assim, digo-vos, há alegria na presença dos anjos de Deus por um só pecador que se arrepende.' },
      { v: 11, en: 'He said, “A certain man had two sons.', pt: 'Disse-lhe mais: Certo homem tinha dois filhos.' },
      { v: 12, en: 'The younger of them said to his father, ‘Father, give me my share of your property.’ He divided his livelihood between them.', pt: 'O mais moço deles disse ao pai: Pai, dá-me a parte dos bens que me toca. Repartiu-lhes, pois, os seus haveres.' },
      { v: 13, en: 'Not many days after, the younger son gathered all of this together and traveled into a far country. There he wasted his property with riotous living.', pt: 'Poucos dias depois, o filho mais moço ajuntando tudo, partiu para um país distante, e ali desperdiçou os seus bens, vivendo dissolutamente.' },
      { v: 14, en: 'When he had spent all of it, there arose a severe famine in that country, and he began to be in need.', pt: 'E, havendo ele dissipado tudo, houve naquela terra uma grande fome, e começou a passar necessidades.' },
      { v: 15, en: 'He went and joined himself to one of the citizens of that country, and he sent him into his fields to feed pigs.', pt: 'Então foi encontrar-se a um dos cidadãos daquele país, o qual o mandou para os seus campos a apascentar porcos.' },
      { v: 16, en: 'He wanted to fill his belly with the husks that the pigs ate, but no one gave him any.', pt: 'E desejava encher o estômago com as alfarrobas que os porcos comiam; e ninguém lhe dava nada.' },
      { v: 17, en: 'But when he came to himself he said, ‘How many hired servants of my father’s have bread enough to spare, and I’m dying with hunger!', pt: 'Caindo, porém, em si, disse: Quantos empregados de meu pai têm abundância de pão, e eu aqui pereço de fome!' },
      { v: 18, en: 'I will get up and go to my father, and will tell him, “Father, I have sinned against heaven, and in your sight.', pt: 'Levantar-me-ei, irei ter com meu pai e dir-lhe-ei: Pai, pequei contra o céu e diante de ti;' },
      { v: 19, en: 'I am no more worthy to be called your son. Make me as one of your hired servants.”’', pt: 'já não sou digno de ser chamado teu filho; trata-me como um dos teus empregados.' },
      { v: 20, en: '“He arose, and came to his father. But while he was still far off, his father saw him, and was moved with compassion, and ran, and fell on his neck, and kissed him.', pt: 'Levantou-se, pois, e foi para seu pai. Estando ele ainda longe, seu pai o viu, encheu-se de compaixão e, correndo, lançou-se-lhe ao pescoço e o beijou.' },
      { v: 21, en: 'The son said to him, ‘Father, I have sinned against heaven, and in your sight. I am no longer worthy to be called your son.’', pt: 'Disse-lhe o filho: Pai, pequei conta o céu e diante de ti; já não sou digno de ser chamado teu filho.' },
      { v: 22, en: '“But the father said to his servants, ‘Bring out the best robe, and put it on him. Put a ring on his hand, and shoes on his feet.', pt: 'Mas o pai disse aos seus servos: Trazei depressa a melhor roupa, e vesti-lha, e ponde-lhe um anel no dedo e alparcas nos pés;' },
      { v: 23, en: 'Bring the fattened calf, kill it, and let us eat, and celebrate;', pt: 'trazei também o bezerro, cevado e matai-o; comamos, e regozijemo-nos,' },
      { v: 24, en: 'for this, my son, was dead, and is alive again. He was lost, and is found.’ They began to celebrate.', pt: 'porque este meu filho estava morto, e reviveu; tinha-se perdido, e foi achado. E começaram a regozijar-se.' },
      { v: 25, en: '“Now his elder son was in the field. As he came near to the house, he heard music and dancing.', pt: 'Ora, o seu filho mais velho estava no campo; e quando voltava, ao aproximar-se de casa, ouviu a música e as danças;' },
      { v: 26, en: 'He called one of the servants to him, and asked what was going on.', pt: 'e chegando um dos servos, perguntou-lhe que era aquilo.' },
      { v: 27, en: 'He said to him, ‘Your brother has come, and your father has killed the fattened calf, because he has received him back safe and healthy.’', pt: 'Respondeu-lhe este: Chegou teu irmão; e teu pai matou o bezerro cevado, porque o recebeu são e salvo.' },
      { v: 28, en: 'But he was angry, and would not go in. Therefore his father came out, and begged him.', pt: 'Mas ele se indignou e não queria entrar. Saiu então o pai e instava com ele.' },
      { v: 29, en: 'But he answered his father, ‘Behold, these many years I have served you, and I never disobeyed a commandment of yours, but you never gave me a goat, that I might celebrate with my friends.', pt: 'Ele, porém, respondeu ao pai: Eis que há tantos anos te sirvo, e nunca transgredi um mandamento teu; contudo nunca me deste um cabrito para eu me regozijar com os meus amigos;' },
      { v: 30, en: 'But when this your son came, who has devoured your living with prostitutes, you killed the fattened calf for him.’', pt: 'vindo, porém, este teu filho, que desperdiçou os teus bens com as meretrizes, mataste-lhe o bezerro cevado.' },
      { v: 31, en: '“He said to him, ‘Son, you are always with me, and all that is mine is yours.', pt: 'Replicou-lhe o pai: Filho, tu sempre estás comigo, e tudo o que é meu é teu;' },
      { v: 32, en: 'But it was appropriate to celebrate and be glad, for this, your brother, was dead, and is alive again. He was lost, and is found.’”', pt: 'era justo, porém, regozijarmo-nos e alegramo-nos, porque este teu irmão estava morto, e reviveu; tinha-se perdido, e foi achado.' },
    ],
    16: [
      { v: 1, en: 'He also said to his disciples, “There was a certain rich man who had a manager. An accusation was made to him that this man was wasting his possessions.', pt: 'Dizia Jesus também aos seus discípulos: Havia certo homem rico, que tinha um mordomo; e este foi acusado perante ele de estar dissipando os seus bens.' },
      { v: 2, en: 'He called him, and said to him, ‘What is this that I hear about you? Give an accounting of your management, for you can no longer be manager.’', pt: 'Chamou-o, então, e lhe disse: Que é isso que ouço dizer de ti? Presta contas da tua mordomia; porque já não podes mais ser meu mordomo.' },
      { v: 3, en: '“The manager said within himself, ‘What will I do, seeing that my lord is taking away the management position from me? I don’t have strength to dig. I am ashamed to beg.', pt: 'Disse, pois, o mordomo consigo: Que hei de fazer, já que o meu senhor me tira a mordomia? Para cavar, não tenho forças; de mendigar, tenho vergonha.' },
      { v: 4, en: 'I know what I will do, so that when I am removed from management, they may receive me into their houses.’', pt: 'Agora sei o que vou fazer, para que, quando for desapossado da mordomia, me recebam em suas casas.' },
      { v: 5, en: 'Calling each one of his lord’s debtors to him, he said to the first, ‘How much do you owe to my lord?’', pt: 'E chamando a si cada um dos devedores do seu senhor, perguntou ao primeiro: Quanto deves ao meu senhor?' },
      { v: 6, en: 'He said, ‘A hundred batos of oil.’ He said to him, ‘Take your bill, and sit down quickly and write fifty.’', pt: 'Respondeu ele: Cem cados de azeite. Disse-lhe então: Toma a tua conta, senta-te depressa e escreve cinquenta.' },
      { v: 7, en: 'Then he said to another, ‘How much do you owe?’ He said, ‘A hundred cors of wheat.’ He said to him, ‘Take your bill, and write eighty.’', pt: 'Perguntou depois a outro: E tu, quanto deves? Respondeu ele: Cem coros de trigo. E disse-lhe: Toma a tua conta e escreve oitenta.' },
      { v: 8, en: '“His lord commended the dishonest manager because he had done wisely, for the children of this world are, in their own generation, wiser than the children of the light.', pt: 'E louvou aquele senhor ao injusto mordomo por haver procedido com sagacidade; porque os filhos deste mundo são mais sagazes para com a sua geração do que os filhos da luz.' },
      { v: 9, en: 'I tell you, make for yourselves friends by means of unrighteous mammon, so that when you fail, they may receive you into the eternal tents.', pt: 'Eu vos digo ainda: Granjeai amigos por meio das riquezas da injustiça; para que, quando estas vos faltarem, vos recebam eles nos tabernáculos eternos.' },
      { v: 10, en: 'He who is faithful in a very little is faithful also in much. He who is dishonest in a very little is also dishonest in much.', pt: 'Quem é fiel no pouco, também é fiel no muito; quem é injusto no pouco, também é injusto no muito.' },
      { v: 11, en: 'If therefore you have not been faithful in the unrighteous mammon, who will commit to your trust the true riches?', pt: 'Se, pois, nas riquezas injustas não fostes fiéis, quem vos confiará as verdadeiras?' },
      { v: 12, en: 'If you have not been faithful in that which is another’s, who will give you that which is your own?', pt: 'E se no alheio não fostes fiéis, quem vos dará o que é vosso?' },
      { v: 13, en: 'No servant can serve two masters, for either he will hate the one, and love the other; or else he will hold to one, and despise the other. You aren’t able to serve God and Mammon.”', pt: 'Nenhum servo pode servir dois senhores; porque ou há de odiar a um e amar ao outro, o há de odiar a um e amar ao outro, o há de dedicar-se a um e desprezar o outro. Não podeis servir a Deus e às riquezas.' },
      { v: 14, en: 'The Pharisees, who were lovers of money, also heard all these things, and they scoffed at him.', pt: 'Os fariseus, que eram gananciosos, ouviam todas essas coisas e zombavam dele.' },
      { v: 15, en: 'He said to them, “You are those who justify yourselves in the sight of men, but God knows your hearts. For that which is exalted among men is an abomination in the sight of God.', pt: 'E ele lhes disse: Vós sois os que vos justificais a vós mesmos diante dos homens, mas Deus conhece os vossos corações; porque o que entre os homens é elevado, perante Deus é abominação.' },
      { v: 16, en: 'The law and the prophets were until John. From that time the Good News of God’s Kingdom is preached, and everyone is forcing his way into it.', pt: 'A lei e os profetas vigoraram até João; desde então é anunciado o evangelho do reino de Deus, e todo homem forceja por entrar nele.' },
      { v: 17, en: 'But it is easier for heaven and earth to pass away, than for one tiny stroke of a pen in the law to fall.', pt: 'É, porém, mais fácil passar o céu e a terra do que cair um til da lei.' },
      { v: 18, en: 'Everyone who divorces his wife, and marries another, commits adultery. He who marries one who is divorced from a husband commits adultery.', pt: 'Todo aquele que repudia sua mulher e casa com outra, comete adultério; e quem casa com a que foi repudiada pelo marido, também comete adultério.' },
      { v: 19, en: '“Now there was a certain rich man, and he was clothed in purple and fine linen, living in luxury every day.', pt: 'Ora, havia um homem rico que se vestia de púrpura e de linho finíssimo, e todos os dias se regalava esplendidamente.' },
      { v: 20, en: 'A certain beggar, named Lazarus, was taken to his gate, full of sores,', pt: 'Ao seu portão fora deitado um mendigo, chamado Lázaro, todo coberto de úlceras;' },
      { v: 21, en: 'and desiring to be fed with the crumbs that fell from the rich man’s table. Yes, even the dogs came and licked his sores.', pt: 'o qual desejava alimentar-se com as migalhas que caíam da mesa do rico; e os próprios cães vinham lamber-lhe as úlceras.' },
      { v: 22, en: 'The beggar died, and he was carried away by the angels to Abraham’s bosom. The rich man also died, and was buried.', pt: 'Veio a morrer o mendigo, e foi levado pelos anjos para o seio de Abraão; morreu também o rico, e foi sepultado.' },
      { v: 23, en: 'In Hades, he lifted up his eyes, being in torment, and saw Abraham far off, and Lazarus at his bosom.', pt: 'No hades, ergueu os olhos, estando em tormentos, e viu ao longe a Abraão, e a Lázaro no seu seio.' },
      { v: 24, en: 'He cried and said, ‘Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water, and cool my tongue! For I am in anguish in this flame.’', pt: 'E, clamando, disse: Pai Abraão, tem misericórdia de mim, e envia-me Lázaro, para que molhe na água a ponta do dedo e me refresque a língua, porque estou atormentado nesta chama.' },
      { v: 25, en: '“But Abraham said, ‘Son, remember that you, in your lifetime, received your good things, and Lazarus, in the same way, bad things. But here he is now comforted, and you are in anguish.', pt: 'Disse, porém, Abraão: Filho, lembra-te de que em tua vida recebeste os teus bens, e Lázaro de igual modo os males; agora, porém, ele aqui é consolado, e tu atormentado.' },
      { v: 26, en: 'Besides all this, between us and you there is a great gulf fixed, that those who want to pass from here to you are not able, and that no one may cross over from there to us.’', pt: 'E além disso, entre nós e vós está posto um grande abismo, de sorte que os que quisessem passar daqui para vós não poderiam, nem os de lá passar para nós.' },
      { v: 27, en: '“He said, ‘I ask you therefore, father, that you would send him to my father’s house;', pt: 'Disse ele então: Rogo-te, pois, ó pai, que o mandes à casa de meu pai,' },
      { v: 28, en: 'for I have five brothers, that he may testify to them, so they won’t also come into this place of torment.’', pt: 'porque tenho cinco irmãos; para que lhes dê testemunho, a fim de que não venham eles também para este lugar de tormento.' },
      { v: 29, en: '“But Abraham said to him, ‘They have Moses and the prophets. Let them listen to them.’', pt: 'Disse-lhe Abraão: Têm Moisés e os profetas; ouçam-nos.' },
      { v: 30, en: '“He said, ‘No, father Abraham, but if one goes to them from the dead, they will repent.’', pt: 'Respondeu ele: Não! pai Abraão; mas, se alguém dentre os mortos for ter com eles, hão de se arrepender.' },
      { v: 31, en: '“He said to him, ‘If they don’t listen to Moses and the prophets, neither will they be persuaded if one rises from the dead.’”', pt: 'Abraão, porém, lhe disse: Se não ouvem a Moisés e aos profetas, tampouco acreditarão, ainda que ressuscite alguém dentre os mortos.' },
    ],
    17: [
      { v: 1, en: 'He said to the disciples, “It is impossible that no occasions of stumbling should come, but woe to him through whom they come!', pt: 'Disse Jesus a seus discípulos: É impossível que não venham tropeços, mas ai daquele por quem vierem!' },
      { v: 2, en: 'It would be better for him if a millstone were hung around his neck, and he were thrown into the sea, rather than that he should cause one of these little ones to stumble.', pt: 'Melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho e fosse lançado ao mar, do que fazer tropeçar um destes pequeninos.' },
      { v: 3, en: 'Be careful. If your brother sins against you, rebuke him. If he repents, forgive him.', pt: 'Tende cuidado de vós mesmos; se teu irmão pecar, repreende-o; e se ele se arrepender, perdoa-lhe.' },
      { v: 4, en: 'If he sins against you seven times in the day, and seven times returns, saying, ‘I repent,’ you shall forgive him.”', pt: 'Mesmo se pecar contra ti sete vezes no dia, e sete vezes vier ter contigo, dizendo: Arrependo-me; tu lhe perdoarás.' },
      { v: 5, en: 'The apostles said to the Lord, “Increase our faith.”', pt: 'Disseram então os apóstolos ao Senhor: Aumenta-nos a fé.' },
      { v: 6, en: 'The Lord said, “If you had faith like a grain of mustard seed, you would tell this sycamore tree, ‘Be uprooted, and be planted in the sea,’ and it would obey you.', pt: 'Respondeu o Senhor: Se tivésseis fé como um grão de mostarda, diríeis a esta amoreira: Desarraiga-te, e planta-te no mar; e ela vos obedeceria.' },
      { v: 7, en: 'But who is there among you, having a servant plowing or keeping sheep, that will say, when he comes in from the field, ‘Come immediately and sit down at the table,’', pt: 'Qual de vós, tendo um servo a lavrar ou a apascentar gado, lhe dirá, ao voltar ele do campo: chega-te já, e reclina-te à mesa?' },
      { v: 8, en: 'and will not rather tell him, ‘Prepare my supper, clothe yourself properly, and serve me, while I eat and drink. Afterward you shall eat and drink’?', pt: 'Não lhe dirá antes: Prepara-me a ceia, e cinge-te, e serve-me, até que eu tenha comido e bebido, e depois comerás tu e beberás?' },
      { v: 9, en: 'Does he thank that servant because he did the things that were commanded? I think not.', pt: 'Porventura agradecerá ao servo, porque este fez o que lhe foi mandado?' },
      { v: 10, en: 'Even so you also, when you have done all the things that are commanded you, say, ‘We are unworthy servants. We have done our duty.’”', pt: 'Assim também vós, quando fizerdes tudo o que vos for mandado, dizei: Somos servos inúteis; fizemos somente o que devíamos fazer.' },
      { v: 11, en: 'As he was on his way to Jerusalem, he was passing along the borders of Samaria and Galilee.', pt: 'E aconteceu que, indo ele a Jerusalém, passava pela divisa entre a Samária e a Galiléia.' },
      { v: 12, en: 'As he entered into a certain village, ten men who were lepers met him, who stood at a distance.', pt: 'Ao entrar em certa aldeia, saíram-lhe ao encontro dez leprosos, os quais pararam de longe,' },
      { v: 13, en: 'They lifted up their voices, saying, “Jesus, Master, have mercy on us!”', pt: 'e levantaram a voz, dizendo: Jesus, Mestre, tem compaixão de nós!' },
      { v: 14, en: 'When he saw them, he said to them, “Go and show yourselves to the priests.” As they went, they were cleansed.', pt: 'Ele, logo que os viu, disse-lhes: Ide, e mostrai-vos aos sacerdotes. E aconteceu que, enquanto iam, ficaram limpos.' },
      { v: 15, en: 'One of them, when he saw that he was healed, turned back, glorifying God with a loud voice.', pt: 'Um deles, vendo que fora curado, voltou glorificando a Deus em alta voz;' },
      { v: 16, en: 'He fell on his face at Jesus’ feet, giving him thanks; and he was a Samaritan.', pt: 'e prostrou-se com o rosto em terra aos pés de Jesus, dando-lhe graças; e este era samaritano.' },
      { v: 17, en: 'Jesus answered, “Weren’t the ten cleansed? But where are the nine?', pt: 'Perguntou, pois, Jesus: Não foram limpos os dez? E os nove, onde estão?' },
      { v: 18, en: 'Were there none found who returned to give glory to God, except this stranger?”', pt: 'Não se achou quem voltasse para dar glória a Deus, senão este estrangeiro?' },
      { v: 19, en: 'Then he said to him, “Get up, and go your way. Your faith has healed you.”', pt: 'E disse-lhe: Levanta-te, e vai; a tua fé te salvou.' },
      { v: 20, en: 'Being asked by the Pharisees when God’s Kingdom would come, he answered them, “God’s Kingdom doesn’t come with observation;', pt: 'Sendo Jesus interrogado pelos fariseus sobre quando viria o reino de Deus, respondeu-lhes: O reino de Deus não vem com aparência exterior;' },
      { v: 21, en: 'neither will they say, ‘Look, here!’ or, ‘Look, there!’ for behold, God’s Kingdom is within you.”', pt: 'nem dirão: Ei-lo aqui! ou: Eí-lo ali! pois o reino de Deus está dentro de vós.' },
      { v: 22, en: 'He said to the disciples, “The days will come, when you will desire to see one of the days of the Son of Man, and you will not see it.', pt: 'Então disse aos discípulos: Dias virão em que desejareis ver um dos dias do Filho do homem, e não o vereis.' },
      { v: 23, en: 'They will tell you, ‘Look, here!’ or ‘Look, there!’ Don’t go away, nor follow after them,', pt: 'Dir-vos-ão: Ei-lo ali! ou: Ei-lo aqui! não vades, nem os sigais;' },
      { v: 24, en: 'for as the lightning, when it flashes out of the one part under the sky, shines to the other part under the sky; so will the Son of Man be in his day.', pt: 'pois, assim como o relâmpago, fuzilando em uma extremidade do céu, ilumina até a outra extremidade, assim será também o Filho do homem no seu dia.' },
      { v: 25, en: 'But first, he must suffer many things and be rejected by this generation.', pt: 'Mas primeiro é necessário que ele padeça muitas coisas, e que seja rejeitado por esta geração.' },
      { v: 26, en: 'As it was in the days of Noah, even so will it be also in the days of the Son of Man.', pt: 'Como aconteceu nos dias de Noé, assim também será nos dias do Filho do homem.' },
      { v: 27, en: 'They ate, they drank, they married, they were given in marriage, until the day that Noah entered into the ship, and the flood came, and destroyed them all.', pt: 'Comiam, bebiam, casavam e davam-se em casamento, até o dia em que Noé entrou na arca, e veio o dilúvio e os destruiu a todos.' },
      { v: 28, en: 'Likewise, even as it was in the days of Lot: they ate, they drank, they bought, they sold, they planted, they built;', pt: 'Como também da mesma forma aconteceu nos dias de Ló: comiam, bebiam, compravam, vendiam, plantavam e edificavam;' },
      { v: 29, en: 'but in the day that Lot went out from Sodom, it rained fire and sulfur from the sky, and destroyed them all.', pt: 'mas no dia em que Ló saiu de Sodoma choveu do céu fogo e enxofre, e os destruiu a todos;' },
      { v: 30, en: 'It will be the same way in the day that the Son of Man is revealed.', pt: 'assim será no dia em que o Filho do homem se há de manifestar.' },
      { v: 31, en: 'In that day, he who will be on the housetop, and his goods in the house, let him not go down to take them away. Let him who is in the field likewise not turn back.', pt: 'Naquele dia, quem estiver no eirado, tendo os seus bens em casa, não desça para tirá-los; e, da mesma sorte, o que estiver no campo, não volte para trás.' },
      { v: 32, en: 'Remember Lot’s wife!', pt: 'Lembrai-vos da mulher de Ló.' },
      { v: 33, en: 'Whoever seeks to save his life loses it, but whoever loses his life preserves it.', pt: 'Qualquer que procurar preservar a sua vida, perdê-la-á, e qualquer que a perder, conservá-la-á.' },
      { v: 34, en: 'I tell you, in that night there will be two people in one bed. The one will be taken, and the other will be left.', pt: 'Digo-vos: Naquela noite estarão dois numa cama; um será tomado, e o outro será deixado.' },
      { v: 35, en: 'There will be two grinding grain together. One will be taken, and the other will be left.”', pt: 'Duas mulheres estarão juntas moendo; uma será tomada, e a outra será deixada.' },
      { v: 36, en: '[Dois homens estarão no campo; um será tomado, e o outro será deixado.]', pt: '[Dois homens estarão no campo; um será tomado, e o outro será deixado.]' },
      { v: 37, en: 'They, answering, asked him, “Where, Lord?” He said to them, “Where the body is, there will the vultures also be gathered together.”', pt: 'Perguntaram-lhe: Onde, Senhor? E respondeu-lhes: Onde estiver o corpo, aí se ajuntarão também os abutres.' },
    ],
    18: [
      { v: 1, en: 'He also spoke a parable to them that they must always pray, and not give up,', pt: 'Contou-lhes também uma parábola sobre o dever de orar sempre, e nunca desfalecer.' },
      { v: 2, en: 'saying, “There was a judge in a certain city who didn’t fear God, and didn’t respect man.', pt: 'dizendo: Havia em certa cidade um juiz que não temia a Deus, nem respeitava os homens.' },
      { v: 3, en: 'A widow was in that city, and she often came to him, saying, ‘Defend me from my adversary!’', pt: 'Havia também naquela mesma cidade uma viúva que ia ter com ele, dizendo: Faze-me justiça contra o meu adversário.' },
      { v: 4, en: 'He wouldn’t for a while, but afterward he said to himself, ‘Though I neither fear God, nor respect man,', pt: 'E por algum tempo não quis atendê-la; mas depois disse consigo: Ainda que não temo a Deus, nem respeito os homens,' },
      { v: 5, en: 'yet because this widow bothers me, I will defend her, or else she will wear me out by her continual coming.’”', pt: 'todavia, como esta viúva me incomoda, hei de fazer-lhe justiça, para que ela não continue a vir molestar-me.' },
      { v: 6, en: 'The Lord said, “Listen to what the unrighteous judge says.', pt: 'Prosseguiu o Senhor: Ouvi o que diz esse juiz injusto.' },
      { v: 7, en: 'Won’t God avenge his chosen ones, who are crying out to him day and night, and yet he exercises patience with them?', pt: 'E não fará Deus justiça aos seus escolhidos, que dia e noite clamam a ele, já que é longânimo para com eles?' },
      { v: 8, en: 'I tell you that he will avenge them quickly. Nevertheless, when the Son of Man comes, will he find faith on the earth?”', pt: 'Digo-vos que depressa lhes fará justiça. Contudo quando vier o Filho do homem, porventura achará fé na terra?' },
      { v: 9, en: 'He spoke also this parable to certain people who were convinced of their own righteousness, and who despised all others.', pt: 'Propôs também esta parábola a uns que confiavam em si mesmos, crendo que eram justos, e desprezavam os outros:' },
      { v: 10, en: '“Two men went up into the temple to pray; one was a Pharisee, and the other was a tax collector.', pt: 'Dois homens subiram ao templo para orar; um fariseu, e o outro publicano.' },
      { v: 11, en: 'The Pharisee stood and prayed to himself like this: ‘God, I thank you, that I am not like the rest of men, extortionists, unrighteous, adulterers, or even like this tax collector.', pt: 'O fariseu, de pé, assim orava consigo mesmo: Ó Deus, graças te dou que não sou como os demais homens, roubadores, injustos, adúlteros, nem ainda com este publicano.' },
      { v: 12, en: 'I fast twice a week. I give tithes of all that I get.’', pt: 'Jejuo duas vezes na semana, e dou o dízimo de tudo quanto ganho.' },
      { v: 13, en: 'But the tax collector, standing far away, wouldn’t even lift up his eyes to heaven, but beat his breast, saying, ‘God, be merciful to me, a sinner!’', pt: 'Mas o publicano, estando em pé de longe, nem ainda queria levantar os olhos ao céu, mas batia no peito, dizendo: Ó Deus, sê propício a mim, o pecador!' },
      { v: 14, en: 'I tell you, this man went down to his house justified rather than the other; for everyone who exalts himself will be humbled, but he who humbles himself will be exalted.”', pt: 'Digo-vos que este desceu justificado para sua casa, e não aquele; porque todo o que a si mesmo se exaltar será humilhado; mas o que a si mesmo se humilhar será exaltado.' },
      { v: 15, en: 'They were also bringing their babies to him, that he might touch them. But when the disciples saw it, they rebuked them.', pt: 'Traziam-lhe também as crianças, para que as tocasse; mas os discípulos, vendo isso, os repreendiam.' },
      { v: 16, en: 'Jesus summoned them, saying, “Allow the little children to come to me, and don’t hinder them, for God’s Kingdom belongs to such as these.', pt: 'Jesus, porém, chamando-as para si, disse: Deixai vir a mim as crianças, e não as impeçais, porque de tais é o reino de Deus.' },
      { v: 17, en: 'Most certainly, I tell you, whoever doesn’t receive God’s Kingdom like a little child, he will in no way enter into it.”', pt: 'Em verdade vos digo que, qualquer que não receber o reino de Deus como criança, de modo algum entrará nele.' },
      { v: 18, en: 'A certain ruler asked him, saying, “Good Teacher, what shall I do to inherit eternal life?”', pt: 'E perguntou-lhe um dos principais: Bom Mestre, que hei de fazer para herdar a vida eterna?' },
      { v: 19, en: 'Jesus asked him, “Why do you call me good? No one is good, except one—God.', pt: 'Respondeu-lhe Jesus: Por que me chamas bom? Ninguém é bom, senão um, que é Deus.' },
      { v: 20, en: 'You know the commandments: ‘Don’t commit adultery,’ ‘Don’t murder,’ ‘Don’t steal,’ ‘Don’t give false testimony,’ ‘Honor your father and your mother.’”', pt: 'Sabes os mandamentos: Não adulterarás; não matarás; não furtarás; não dirás falso testemunho; honra a teu pai e a tua mãe.' },
      { v: 21, en: 'He said, “I have observed all these things from my youth up.”', pt: 'Replicou o homem: Tudo isso tenho guardado desde a minha juventude.' },
      { v: 22, en: 'When Jesus heard these things, he said to him, “You still lack one thing. Sell all that you have, and distribute it to the poor. You will have treasure in heaven. Come, follow me.”', pt: 'Quando Jesus ouviu isso, disse-lhe: Ainda te falta uma coisa; vende tudo quanto tens e reparte-o pelos pobres, e terás um tesouro no céu; e vem, segue-me.' },
      { v: 23, en: 'But when he heard these things, he became very sad, for he was very rich.', pt: 'Mas, ouvindo ele isso, encheu-se de tristeza; porque era muito rico.' },
      { v: 24, en: 'Jesus, seeing that he became very sad, said, “How hard it is for those who have riches to enter into God’s Kingdom!', pt: 'E Jesus, vendo-o assim, disse: Quão dificilmente entrarão no reino de Deus os que têm riquezas!' },
      { v: 25, en: 'For it is easier for a camel to enter in through a needle’s eye, than for a rich man to enter into God’s Kingdom.”', pt: 'Pois é mais fácil um camelo passar pelo fundo duma agulha, do que entrar um rico no reino de Deus.' },
      { v: 26, en: 'Those who heard it said, “Then who can be saved?”', pt: 'Então os que ouviram isso disseram: Quem pode, então, ser salvo?' },
      { v: 27, en: 'But he said, “The things which are impossible with men are possible with God.”', pt: 'Respondeu-lhes: As coisas que são impossíveis aos homens são possíveis a Deus.' },
      { v: 28, en: 'Peter said, “Look, we have left everything, and followed you.”', pt: 'Disse-lhe Pedro: Eis que nós deixamos tudo, e te seguimos.' },
      { v: 29, en: 'He said to them, “Most certainly I tell you, there is no one who has left house, or wife, or brothers, or parents, or children, for God’s Kingdom’s sake,', pt: 'Respondeu-lhes Jesus: Em verdade vos digo que ninguém há que tenha deixado casa, ou mulher, ou irmãos, ou pais, ou filhos, por amor do reino de Deus,' },
      { v: 30, en: 'who will not receive many times more in this time, and in the world to come, eternal life.”', pt: 'que não haja de receber no presente muito mais, e no mundo vindouro a vida eterna.' },
      { v: 31, en: 'He took the twelve aside, and said to them, “Behold, we are going up to Jerusalem, and all the things that are written through the prophets concerning the Son of Man will be completed.', pt: 'Tomando Jesus consigo os doze, disse-lhes: Eis que subimos a Jerusalém e se cumprirá no filho do homem tudo o que pelos profetas foi escrito;' },
      { v: 32, en: 'For he will be delivered up to the Gentiles, will be mocked, treated shamefully, and spit on.', pt: 'pois será entregue aos gentios, e escarnecido, injuriado e cuspido;' },
      { v: 33, en: 'They will scourge and kill him. On the third day, he will rise again.”', pt: 'e depois de o açoitarem, o matarão; e ao terceiro dia ressurgirá.' },
      { v: 34, en: 'They understood none of these things. This saying was hidden from them, and they didn’t understand the things that were said.', pt: 'Mas eles não entenderam nada disso; essas palavras lhes eram obscuras, e não percebiam o que lhes dizia.' },
      { v: 35, en: 'As he came near Jericho, a certain blind man sat by the road, begging.', pt: 'Ora, quando ele ia chegando a Jericó, estava um cego sentado junto do caminho, mendigando.' },
      { v: 36, en: 'Hearing a multitude going by, he asked what this meant.', pt: 'Este, pois, ouvindo passar a multidão, perguntou que era aquilo.' },
      { v: 37, en: 'They told him that Jesus of Nazareth was passing by.', pt: 'Disseram-lhe que Jesus, o nazareno, ia passando.' },
      { v: 38, en: 'He cried out, “Jesus, you son of David, have mercy on me!”', pt: 'Então ele se pôs a clamar, dizendo: Jesus, Filho de Davi, tem compaixão de mim!' },
      { v: 39, en: 'Those who led the way rebuked him, that he should be quiet; but he cried out all the more, “You son of David, have mercy on me!”', pt: 'E os que iam à frente repreendiam-no, para que se calasse; ele, porém, clamava ainda mais: Filho de Davi, tem compaixão de mim!' },
      { v: 40, en: 'Standing still, Jesus commanded him to be brought to him. When he had come near, he asked him,', pt: 'Parou, pois, Jesus, e mandou que lho trouxessem. Tendo ele chegado, perguntou-lhe:' },
      { v: 41, en: '“What do you want me to do?” He said, “Lord, that I may see again.”', pt: 'Que queres que te faça? Respondeu ele: Senhor, que eu veja.' },
      { v: 42, en: 'Jesus said to him, “Receive your sight. Your faith has healed you.”', pt: 'Disse-lhe Jesus: Vê; a tua fé te salvou.' },
      { v: 43, en: 'Immediately he received his sight, and followed him, glorifying God. All the people, when they saw it, praised God.', pt: 'Imediatamente recuperou a vista, e o foi seguindo, gloficando a Deus. E todo o povo, vendo isso, dava louvores a Deus.' },
    ],
    19: [
      { v: 1, en: 'He entered and was passing through Jericho.', pt: 'Tendo Jesus entrado em Jericó, ia atravessando a cidade.' },
      { v: 2, en: 'There was a man named Zacchaeus. He was a chief tax collector, and he was rich.', pt: 'Havia ali um homem chamado Zaqueu, o qual era chefe de publicanos e era rico.' },
      { v: 3, en: 'He was trying to see who Jesus was, and couldn’t because of the crowd, because he was short.', pt: 'Este procurava ver quem era Jesus, e não podia, por causa da multidão, porque era de pequena estatura.' },
      { v: 4, en: 'He ran on ahead, and climbed up into a sycamore tree to see him, for he was going to pass that way.', pt: 'E correndo adiante, subiu a um sicômoro a fim de vê-lo, porque havia de passar por ali.' },
      { v: 5, en: 'When Jesus came to the place, he looked up and saw him, and said to him, “Zacchaeus, hurry and come down, for today I must stay at your house.”', pt: 'Quando Jesus chegou àquele lugar, olhou para cima e disse-lhe: Zaqueu, desce depressa; porque importa que eu fique hoje em tua casa.' },
      { v: 6, en: 'He hurried, came down, and received him joyfully.', pt: 'Desceu, pois, a toda a pressa, e o recebeu com alegria.' },
      { v: 7, en: 'When they saw it, they all murmured, saying, “He has gone in to lodge with a man who is a sinner.”', pt: 'Ao verem isso, todos murmuravam, dizendo: Entrou para ser hóspede de um homem pecador.' },
      { v: 8, en: 'Zacchaeus stood and said to the Lord, “Behold, Lord, half of my goods I give to the poor. If I have wrongfully exacted anything of anyone, I restore four times as much.”', pt: 'Zaqueu, porém, levantando-se, disse ao Senhor: Eis aqui, Senhor, dou aos pobres metade dos meus bens; e se em alguma coisa tenho defraudado alguém, eu lho restituo quadruplicado.' },
      { v: 9, en: 'Jesus said to him, “Today, salvation has come to this house, because he also is a son of Abraham.', pt: 'Disse-lhe Jesus: Hoje veio a salvação a esta casa, porquanto também este é filho de Abraão.' },
      { v: 10, en: 'For the Son of Man came to seek and to save that which was lost.”', pt: 'Porque o Filho do homem veio buscar e salvar o que se havia perdido.' },
      { v: 11, en: 'As they heard these things, he went on and told a parable, because he was near Jerusalem, and they supposed that God’s Kingdom would be revealed immediately.', pt: 'Ouvindo eles isso, prosseguiu Jesus, e contou uma parábola, visto estar ele perto de Jerusalém, e pensarem eles que o reino de Deus se havia de manifestar imediatamente.' },
      { v: 12, en: 'He said therefore, “A certain nobleman went into a far country to receive for himself a kingdom, and to return.', pt: 'Disse pois: Certo homem nobre partiu para uma terra longínqua, a fim de tomar posse de um reino e depois voltar.' },
      { v: 13, en: 'He called ten servants of his, and gave them ten mina coins, and told them, ‘Conduct business until I come.’', pt: 'E chamando dez servos seus, deu-lhes dez minas, e disse-lhes: Negociai até que eu venha.' },
      { v: 14, en: 'But his citizens hated him, and sent an envoy after him, saying, ‘We don’t want this man to reign over us.’', pt: 'Mas os seus concidadãos odiavam-no, e enviaram após ele uma embaixada, dizendo: Não queremos que este homem reine sobre nós.' },
      { v: 15, en: '“When he had come back again, having received the kingdom, he commanded these servants, to whom he had given the money, to be called to him, that he might know what they had gained by conducting business.', pt: 'E sucedeu que, ao voltar ele, depois de ter tomado posse do reino, mandou chamar aqueles servos a quem entregara o dinheiro, a fim de saber como cada um havia negociado.' },
      { v: 16, en: 'The first came before him, saying, ‘Lord, your mina has made ten more minas.’', pt: 'Apresentou-se, pois, o primeiro, e disse: Senhor, a tua mina rendeu dez minas.' },
      { v: 17, en: '“He said to him, ‘Well done, you good servant! Because you were found faithful with very little, you shall have authority over ten cities.’', pt: 'Respondeu-lhe o senhor: Bem está, servo bom! porque no mínimo foste fiel, sobre dez cidades terás autoridade.' },
      { v: 18, en: '“The second came, saying, ‘Your mina, Lord, has made five minas.’', pt: 'Veio o segundo, dizendo: Senhor, a tua mina rendeu cinco minas.' },
      { v: 19, en: '“So he said to him, ‘And you are to be over five cities.’', pt: 'A este também respondeu: Sê tu também sobre cinco cidades.' },
      { v: 20, en: 'Another came, saying, ‘Lord, behold, your mina, which I kept laid away in a handkerchief,', pt: 'E veio outro, dizendo: Senhor, eis aqui a tua mina, que guardei num lenço;' },
      { v: 21, en: 'for I feared you, because you are an exacting man. You take up that which you didn’t lay down, and reap that which you didn’t sow.’', pt: 'pois tinha medo de ti, porque és homem severo; tomas o que não puseste, e ceifas o que não semeaste.' },
      { v: 22, en: '“He said to him, ‘Out of your own mouth will I judge you, you wicked servant! You knew that I am an exacting man, taking up that which I didn’t lay down, and reaping that which I didn’t sow.', pt: 'Disse-lhe o Senhor: Servo mau! pela tua boca te julgarei; sabias que eu sou homem severo, que tomo o que não pus, e ceifo o que não semeei;' },
      { v: 23, en: 'Then why didn’t you deposit my money in the bank, and at my coming, I might have earned interest on it?’', pt: 'por que, pois, não puseste o meu dinheiro no banco? então vindo eu, o teria retirado com os juros.' },
      { v: 24, en: 'He said to those who stood by, ‘Take the mina away from him, and give it to him who has the ten minas.’', pt: 'E disse aos que estavam ali: Tirai-lhe a mina, e dai-a ao que tem as dez minas.' },
      { v: 25, en: '“They said to him, ‘Lord, he has ten minas!’', pt: 'Responderam-lhe eles: Senhor, ele tem dez minas.' },
      { v: 26, en: '‘For I tell you that to everyone who has, will more be given; but from him who doesn’t have, even that which he has will be taken away from him.', pt: 'Pois eu vos digo que a todo o que tem, dar-se-lhe-á; mas ao que não tem, até aquilo que tem ser-lhe-á tirado.' },
      { v: 27, en: 'But bring those enemies of mine who didn’t want me to reign over them here, and kill them before me.’”', pt: 'Quanto, porém, àqueles meus inimigos que não quiseram que eu reinasse sobre eles, trazei-os aqui, e matai-os diante de mim.' },
      { v: 28, en: 'Having said these things, he went on ahead, going up to Jerusalem.', pt: 'Tendo Jesus assim falado, ia caminhando adiante deles, subindo para Jerusalém.' },
      { v: 29, en: 'When he came near to Bethsphage and Bethany, at the mountain that is called Olivet, he sent two of his disciples,', pt: 'Ao aproximar-se de Betfagé e de Betânia, junto do monte que se chama das Oliveiras, enviou dois dos discípulos,' },
      { v: 30, en: 'saying, “Go your way into the village on the other side, in which, as you enter, you will find a colt tied, which no man had ever sat upon. Untie it, and bring it.', pt: 'dizendo-lhes: Ide à aldeia que está defronte, e aí, ao entrar, achareis preso um jumentinho em que ninguém jamais montou; desprendei-o e trazei-o.' },
      { v: 31, en: 'If anyone asks you, ‘Why are you untying it?’ say to him: ‘The Lord needs it.’”', pt: 'Se alguém vos perguntar: Por que o desprendeis? respondereis assim: O Senhor precisa dele.' },
      { v: 32, en: 'Those who were sent went away, and found things just as he had told them.', pt: 'Partiram, pois, os que tinham sido enviados, e acharam conforme lhes dissera.' },
      { v: 33, en: 'As they were untying the colt, its owners said to them, “Why are you untying the colt?”', pt: 'Enquanto desprendiam o jumentinho, os seus donos lhes perguntaram: Por que desprendeis o jumentinho?' },
      { v: 34, en: 'They said, “The Lord needs it.”', pt: 'Responderam eles: O Senhor precisa dele.' },
      { v: 35, en: 'They brought it to Jesus. They threw their cloaks on the colt, and set Jesus on them.', pt: 'Trouxeram-no, pois, a Jesus e, lançando os seus mantos sobre o jumentinho, fizeram que Jesus montasse.' },
      { v: 36, en: 'As he went, they spread their cloaks on the road.', pt: 'E, enquanto ele ia passando, outros estendiam no caminho os seus mantos.' },
      { v: 37, en: 'As he was now getting near, at the descent of the Mount of Olives, the whole multitude of the disciples began to rejoice and praise God with a loud voice for all the mighty works which they had seen,', pt: 'Quando já ia chegando à descida do Monte das Oliveiras, toda a multidão dos discípulos, regozijando-se, começou a louvar a Deus em alta voz, por todos os milagres que tinha visto,' },
      { v: 38, en: 'saying, “Blessed is the King who comes in the name of the Lord! Peace in heaven, and glory in the highest!”', pt: 'dizendo: Bendito o Rei que vem em nome do Senhor; paz no céu, e glória nas alturas.' },
      { v: 39, en: 'Some of the Pharisees from the multitude said to him, “Teacher, rebuke your disciples!”', pt: 'Nisso, disseram-lhe alguns dos fariseus dentre a multidão: Mestre, repreende os teus discípulos.' },
      { v: 40, en: 'He answered them, “I tell you that if these were silent, the stones would cry out.”', pt: 'Ao que ele respondeu: Digo-vos que, se estes se calarem, as pedras clamarão.' },
      { v: 41, en: 'When he came near, he saw the city and wept over it,', pt: 'E quando chegou perto e viu a cidade, chorou sobre ela,' },
      { v: 42, en: 'saying, “If you, even you, had known today the things which belong to your peace! But now, they are hidden from your eyes.', pt: 'dizendo: Ah! se tu conhecesses, ao menos neste dia, o que te poderia trazer a paz! mas agora isso está encoberto aos teus olhos.' },
      { v: 43, en: 'For the days will come on you, when your enemies will throw up a barricade against you, surround you, hem you in on every side,', pt: 'Porque dias virão sobre ti em que os teus inimigos te cercarão de trincheiras, e te sitiarão, e te apertarão de todos os lados,' },
      { v: 44, en: 'and will dash you and your children within you to the ground. They will not leave in you one stone on another, because you didn’t know the time of your visitation.”', pt: 'e te derribarão, a ti e aos teus filhos que dentro de ti estiverem; e não deixarão em ti pedra sobre pedra, porque não conheceste o tempo da tua visitação.' },
      { v: 45, en: 'He entered into the temple, and began to drive out those who bought and sold in it,', pt: 'Então, entrando ele no templo, começou a expulsar os que ali vendiam,' },
      { v: 46, en: 'saying to them, “It is written, ‘My house is a house of prayer,’ but you have made it a ‘den of robbers’!”', pt: 'dizendo-lhes: Está escrito: A minha casa será casa de oração; vós, porém, a fizestes covil de salteadores.' },
      { v: 47, en: 'He was teaching daily in the temple, but the chief priests and the scribes and the leading men among the people sought to destroy him.', pt: 'E todos os dias ensinava no templo; mas os principais sacerdotes, os escribas, e os principais do povo procuravam matá-lo;' },
      { v: 48, en: 'They couldn’t find what they might do, for all the people hung on to every word that he said.', pt: 'mas não achavam meio de o fazer; porque todo o povo ficava enlevado ao ouvi-lo.' },
    ],
    20: [
      { v: 1, en: 'On one of those days, as he was teaching the people in the temple and preaching the Good News, the priests and scribes came to him with the elders.', pt: 'Num desses dias, quando Jesus ensinava o povo no templo, e anunciava o evangelho, sobrevieram os principais sacerdotes e os escribas, com os anciãos.' },
      { v: 2, en: 'They asked him, “Tell us: by what authority do you do these things? Or who is giving you this authority?”', pt: 'e falaram-lhe deste modo: Dize-nos, com que autoridade fazes tu estas coisas? Ou, quem é o que te deu esta autoridade?' },
      { v: 3, en: 'He answered them, “I also will ask you one question. Tell me:', pt: 'Respondeu-lhes ele: Eu também vos farei uma pergunta; dizei-me, pois:' },
      { v: 4, en: 'the baptism of John, was it from heaven, or from men?”', pt: 'O batismo de João era do céu ou dos homens?' },
      { v: 5, en: 'They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will say, ‘Why didn’t you believe him?’', pt: 'Ao que eles arrazoavam entre si: Se dissermos: do céu, ele dirá: Por que não crestes?' },
      { v: 6, en: 'But if we say, ‘From men,’ all the people will stone us, for they are persuaded that John was a prophet.”', pt: 'Mas, se dissermos: Dos homens, todo o povo nos apedrejará; pois está convencido de que João era profeta.' },
      { v: 7, en: 'They answered that they didn’t know where it was from.', pt: 'Responderam, pois, que não sabiam donde era.' },
      { v: 8, en: 'Jesus said to them, “Neither will I tell you by what authority I do these things.”', pt: 'Replicou-lhes Jesus: Nem eu vos digo com que autoridade faço estas coisas.' },
      { v: 9, en: 'He began to tell the people this parable. “A man planted a vineyard, and rented it out to some farmers, and went into another country for a long time.', pt: 'Começou então a dizer ao povo esta parábola: Um homem plantou uma vinha, arrendou-a a uns lavradores, e ausentou-se do país por muito tempo.' },
      { v: 10, en: 'At the proper season, he sent a servant to the farmers to collect his share of the fruit of the vineyard. But the farmers beat him, and sent him away empty.', pt: 'No tempo próprio mandou um servo aos lavradores, para que lhe dessem dos frutos da vinha; mas os lavradores, espancando-o, mandaram-no embora de mãos vazias.' },
      { v: 11, en: 'He sent yet another servant, and they also beat him, and treated him shamefully, and sent him away empty.', pt: 'Tornou a mandar outro servo; mas eles espancaram também a este e, afrontando-o, mandaram-no embora de mãos vazias.' },
      { v: 12, en: 'He sent yet a third, and they also wounded him, and threw him out.', pt: 'E mandou ainda um terceiro; mas feriram também a este e lançaram-no fora.' },
      { v: 13, en: 'The lord of the vineyard said, ‘What shall I do? I will send my beloved son. It may be that seeing him, they will respect him.’', pt: 'Disse então o senhor da vinha: Que farei? Mandarei o meu filho amado; a ele talvez respeitarão.' },
      { v: 14, en: '“But when the farmers saw him, they reasoned among themselves, saying, ‘This is the heir. Come, let’s kill him, that the inheritance may be ours.’', pt: 'Mas quando os lavradores o viram, arrazoaram entre si, dizendo: Este é o herdeiro; matemo-lo, para que a herança seja nossa.' },
      { v: 15, en: 'They threw him out of the vineyard, and killed him. What therefore will the lord of the vineyard do to them?', pt: 'E lançando-o fora da vinha, o mataram. Que lhes fará, pois, o senhor da vinha?' },
      { v: 16, en: 'He will come and destroy these farmers, and will give the vineyard to others.” When they heard it, they said, “May it never be!”', pt: 'Virá e destruirá esses lavradores, e dará a vinha a outros. Ouvindo eles isso, disseram: Tal não aconteça!' },
      { v: 17, en: 'But he looked at them, and said, “Then what is this that is written, ‘The stone which the builders rejected, the same was made the chief cornerstone?’', pt: 'Mas Jesus, olhando para eles, disse: Pois, que quer dizer isto que está escrito: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular?' },
      { v: 18, en: 'Everyone who falls on that stone will be broken to pieces, but it will crush whomever it falls on to dust.”', pt: 'Todo o que cair sobre esta pedra será despedaçado; mas aquele sobre quem ela cair será reduzido a pó.' },
      { v: 19, en: 'The chief priests and the scribes sought to lay hands on him that very hour, but they feared the people—for they knew he had spoken this parable against them.', pt: 'Ainda na mesma hora os escribas e os principais sacerdotes, percebendo que contra eles proferira essa parábola, procuraram deitar-lhe as mãos, mas temeram o povo.' },
      { v: 20, en: 'They watched him, and sent out spies, who pretended to be righteous, that they might trap him in something he said, so as to deliver him up to the power and authority of the governor.', pt: 'E, aguardando oportunidade, mandaram espias, os quais se fingiam justos, para o apanharem em alguma palavra, e o entregarem à jurisdição e à autoridade do governador.' },
      { v: 21, en: 'They asked him, “Teacher, we know that you say and teach what is right, and aren’t partial to anyone, but truly teach the way of God.', pt: 'Estes, pois, o interrogaram, dizendo: Mestre, sabemos que falas e ensinas retamente, e que não consideras a aparência da pessoa, mas ensinas segundo a verdade o caminho de Deus;' },
      { v: 22, en: 'Is it lawful for us to pay taxes to Caesar, or not?”', pt: 'é-nos lícito dar tributo a César, ou não?' },
      { v: 23, en: 'But he perceived their craftiness, and said to them, “Why do you test me?', pt: 'Mas Jesus, percebendo a astúcia deles, disse-lhes:' },
      { v: 24, en: 'Show me a denarius. Whose image and inscription are on it?” They answered, “Caesar’s.”', pt: 'Mostrai-me um denário. De quem é a imagem e a inscrição que ele tem? Responderam: De César.' },
      { v: 25, en: 'He said to them, “Then give to Caesar the things that are Caesar’s, and to God the things that are God’s.”', pt: 'Disse-lhes então: Dai, pois, a César o que é de César, e a Deus o que é de Deus.' },
      { v: 26, en: 'They weren’t able to trap him in his words before the people. They marveled at his answer, and were silent.', pt: 'E não puderam apanhá-lo em palavra alguma diante do povo; e admirados da sua resposta, calaram-se.' },
      { v: 27, en: 'Some of the Sadducees came to him, those who deny that there is a resurrection.', pt: 'Chegaram então alguns dos saduceus, que dizem não haver ressurreição, e perguntaram-lhe:' },
      { v: 28, en: 'They asked him, “Teacher, Moses wrote to us that if a man’s brother dies having a wife, and he is childless, his brother should take the wife, and raise up children for his brother.', pt: 'Mestre, Moisés nos deixou escrito que se morrer alguém, tendo mulher mas não tendo filhos, o irmão dele case com a viúva, e suscite descendência ao irmão.' },
      { v: 29, en: 'There were therefore seven brothers. The first took a wife, and died childless.', pt: 'Havia, pois, sete irmãos. O primeiro casou-se e morreu sem filhos;' },
      { v: 30, en: 'The second took her as wife, and he died childless.', pt: 'então o segundo, e depois o terceiro, casaram com a viúva;' },
      { v: 31, en: 'The third took her, and likewise the seven all left no children, and died.', pt: 'e assim todos os sete, e morreram, sem deixar filhos.' },
      { v: 32, en: 'Afterward the woman also died.', pt: 'Depois morreu também a mulher.' },
      { v: 33, en: 'Therefore in the resurrection whose wife of them will she be? For the seven had her as a wife.”', pt: 'Portanto, na ressurreição, de qual deles será ela esposa, pois os sete por esposa a tiveram?' },
      { v: 34, en: 'Jesus said to them, “The children of this age marry, and are given in marriage.', pt: 'Respondeu-lhes Jesus: Os filhos deste mundo casaram-se e dão-se em casamento;' },
      { v: 35, en: 'But those who are considered worthy to attain to that age and the resurrection from the dead, neither marry, nor are given in marriage.', pt: 'mas os que são julgados dignos de alcançar o mundo vindouro, e a ressurreição dentre os mortos, nem se casam nem se dão em casamento;' },
      { v: 36, en: 'For they can’t die any more, for they are like the angels, and are children of God, being children of the resurrection.', pt: 'porque já não podem mais morrer; pois são iguais aos anjos, e são filhos de Deus, sendo filhos da ressurreição.' },
      { v: 37, en: 'But that the dead are raised, even Moses showed at the bush, when he called the Lord ‘The God of Abraham, the God of Isaac, and the God of Jacob.’', pt: 'Mas que os mortos hão de ressurgir, o próprio Moisés o mostrou, na passagem a respeito da sarça, quando chama ao Senhor; Deus de Abraão, e Deus de Isaque, e Deus de Jacó.' },
      { v: 38, en: 'Now he is not the God of the dead, but of the living, for all are alive to him.”', pt: 'Ora, ele não é Deus de mortos, mas de vivos; porque para ele todos vivem.' },
      { v: 39, en: 'Some of the scribes answered, “Teacher, you speak well.”', pt: 'Responderam alguns dos escribas: Mestre, disseste bem.' },
      { v: 40, en: 'They didn’t dare to ask him any more questions.', pt: 'Não ousavam, pois, perguntar-lhe mais coisa alguma.' },
      { v: 41, en: 'He said to them, “Why do they say that the Christ is David’s son?', pt: 'Jesus, porém, lhes perguntou: Como dizem que o Cristo é filho de Davi?' },
      { v: 42, en: 'David himself says in the book of Psalms, ‘The Lord said to my Lord, “Sit at my right hand,', pt: 'Pois o próprio Davi diz no livro dos Salmos: Disse o Senhor ao meu Senhor: Assenta-te à minha direita,' },
      { v: 43, en: 'until I make your enemies the footstool of your feet.”’', pt: 'até que eu ponha os teus inimigos por escabelo dos teus pés.' },
      { v: 44, en: '“David therefore calls him Lord, so how is he his son?”', pt: 'Logo Davi lhe chama Senhor como, pois, é ele seu filho?' },
      { v: 45, en: 'In the hearing of all the people, he said to his disciples,', pt: 'Enquanto todo o povo o ouvia, disse Jesus aos seus discípulos:' },
      { v: 46, en: '“Beware of those scribes who like to walk in long robes, and love greetings in the marketplaces, the best seats in the synagogues, and the best places at feasts;', pt: 'Guardai-vos dos escribas, que querem andar com vestes compridas, e gostam das saudações nas praças, dos primeiros assentos nas sinagogas, e dos primeiros lugares nos banquetes;' },
      { v: 47, en: 'who devour widows’ houses, and for a pretense make long prayers: these will receive greater condemnation.”', pt: 'que devoram as casas das viúvas, fazendo, por pretexto, longas orações; estes hão de receber maior condenação.' },
    ],
    21: [
      { v: 1, en: 'He looked up, and saw the rich people who were putting their gifts into the treasury.', pt: 'Jesus, levantando os olhos, viu os ricos deitarem as suas ofertas no cofre;' },
      { v: 2, en: 'He saw a certain poor widow casting in two small brass coins.', pt: 'viu também uma pobre viúva lançar ali dois leptos;' },
      { v: 3, en: 'He said, “Truly I tell you, this poor widow put in more than all of them,', pt: 'e disse: Em verdade vos digo que esta pobre viúva deu mais do que todos;' },
      { v: 4, en: 'for all these put in gifts for God from their abundance, but she, out of her poverty, put in all that she had to live on.”', pt: 'porque todos aqueles deram daquilo que lhes sobrava; mas esta, da sua pobreza, deu tudo o que tinha para o seu sustento.' },
      { v: 5, en: 'As some were talking about the temple and how it was decorated with beautiful stones and gifts, he said,', pt: 'E falando-lhe alguns a respeito do templo, como estava ornado de formosas pedras e dádivas, disse ele:' },
      { v: 6, en: '“As for these things which you see, the days will come, in which there will not be left here one stone on another that will not be thrown down.”', pt: 'Quanto a isto que vedes, dias virão em que não se deixará aqui pedra sobre pedra, que não seja derribada.' },
      { v: 7, en: 'They asked him, “Teacher, so when will these things be? What is the sign that these things are about to happen?”', pt: 'Perguntaram-lhe então: Mestre, quando, pois, sucederão estas coisas? E que sinal haverá, quando elas estiverem para se cumprir?' },
      { v: 8, en: 'He said, “Watch out that you don’t get led astray, for many will come in my name, saying, ‘I am he ,’ and, ‘The time is at hand.’ Therefore don’t follow them.', pt: 'Respondeu então ele: Acautelai-vos; não sejais enganados; porque virão muitos em meu nome, dizendo: Sou eu; e: O tempo é chegado; não vades após eles.' },
      { v: 9, en: 'When you hear of wars and disturbances, don’t be terrified, for these things must happen first, but the end won’t come immediately.”', pt: 'Quando ouvirdes de guerras e tumultos, não vos assusteis; pois é necessário que primeiro aconteçam essas coisas; mas o fim não será logo.' },
      { v: 10, en: 'Then he said to them, “Nation will rise against nation, and kingdom against kingdom.', pt: 'Então lhes disse: Levantar-se-á nação contra nação, e reino contra reino;' },
      { v: 11, en: 'There will be great earthquakes, famines, and plagues in various places. There will be terrors and great signs from heaven.', pt: 'e haverá em vários lugares grandes terremotos, e pestes e fomes; haverá também coisas espantosas, e grandes sinais do céu.' },
      { v: 12, en: 'But before all these things, they will lay their hands on you and will persecute you, delivering you up to synagogues and prisons, bringing you before kings and governors for my name’s sake.', pt: 'Mas antes de todas essas coisas vos hão de prender e perseguir, entregando-vos às sinagogas e aos cárceres, e conduzindo-vos à presença de reis e governadores, por causa do meu nome.' },
      { v: 13, en: 'It will turn out as a testimony for you.', pt: 'Isso vos acontecerá para que deis testemunho.' },
      { v: 14, en: 'Settle it therefore in your hearts not to meditate beforehand how to answer,', pt: 'Proponde, pois, em vossos corações não premeditar como haveis de fazer a vossa defesa;' },
      { v: 15, en: 'for I will give you a mouth and wisdom which all your adversaries will not be able to withstand or to contradict.', pt: 'porque eu vos darei boca e sabedoria, a que nenhum dos vossos adversário poderá resistir nem contradizer.' },
      { v: 16, en: 'You will be handed over even by parents, brothers, relatives, and friends. They will cause some of you to be put to death.', pt: 'E até pelos pais, e irmãos, e parentes, e amigos sereis entregues; e matarão alguns de vós;' },
      { v: 17, en: 'You will be hated by all men for my name’s sake.', pt: 'e sereis odiados de todos por causa do meu nome.' },
      { v: 18, en: 'And not a hair of your head will perish.', pt: 'Mas não se perderá um único cabelo da vossa cabeça.' },
      { v: 19, en: '“By your endurance you will win your lives.', pt: 'Pela vossa perseverança ganhareis as vossas almas.' },
      { v: 20, en: '“But when you see Jerusalem surrounded by armies, then know that its desolation is at hand.', pt: 'Mas, quando virdes Jerusalém cercada de exércitos, sabei então que é chegada a sua desolação.' },
      { v: 21, en: 'Then let those who are in Judea flee to the mountains. Let those who are in the middle of her depart. Let those who are in the country not enter therein.', pt: 'Então, os que estiverem na Judéia fujam para os montes; os que estiverem dentro da cidade, saiam; e os que estiverem nos campos não entrem nela.' },
      { v: 22, en: 'For these are days of vengeance, that all things which are written may be fulfilled.', pt: 'Porque dias de vingança são estes, para que se cumpram todas as coisas que estão escritas.' },
      { v: 23, en: 'Woe to those who are pregnant and to those who nurse infants in those days! For there will be great distress in the land, and wrath to this people.', pt: 'Ai das que estiverem grávidas, e das que amamentarem naqueles dias! porque haverá grande angústia sobre a terra, e ira contra este povo.' },
      { v: 24, en: 'They will fall by the edge of the sword, and will be led captive into all the nations. Jerusalem will be trampled down by the Gentiles, until the times of the Gentiles are fulfilled.', pt: 'E cairão ao fio da espada, e para todas as nações serão levados cativos; e Jerusalém será pisada pelos gentios, até que os tempos destes se completem.' },
      { v: 25, en: 'There will be signs in the sun, moon, and stars; and on the earth anxiety of nations, in perplexity for the roaring of the sea and the waves;', pt: 'E haverá sinais no sol, na lua e nas estrelas; e sobre a terra haverá angústia das nações em perplexidade pelo bramido do mar e das ondas.' },
      { v: 26, en: 'men fainting for fear, and for expectation of the things which are coming on the world: for the powers of the heavens will be shaken.', pt: 'os homens desfalecerão de terror, e pela expectação das coisas que sobrevirão ao mundo; porquanto os poderes do céu serão abalados.' },
      { v: 27, en: 'Then they will see the Son of Man coming in a cloud with power and great glory.', pt: 'Então verão vir o Filho do homem em uma nuvem, com poder e grande glória.' },
      { v: 28, en: 'But when these things begin to happen, look up, and lift up your heads, because your redemption is near.”', pt: 'Ora, quando essas coisas começarem a acontecer, exultai e levantai as vossas cabeças, porque a vossa redenção se aproxima.' },
      { v: 29, en: 'He told them a parable. “See the fig tree, and all the trees.', pt: 'Propôs-lhes então uma parábola: Olhai para a figueira, e para todas as árvores;' },
      { v: 30, en: 'When they are already budding, you see it and know by your own selves that the summer is already near.', pt: 'quando começam a brotar, sabeis por vós mesmos, ao vê-las, que já está próximo o verão.' },
      { v: 31, en: 'Even so you also, when you see these things happening, know that God’s Kingdom is near.', pt: 'Assim também vós, quando virdes acontecerem estas coisas, sabei que o reino de Deus está próximo.' },
      { v: 32, en: 'Most certainly I tell you, this generation will not pass away until all things are accomplished.', pt: 'Em verdade vos digo que não passará esta geração até que tudo isso se cumpra.' },
      { v: 33, en: 'Heaven and earth will pass away, but my words will by no means pass away.', pt: 'Passará o céu e a terra, mas as minhas palavras jamais passarão.' },
      { v: 34, en: '“So be careful, or your hearts will be loaded down with carousing, drunkenness, and cares of this life, and that day will come on you suddenly.', pt: 'Olhai por vós mesmos; não aconteça que os vossos corações se carreguem de glutonaria, de embriaguez, e dos cuidados da vida, e aquele dia vos sobrevenha de improviso como um laço.' },
      { v: 35, en: 'For it will come like a snare on all those who dwell on the surface of all the earth.', pt: 'Porque há de vir sobre todos os que habitam na face da terra.' },
      { v: 36, en: 'Therefore be watchful all the time, praying that you may be counted worthy to escape all these things that will happen, and to stand before the Son of Man.”', pt: 'Vigiai, pois, em todo o tempo, orando, para que possais escapar de todas estas coisas que hão de acontecer, e estar em pé na presença do Filho do homem.' },
      { v: 37, en: 'Every day Jesus was teaching in the temple, and every night he would go out and spend the night on the mountain that is called Olivet.', pt: 'Ora, de dia ensinava no templo, e à noite, saindo, pousava no monte chamado das Oliveiras.' },
      { v: 38, en: 'All the people came early in the morning to him in the temple to hear him.', pt: 'E todo o povo ia ter com ele no templo, de manhã cedo, para o ouvir.' },
    ],
    22: [
      { v: 1, en: 'Now the feast of unleavened bread, which is called the Passover, was approaching.', pt: 'Aproximava-se a festa dos pães ázimos, que se chama a páscoa.' },
      { v: 2, en: 'The chief priests and the scribes sought how they might put him to death, for they feared the people.', pt: 'E os principais sacerdotes e os escribas andavam procurando um modo de o matar; pois temiam o povo.' },
      { v: 3, en: 'Satan entered into Judas, who was also called Iscariot, who was counted with the twelve.', pt: 'Entrou então Satanás em Judas, que tinha por sobrenome Iscariotes, que era um dos doze;' },
      { v: 4, en: 'He went away, and talked with the chief priests and captains about how he might deliver him to them.', pt: 'e foi ele tratar com os principais sacerdotes e com os capitães de como lho entregaria.' },
      { v: 5, en: 'They were glad, and agreed to give him money.', pt: 'Eles se alegraram com isso, e convieram em lhe dar dinheiro.' },
      { v: 6, en: 'He consented, and sought an opportunity to deliver him to them in the absence of the multitude.', pt: 'E ele concordou, e buscava ocasião para lho entregar sem alvoroço.' },
      { v: 7, en: 'The day of unleavened bread came, on which the Passover must be sacrificed.', pt: 'Ora, chegou o dia dos pães ázimos, em que se devia imolar a páscoa;' },
      { v: 8, en: 'Jesus sent Peter and John, saying, “Go and prepare the Passover for us, that we may eat.”', pt: 'e Jesus enviou a Pedro e a João, dizendo: Ide, preparai-nos a páscoa, para que a comamos.' },
      { v: 9, en: 'They said to him, “Where do you want us to prepare?”', pt: 'Perguntaram-lhe eles: Onde queres que a preparemos?' },
      { v: 10, en: 'He said to them, “Behold, when you have entered into the city, a man carrying a pitcher of water will meet you. Follow him into the house which he enters.', pt: 'Respondeu-lhes: Quando entrardes na cidade, sair-vos-á ao encontro um homem, levando um cântaro de água; segui-o até a casa em que ele entrar.' },
      { v: 11, en: 'Tell the master of the house, ‘The Teacher says to you, “Where is the guest room, where I may eat the Passover with my disciples?”’', pt: 'E direis ao dono da casa: O Mestre manda perguntar-te: Onde está o aposento em que hei de comer a páscoa com os meus discípulos?' },
      { v: 12, en: 'He will show you a large, furnished upper room. Make preparations there.”', pt: 'Então ele vos mostrará um grande cenáculo mobiliado; aí fazei os preparativos.' },
      { v: 13, en: 'They went, found things as Jesus had told them, and they prepared the Passover.', pt: 'Foram, pois, e acharam tudo como lhes dissera e prepararam a páscoa.' },
      { v: 14, en: 'When the hour had come, he sat down with the twelve apostles.', pt: 'E, chegada a hora, pôs-se Jesus à mesa, e com ele os apóstolos.' },
      { v: 15, en: 'He said to them, “I have earnestly desired to eat this Passover with you before I suffer,', pt: 'E disse-lhes: Tenho desejado ardentemente comer convosco esta páscoa, antes da minha paixão;' },
      { v: 16, en: 'for I tell you, I will no longer by any means eat of it until it is fulfilled in God’s Kingdom.”', pt: 'pois vos digo que não a comerei mais até que ela se cumpra no reino de Deus.' },
      { v: 17, en: 'He received a cup, and when he had given thanks, he said, “Take this, and share it among yourselves,', pt: 'Então havendo recebido um cálice, e tendo dado graças, disse: Tomai-o, e reparti-o entre vós;' },
      { v: 18, en: 'for I tell you, I will not drink at all again from the fruit of the vine, until God’s Kingdom comes.”', pt: 'porque vos digo que desde agora não mais beberei do fruto da videira, até que venha o reino de Deus.' },
      { v: 19, en: 'He took bread, and when he had given thanks, he broke, and gave it to them, saying, “This is my body which is given for you. Do this in memory of me.”', pt: 'E tomando pão, e havendo dado graças, partiu-o e deu-lho, dizendo: Isto é o meu corpo, que é dado por vós; fazei isto em memória de mim.' },
      { v: 20, en: 'Likewise, he took the cup after supper, saying, “This cup is the new covenant in my blood, which is poured out for you.', pt: 'Semelhantemente, depois da ceia, tomou o cálice, dizendo: Este cálice é o novo pacto em meu sangue, que é derramado por vós.' },
      { v: 21, en: 'But behold, the hand of him who betrays me is with me on the table.', pt: 'Mas eis que a mão do que me trai está comigo à mesa.' },
      { v: 22, en: 'The Son of Man indeed goes, as it has been determined, but woe to that man through whom he is betrayed!”', pt: 'Porque, na verdade, o Filho do homem vai segundo o que está determinado; mas ai daquele homem por quem é traído!' },
      { v: 23, en: 'They began to question among themselves, which of them it was who would do this thing.', pt: 'Então eles começaram a perguntar entre si qual deles o que ia fazer isso.' },
      { v: 24, en: 'There arose also a contention among them, which of them was considered to be greatest.', pt: 'Levantou-se também entre eles contenda, sobre qual deles parecia ser o maior.' },
      { v: 25, en: 'He said to them, “The kings of the nations lord it over them, and those who have authority over them are called ‘benefactors.’', pt: 'Ao que Jesus lhes disse: Os reis dos gentios dominam sobre eles, e os que sobre eles exercem autoridade são chamados benfeitores.' },
      { v: 26, en: 'But not so with you. But one who is the greater among you, let him become as the younger, and one who is governing, as one who serves.', pt: 'Mas vós não sereis assim; antes o maior entre vós seja como o mais novo; e quem governa como quem serve.' },
      { v: 27, en: 'For who is greater, one who sits at the table, or one who serves? Isn’t it he who sits at the table? But I am among you as one who serves.', pt: 'Pois qual é maior, quem está à mesa, ou quem serve? porventura não é quem está à mesa? Eu, porém, estou entre vós como quem serve.' },
      { v: 28, en: 'But you are those who have continued with me in my trials.', pt: 'Mas vós sois os que tendes permanecido comigo nas minhas provações;' },
      { v: 29, en: 'I confer on you a kingdom, even as my Father conferred on me,', pt: 'e assim como meu Pai me conferiu domínio, eu vo-lo confiro a vós;' },
      { v: 30, en: 'that you may eat and drink at my table in my Kingdom. You will sit on thrones, judging the twelve tribes of Israel.”', pt: 'para que comais e bebais à minha mesa no meu reino, e vos senteis sobre tronos, julgando as doze tribos de Israel.' },
      { v: 31, en: 'The Lord said, “Simon, Simon, behold, Satan asked to have all of you, that he might sift you as wheat,', pt: 'Simão, Simão, eis que Satanás vos pediu para vos cirandar como trigo;' },
      { v: 32, en: 'but I prayed for you, that your faith wouldn’t fail. You, when once you have turned again, establish your brothers.”', pt: 'mas eu roguei por ti, para que a tua fé não desfaleça; e tu, quando te converteres, fortalece teus irmãos.' },
      { v: 33, en: 'He said to him, “Lord, I am ready to go with you both to prison and to death!”', pt: 'Respondeu-lhe Pedro: Senhor, estou pronto a ir contigo tanto para a prisão como para a morte.' },
      { v: 34, en: 'He said, “I tell you, Peter, the rooster will by no means crow today until you deny that you know me three times.”', pt: 'Tornou-lhe Jesus: Digo-te, Pedro, que não cantará hoje o galo antes que três vezes tenhas negado que me conheces.' },
      { v: 35, en: 'He said to them, “When I sent you out without purse, and wallet, and shoes, did you lack anything?” They said, “Nothing.”', pt: 'E perguntou-lhes: Quando vos mandei sem bolsa, alforje, ou alparcas, faltou-vos porventura alguma coisa? Eles responderam: Nada.' },
      { v: 36, en: 'Then he said to them, “But now, whoever has a purse, let him take it, and likewise a wallet. Whoever has none, let him sell his cloak, and buy a sword.', pt: 'Disse-lhes pois: Mas agora, quem tiver bolsa, tome-a, como também o alforje; e quem não tiver espada, venda o seu manto e compre-a.' },
      { v: 37, en: 'For I tell you that this which is written must still be fulfilled in me: ‘He was counted with transgressors.’ For that which concerns me has an end.”', pt: 'Porquanto vos digo que importa que se cumpra em mim isto que está escrito: E com os malfeitores foi contado. Pois o que me diz respeito tem seu cumprimento.' },
      { v: 38, en: 'They said, “Lord, behold, here are two swords.” He said to them, “That is enough.”', pt: 'Disseram eles: Senhor, eis aqui duas espadas. Respondeu-lhes: Basta.' },
      { v: 39, en: 'He came out, and went, as his custom was, to the Mount of Olives. His disciples also followed him.', pt: 'Então saiu e, segundo o seu costume, foi para o Monte das Oliveiras; e os discípulos o seguiam.' },
      { v: 40, en: 'When he was at the place, he said to them, “Pray that you don’t enter into temptation.”', pt: 'Quando chegou àquele lugar, disse-lhes: Orai, para que não entreis em tentação.' },
      { v: 41, en: 'He was withdrawn from them about a stone’s throw, and he knelt down and prayed,', pt: 'E apartou-se deles cerca de um tiro de pedra; e pondo-se de joelhos, orava,' },
      { v: 42, en: 'saying, “Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done.”', pt: 'dizendo: Pai, se queres afasta de mim este cálice; todavia não se faça a minha vontade, mas a tua.' },
      { v: 43, en: 'An angel from heaven appeared to him, strengthening him.', pt: 'Então lhe apareceu um anjo do céu, que o confortava.' },
      { v: 44, en: 'Being in agony he prayed more earnestly. His sweat became like great drops of blood falling down on the ground.', pt: 'E, posto em agonia, orava mais intensamente; e o seu suor tornou-se como grandes gotas de sangue, que caíam sobre o chão.' },
      { v: 45, en: 'When he rose up from his prayer, he came to the disciples, and found them sleeping because of grief,', pt: 'Depois, levantando-se da oração, veio para os seus discípulos, e achou-os dormindo de tristeza;' },
      { v: 46, en: 'and said to them, “Why do you sleep? Rise and pray that you may not enter into temptation.”', pt: 'e disse-lhes: Por que estais dormindo? Lenvantai-vos, e orai, para que não entreis em tentação.' },
      { v: 47, en: 'While he was still speaking, behold, a multitude, and he who was called Judas, one of the twelve, was leading them. He came near to Jesus to kiss him.', pt: 'E estando ele ainda a falar, eis que surgiu uma multidão; e aquele que se chamava Judas, um dos doze, ia adiante dela, e chegou-se a Jesus para o beijar.' },
      { v: 48, en: 'But Jesus said to him, “Judas, do you betray the Son of Man with a kiss?”', pt: 'Jesus, porém, lhe disse: Judas, com um beijo trais o Filho do homem?' },
      { v: 49, en: 'When those who were around him saw what was about to happen, they said to him, “Lord, shall we strike with the sword?”', pt: 'Quando os que estavam com ele viram o que ia suceder, disseram: Senhor, feri-los-emos a espada?' },
      { v: 50, en: 'A certain one of them struck the servant of the high priest, and cut off his right ear.', pt: 'Então um deles feriu o servo do sumo sacerdote, e cortou-lhe a orelha direita.' },
      { v: 51, en: 'But Jesus answered, “Let me at least do this” —and he touched his ear, and healed him.', pt: 'Mas Jesus disse: Deixei-os; basta. E tocando-lhe a orelha, o curou.' },
      { v: 52, en: 'Jesus said to the chief priests, captains of the temple, and elders, who had come against him, “Have you come out as against a robber, with swords and clubs?', pt: 'Então disse Jesus aos principais sacerdotes, oficiais do templo e anciãos, que tinham ido contra ele: Saístes, como a um salteador, com espadas e varapaus?' },
      { v: 53, en: 'When I was with you in the temple daily, you didn’t stretch out your hands against me. But this is your hour, and the power of darkness.”', pt: 'Todos os dias estava eu convosco no templo, e não estendestes as mãos contra mim; mas esta é a vossa hora e o poder das trevas.' },
      { v: 54, en: 'They seized him, and led him away, and brought him into the high priest’s house. But Peter followed from a distance.', pt: 'Então, prendendo-o, o levaram e o introduziram na casa do sumo sacerdote; e Pedro seguia-o de longe.' },
      { v: 55, en: 'When they had kindled a fire in the middle of the courtyard, and had sat down together, Peter sat among them.', pt: 'E tendo eles acendido fogo no meio do pátio e havendo-se sentado à roda, sentou-se Pedro entre eles.' },
      { v: 56, en: 'A certain servant girl saw him as he sat in the light, and looking intently at him, said, “This man also was with him.”', pt: 'Uma criada, vendo-o sentado ao lume, fixou os olhos nele e disse: Esse também estava com ele.' },
      { v: 57, en: 'He denied Jesus, saying, “Woman, I don’t know him.”', pt: 'Mas Pedro o negou, dizendo: Mulher, não o conheço.' },
      { v: 58, en: 'After a little while someone else saw him, and said, “You also are one of them!” But Peter answered, “Man, I am not!”', pt: 'Daí a pouco, outro o viu, e disse: Tu também és um deles. Mas Pedro disse: Homem, não sou.' },
      { v: 59, en: 'After about one hour passed, another confidently affirmed, saying, “Truly this man also was with him, for he is a Galilean!”', pt: 'E, tendo passado quase uma hora, outro afirmava, dizendo: Certamente este também estava com ele, pois é galileu.' },
      { v: 60, en: 'But Peter said, “Man, I don’t know what you are talking about!” Immediately, while he was still speaking, a rooster crowed.', pt: 'Mas Pedro respondeu: Homem, não sei o que dizes. E imediatamente estando ele ainda a falar, cantou o galo.' },
      { v: 61, en: 'The Lord turned, and looked at Peter. Then Peter remembered the Lord’s word, how he said to him, “Before the rooster crows you will deny me three times.”', pt: 'Virando-se o Senhor, olhou para Pedro; e Pedro lembrou-se da palavra do Senhor, como lhe havia dito: Hoje, antes que o galo cante, três vezes me negarás.' },
      { v: 62, en: 'He went out, and wept bitterly.', pt: 'E, havendo saído, chorou amargamente.' },
      { v: 63, en: 'The men who held Jesus mocked him and beat him.', pt: 'Os homens que detinham Jesus zombavam dele, e feriam-no;' },
      { v: 64, en: 'Having blindfolded him, they struck him on the face and asked him, “Prophesy! Who is the one who struck you?”', pt: 'e, vendando-lhe os olhos, perguntavam, dizendo: Profetiza, quem foi que te bateu?' },
      { v: 65, en: 'They spoke many other things against him, insulting him.', pt: 'E, blasfemando, diziam muitas outras coisas contra ele.' },
      { v: 66, en: 'As soon as it was day, the assembly of the elders of the people were gathered together, both chief priests and scribes, and they led him away into their council, saying,', pt: 'Logo que amanheceu reuniu-se a assembléia dos anciãos do povo, tanto os principais sacerdotes como os escribas, e o conduziam ao sinédrio deles, onde lhe disseram:' },
      { v: 67, en: '“If you are the Christ, tell us.” But he said to them, “If I tell you, you won’t believe,', pt: 'Se tu és o Cristo, dize-no-lo. Replicou-lhes ele: Se eu vo-lo disser, não o crereis;' },
      { v: 68, en: 'and if I ask, you will in no way answer me or let me go.', pt: 'e se eu vos interrogar, de modo algum me respondereis.' },
      { v: 69, en: 'From now on, the Son of Man will be seated at the right hand of the power of God.”', pt: 'Mas desde agora estará assentado o Filho do homem à mão direita do poder de Deus.' },
      { v: 70, en: 'They all said, “Are you then the Son of God?” He said to them, “You say it, because I am.”', pt: 'Ao que perguntaram todos: Logo, tu és o Filho de Deus? Respondeu-lhes: Vós dizeis que eu sou.' },
      { v: 71, en: 'They said, “Why do we need any more witness? For we ourselves have heard from his own mouth!”', pt: 'Então disseram: Por que ainda temos necessidade de testemunho? pois nós mesmos o ouvimos da sua própria boca.' },
    ],
    23: [
      { v: 1, en: 'The whole company of them rose up and brought him before Pilate.', pt: 'E levantando-se toda a multidão deles, conduziram Jesus a Pilatos.' },
      { v: 2, en: 'They began to accuse him, saying, “We found this man perverting the nation, forbidding paying taxes to Caesar, and saying that he himself is Christ, a king.”', pt: 'E começaram a acusá-lo, dizendo: Achamos este homem pervertendo a nossa nação, proibindo dar o tributo a César, e dizendo ser ele mesmo Cristo, rei.' },
      { v: 3, en: 'Pilate asked him, “Are you the King of the Jews?” He answered him, “So you say.”', pt: 'Pilatos, pois, perguntou-lhe: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.' },
      { v: 4, en: 'Pilate said to the chief priests and the multitudes, “I find no basis for a charge against this man.”', pt: 'Então disse Pilatos aos principais sacerdotes, e às multidões: Não acho culpa alguma neste homem.' },
      { v: 5, en: 'But they insisted, saying, “He stirs up the people, teaching throughout all Judea, beginning from Galilee even to this place.”', pt: 'Eles, porém, insistiam ainda mais, dizendo: Alvoroça o povo ensinando por toda a Judéia, começando desde a Galiléia até aqui.' },
      { v: 6, en: 'But when Pilate heard Galilee mentioned, he asked if the man was a Galilean.', pt: 'Então Pilatos, ouvindo isso, perguntou se o homem era galileu;' },
      { v: 7, en: 'When he found out that he was in Herod’s jurisdiction, he sent him to Herod, who was also in Jerusalem during those days.', pt: 'e, quando soube que era da jurisdição de Herodes, remeteu-o a Herodes, que também naqueles dias estava em Jerusalém.' },
      { v: 8, en: 'Now when Herod saw Jesus, he was exceedingly glad, for he had wanted to see him for a long time, because he had heard many things about him. He hoped to see some miracle done by him.', pt: 'Ora, quando Herodes viu a Jesus, alegrou-se muito; pois de longo tempo desejava vê-lo, por ter ouvido falar a seu respeito; e esperava ver algum sinal feito por ele;' },
      { v: 9, en: 'He questioned him with many words, but he gave no answers.', pt: 'e fazia-lhe muitas perguntas; mas ele nada lhe respondeu.' },
      { v: 10, en: 'The chief priests and the scribes stood, vehemently accusing him.', pt: 'Estavam ali os principais sacerdotes, e os escribas, acusando-o com grande veemência.' },
      { v: 11, en: 'Herod with his soldiers humiliated him and mocked him. Dressing him in luxurious clothing, they sent him back to Pilate.', pt: 'Herodes, porém, com os seus soldados, desprezou-o e, escarnecendo dele, vestiu-o com uma roupa resplandecente e tornou a enviá-lo a Pilatos.' },
      { v: 12, en: 'Herod and Pilate became friends with each other that very day, for before that they were enemies with each other.', pt: 'Nesse mesmo dia Pilatos e Herodes tornaram-se amigos; pois antes andavam em inimizade um com o outro.' },
      { v: 13, en: 'Pilate called together the chief priests, the rulers, and the people,', pt: 'Então Pilatos convocou os principais sacerdotes, as autoridades e o povo,' },
      { v: 14, en: 'and said to them, “You brought this man to me as one that perverts the people, and behold, having examined him before you, I found no basis for a charge against this man concerning those things of which you accuse him.', pt: 'e disse-lhes: Apresentastes-me este homem como pervertedor do povo; e eis que, interrogando-o diante de vós, não achei nele nenhuma culpa, das de que o acusais;' },
      { v: 15, en: 'Neither has Herod, for I sent you to him, and see, nothing worthy of death has been done by him.', pt: 'nem tampouco Herodes, pois no-lo tornou a enviar; e eis que não tem feito ele coisa alguma digna de morte.' },
      { v: 16, en: 'I will therefore chastise him and release him.”', pt: 'Castigá-lo-ei, pois, e o soltarei.' },
      { v: 17, en: 'Now he had to release one prisoner to them at the feast.', pt: '[E era-lhe necessário soltar-lhes um pela festa.]' },
      { v: 18, en: 'But they all cried out together, saying, “Away with this man! Release to us Barabbas!”—', pt: 'Mas todos clamaram à uma, dizendo: Fora com este, e solta-nos Barrabás!' },
      { v: 19, en: 'one who was thrown into prison for a certain revolt in the city, and for murder.', pt: 'Ora, Barrabás fora lançado na prisão por causa de uma sedição feita na cidade, e de um homicídio.' },
      { v: 20, en: 'Then Pilate spoke to them again, wanting to release Jesus,', pt: 'Mais uma vez, pois, falou-lhes Pilatos, querendo soltar a Jesus.' },
      { v: 21, en: 'but they shouted, saying, “Crucify! Crucify him!”', pt: 'Eles, porém, brandavam, dizendo: Crucifica-o! crucifica-o!' },
      { v: 22, en: 'He said to them the third time, “Why? What evil has this man done? I have found no capital crime in him. I will therefore chastise him and release him.”', pt: 'Falou-lhes, então, pela terceira vez: Pois, que mal fez ele? Não achei nele nenhuma culpa digna de morte. Castigá-lo-ei, pois, e o soltarei.' },
      { v: 23, en: 'But they were urgent with loud voices, asking that he might be crucified. Their voices and the voices of the chief priests prevailed.', pt: 'Mas eles instavam com grandes brados, pedindo que fosse crucificado. E prevaleceram os seus clamores.' },
      { v: 24, en: 'Pilate decreed that what they asked for should be done.', pt: 'Então Pilatos resolveu atender-lhes o pedido;' },
      { v: 25, en: 'He released him who had been thrown into prison for insurrection and murder, for whom they asked, but he delivered Jesus up to their will.', pt: 'e soltou-lhes o que fora lançado na prisão por causa de sedição e de homicídio, que era o que eles pediam; mas entregou Jesus à vontade deles.' },
      { v: 26, en: 'When they led him away, they grabbed one Simon of Cyrene, coming from the country, and laid on him the cross, to carry it after Jesus.', pt: 'Quando o levaram dali tomaram um certo Simão, cireneu, que vinha do campo, e puseram-lhe a cruz às costas, para que a levasse após Jesus.' },
      { v: 27, en: 'A great multitude of the people followed him, including women who also mourned and lamented him.', pt: 'Seguia-o grande multidão de povo e de mulheres, as quais o pranteavam e lamentavam.' },
      { v: 28, en: 'But Jesus, turning to them, said, “Daughters of Jerusalem, don’t weep for me, but weep for yourselves and for your children.', pt: 'Jesus, porém, voltando-se para elas, disse: Filhas de Jerusalém, não choreis por mim; chorai antes por vós mesmas, e por vossos filhos.' },
      { v: 29, en: 'For behold, the days are coming in which they will say, ‘Blessed are the barren, the wombs that never bore, and the breasts that never nursed.’', pt: 'Porque dias hão de vir em que se dirá: Bem-aventuradas as estéreis, e os ventres que não geraram, e os peitos que não amamentaram!' },
      { v: 30, en: 'Then they will begin to tell the mountains, ‘Fall on us!’ and tell the hills, ‘Cover us.’', pt: 'Então começarão a dizer aos montes: Caí sobre nós; e aos outeiros: Cobri-nos.' },
      { v: 31, en: 'For if they do these things in the green tree, what will be done in the dry?”', pt: 'Porque, se isto se faz no lenho verde, que se fará no seco?' },
      { v: 32, en: 'There were also others, two criminals, led with him to be put to death.', pt: 'E levavam também com ele outros dois, que eram malfeitores, para serem mortos.' },
      { v: 33, en: 'When they came to the place that is called The Skull, they crucified him there with the criminals, one on the right and the other on the left.', pt: 'Quando chegaram ao lugar chamado Caveira, ali o crucificaram, a ele e também aos malfeitores, um à direita e outro à esquerda.' },
      { v: 34, en: 'Jesus said, “Father, forgive them, for they don’t know what they are doing.” Dividing his garments among them, they cast lots.', pt: 'Jesus, porém, dizia: Pai, perdoa-lhes; porque não sabem o que fazem. Então repartiram as vestes dele, deitando sortes sobre elas.' },
      { v: 35, en: 'The people stood watching. The rulers with them also scoffed at him, saying, “He saved others. Let him save himself, if this is the Christ of God, his chosen one!”', pt: 'E o povo estava ali a olhar. E as próprias autoridades zombavam dele, dizendo: Aos outros salvou; salve-se a si mesmo, se é o Cristo, o escolhido de Deus.' },
      { v: 36, en: 'The soldiers also mocked him, coming to him and offering him vinegar,', pt: 'Os soldados também o escarneciam, chegando-se a ele, oferecendo-lhe vinagre,' },
      { v: 37, en: 'and saying, “If you are the King of the Jews, save yourself!”', pt: 'e dizendo: Se tu és o rei dos judeus, salva-te a ti mesmo.' },
      { v: 38, en: 'An inscription was also written over him in letters of Greek, Latin, and Hebrew: “THIS IS THE KING OF THE JEWS.”', pt: 'Por cima dele estava esta inscrição [em letras gregas, romanas e hebraicas:] ESTE É O REI DOS JUDEUS.' },
      { v: 39, en: 'One of the criminals who was hanged insulted him, saying, “If you are the Christ, save yourself and us!”', pt: 'Então um dos malfeitores que estavam pendurados, blasfemava dele, dizendo: Não és tu o Cristo? salva-te a ti mesmo e a nós.' },
      { v: 40, en: 'But the other answered, and rebuking him said, “Don’t you even fear God, seeing you are under the same condemnation?', pt: 'Respondendo, porém, o outro, repreendia-o, dizendo: Nem ao menos temes a Deus, estando na mesma condenação?' },
      { v: 41, en: 'And we indeed justly, for we receive the due reward for our deeds, but this man has done nothing wrong.”', pt: 'E nós, na verdade, com justiça; porque recebemos o que os nossos feitos merecem; mas este nenhum mal fez.' },
      { v: 42, en: 'He said to Jesus, “Lord, remember me when you come into your Kingdom.”', pt: 'Então disse: Jesus, lembra-te de mim, quando entrares no teu reino.' },
      { v: 43, en: 'Jesus said to him, “Assuredly I tell you, today you will be with me in Paradise.”', pt: 'Respondeu-lhe Jesus: Em verdade te digo que hoje estarás comigo no paraíso.' },
      { v: 44, en: 'It was now about the sixth hour, and darkness came over the whole land until the ninth hour.', pt: 'Era já quase a hora sexta, e houve trevas em toda a terra até a hora nona, pois o sol se escurecera;' },
      { v: 45, en: 'The sun was darkened, and the veil of the temple was torn in two.', pt: 'e rasgou-se ao meio o véu do santuário.' },
      { v: 46, en: 'Jesus, crying with a loud voice, said, “Father, into your hands I commit my spirit!” Having said this, he breathed his last.', pt: 'Jesus, clamando com grande voz, disse: Pai, nas tuas mãos entrego o meu espírito. E, havendo dito isso, expirou.' },
      { v: 47, en: 'When the centurion saw what was done, he glorified God, saying, “Certainly this was a righteous man.”', pt: 'Quando o centurião viu o que acontecera, deu glória a Deus, dizendo: Na verdade, este homem era justo.' },
      { v: 48, en: 'All the multitudes that came together to see this, when they saw the things that were done, returned home beating their breasts.', pt: 'E todas as multidões que presenciaram este espetáculo, vendo o que havia acontecido, voltaram batendo no peito.' },
      { v: 49, en: 'All his acquaintances, and the women who followed with him from Galilee, stood at a distance, watching these things.', pt: 'Entretanto, todos os conhecidos de Jesus, e as mulheres que o haviam seguido desde a Galiléia, estavam de longe vendo estas coisas.' },
      { v: 50, en: 'Behold, a man named Joseph, who was a member of the council, a good and righteous man', pt: 'Então um homem chamado José, natural de Arimatéia, cidade dos judeus, membro do sinédrio, homem bom e justo,' },
      { v: 51, en: '(he had not consented to their counsel and deed), from Arimathaea, a city of the Jews, who was also waiting for God’s Kingdom:', pt: 'o qual não tinha consentido no conselho e nos atos dos outros, e que esperava o reino de Deus,' },
      { v: 52, en: 'this man went to Pilate, and asked for Jesus’ body.', pt: 'chegando a Pilatos, pediu-lhe o corpo de Jesus;' },
      { v: 53, en: 'He took it down, and wrapped it in a linen cloth, and laid him in a tomb that was cut in stone, where no one had ever been laid.', pt: 'e tirando-o da cruz, envolveu-o num pano de linho, e pô-lo num sepulcro escavado em rocha, onde ninguém ainda havia sido posto.' },
      { v: 54, en: 'It was the day of the Preparation, and the Sabbath was drawing near.', pt: 'Era o dia da preparação, e ia começar o sábado.' },
      { v: 55, en: 'The women, who had come with him out of Galilee, followed after, and saw the tomb, and how his body was laid.', pt: 'E as mulheres que tinham vindo com ele da Galiléia, seguindo a José, viram o sepulcro, e como o corpo foi ali depositado.' },
      { v: 56, en: 'They returned, and prepared spices and ointments. On the Sabbath they rested according to the commandment.', pt: 'Então voltaram e prepararam especiarias e unguentos. E no sábado repousaram, conforme o mandamento.' },
    ],
    24: [
      { v: 1, en: 'But on the first day of the week, at early dawn, they and some others came to the tomb, bringing the spices which they had prepared.', pt: 'Mas já no primeiro dia da semana, bem de madrugada, foram elas ao sepulcro, levando as especiarias que tinham preparado.' },
      { v: 2, en: 'They found the stone rolled away from the tomb.', pt: 'E acharam a pedra revolvida do sepulcro.' },
      { v: 3, en: 'They entered in, and didn’t find the Lord Jesus’ body.', pt: 'Entrando, porém, não acharam o corpo do Senhor Jesus.' },
      { v: 4, en: 'While they were greatly perplexed about this, behold, two men stood by them in dazzling clothing.', pt: 'E, estando elas perplexas a esse respeito, eis que lhes apareceram dois varões em vestes resplandecentes;' },
      { v: 5, en: 'Becoming terrified, they bowed their faces down to the earth. They said to them, “Why do you seek the living among the dead?', pt: 'e ficando elas atemorizadas e abaixando o rosto para o chão, eles lhes disseram: Por que buscais entre os mortos aquele que vive?' },
      { v: 6, en: 'He isn’t here, but is risen. Remember what he told you when he was still in Galilee,', pt: 'Ele não está aqui, mas ressurgiu. Lembrai-vos de como vos falou, estando ainda na Galiléia.' },
      { v: 7, en: 'saying that the Son of Man must be delivered up into the hands of sinful men, and be crucified, and the third day rise again?”', pt: 'dizendo: Importa que o Filho do homem seja entregue nas mãos de homens pecadores, e seja crucificado, e ao terceiro dia ressurja.' },
      { v: 8, en: 'They remembered his words,', pt: 'Lembraram-se, então, das suas palavras;' },
      { v: 9, en: 'returned from the tomb, and told all these things to the eleven, and to all the rest.', pt: 'e, voltando do sepulcro, anunciaram todas estas coisas aos onze e a todos os demais.' },
      { v: 10, en: 'Now they were Mary Magdalene, Joanna, and Mary the mother of James. The other women with them told these things to the apostles.', pt: 'E eram Maria Madalena, e Joana, e Maria, mãe de Tiago; também as outras que estavam com elas relataram estas coisas aos apóstolos.' },
      { v: 11, en: 'These words seemed to them to be nonsense, and they didn’t believe them.', pt: 'E pareceram-lhes como um delírio as palavras das mulheres e não lhes deram crédito.' },
      { v: 12, en: 'But Peter got up and ran to the tomb. Stooping and looking in, he saw the strips of linen lying by themselves, and he departed to his home, wondering what had happened.', pt: 'Mas Pedro, levantando-se, correu ao sepulcro; e, abaixando-se, viu somente os panos de linho; e retirou-se, admirando consigo o que havia acontecido.' },
      { v: 13, en: 'Behold, two of them were going that very day to a village named Emmaus, which was sixty stadia from Jerusalem.', pt: 'Nesse mesmo dia, iam dois deles para uma aldeia chamada Emaús, que distava de Jerusalém sessenta estádios;' },
      { v: 14, en: 'They talked with each other about all of these things which had happened.', pt: 'e iam comentando entre si tudo aquilo que havia sucedido.' },
      { v: 15, en: 'While they talked and questioned together, Jesus himself came near, and went with them.', pt: 'Enquanto assim comentavam e discutiam, o próprio Jesus se aproximou, e ia com eles;' },
      { v: 16, en: 'But their eyes were kept from recognizing him.', pt: 'mas os olhos deles estavam como que fechados, de sorte que não o reconheceram.' },
      { v: 17, en: 'He said to them, “What are you talking about as you walk, and are sad?”', pt: 'Então ele lhes perguntou: Que palavras são essas que, caminhando, trocais entre vós? Eles então pararam tristes.' },
      { v: 18, en: 'One of them, named Cleopas, answered him, “Are you the only stranger in Jerusalem who doesn’t know the things which have happened there in these days?”', pt: 'E um deles, chamado Cleopas, respondeu-lhe: És tu o único peregrino em Jerusalém que não soube das coisas que nela têm sucedido nestes dias?' },
      { v: 19, en: 'He said to them, “What things?” They said to him, “The things concerning Jesus, the Nazarene, who was a prophet mighty in deed and word before God and all the people;', pt: 'Ao que ele lhes perguntou: Quais? Disseram-lhe: As que dizem respeito a Jesus, o nazareno, que foi profeta, poderoso em obras e palavras diante de Deus e de todo o povo.' },
      { v: 20, en: 'and how the chief priests and our rulers delivered him up to be condemned to death, and crucified him.', pt: 'e como os principais sacerdotes e as nossas autoridades e entregaram para ser condenado à morte, e o crucificaram.' },
      { v: 21, en: 'But we were hoping that it was he who would redeem Israel. Yes, and besides all this, it is now the third day since these things happened.', pt: 'Ora, nós esperávamos que fosse ele quem havia de remir Israel; e, além de tudo isso, é já hoje o terceiro dia desde que essas coisas aconteceram.' },
      { v: 22, en: 'Also, certain women of our company amazed us, having arrived early at the tomb;', pt: 'Verdade é, também, que algumas mulheres do nosso meio nos encheram de espanto; pois foram de madrugada ao sepulcro' },
      { v: 23, en: 'and when they didn’t find his body, they came saying that they had also seen a vision of angels, who said that he was alive.', pt: 'e, não achando o corpo dele voltaram, declarando que tinham tido uma visão de anjos que diziam estar ele vivo.' },
      { v: 24, en: 'Some of us went to the tomb, and found it just like the women had said, but they didn’t see him.”', pt: 'Além disso, alguns dos que estavam conosco foram ao sepulcro, e acharam ser assim como as mulheres haviam dito; a ele, porém, não o viram.' },
      { v: 25, en: 'He said to them, “Foolish men, and slow of heart to believe in all that the prophets have spoken!', pt: 'Então ele lhes disse: Ó néscios, e tardos de coração para crerdes tudo o que os profetas disseram!' },
      { v: 26, en: 'Didn’t the Christ have to suffer these things and to enter into his glory?”', pt: 'Porventura não importa que o Cristo padecesse essas coisas e entrasse na sua glória?' },
      { v: 27, en: 'Beginning from Moses and from all the prophets, he explained to them in all the Scriptures the things concerning himself.', pt: 'E, começando por Moisés, e por todos os profetas, explicou-lhes o que dele se achava em todas as Escrituras.' },
      { v: 28, en: 'They came near to the village, where they were going, and he acted like he would go further.', pt: 'Quando se aproximaram da aldeia para onde iam, ele fez como quem ia para mais longe.' },
      { v: 29, en: 'They urged him, saying, “Stay with us, for it is almost evening, and the day is almost over.” He went in to stay with them.', pt: 'Eles, porém, o constrangeram, dizendo: Fica conosco; porque é tarde, e já declinou o dia. E entrou para ficar com eles.' },
      { v: 30, en: 'When he had sat down at the table with them, he took the bread and gave thanks. Breaking it, he gave it to them.', pt: 'Estando com eles à mesa, tomou o pão e o abençoou; e, partindo-o, lho dava.' },
      { v: 31, en: 'Their eyes were opened, and they recognized him, and he vanished out of their sight.', pt: 'Abriram-se-lhes então os olhos, e o reconheceram; nisto ele desapareceu de diante deles.' },
      { v: 32, en: 'They said to one another, “Weren’t our hearts burning within us, while he spoke to us along the way, and while he opened the Scriptures to us?”', pt: 'E disseram um para o outro: Porventura não se nos abrasava o coração, quando pelo caminho nos falava, e quando nos abria as Escrituras?' },
      { v: 33, en: 'They rose up that very hour, returned to Jerusalem, and found the eleven gathered together, and those who were with them,', pt: 'E na mesma hora levantaram-se e voltaram para Jerusalém, e encontraram reunidos os onze e os que estavam com eles,' },
      { v: 34, en: 'saying, “The Lord is risen indeed, and has appeared to Simon!”', pt: 'os quais diziam: Realmente o Senhor ressurgiu, e apareceu a Simão.' },
      { v: 35, en: 'They related the things that happened along the way, and how he was recognized by them in the breaking of the bread.', pt: 'Então os dois contaram o que acontecera no caminho, e como se lhes fizera conhecer no partir do pão.' },
      { v: 36, en: 'As they said these things, Jesus himself stood among them, and said to them, “Peace be to you.”', pt: 'Enquanto ainda falavam nisso, o próprio Jesus se apresentou no meio deles, e disse-lhes: Paz seja convosco.' },
      { v: 37, en: 'But they were terrified and filled with fear, and supposed that they had seen a spirit.', pt: 'Mas eles, espantados e atemorizados, pensavam que viam algum espírito.' },
      { v: 38, en: 'He said to them, “Why are you troubled? Why do doubts arise in your hearts?', pt: 'Ele, porém, lhes disse: Por que estais perturbados? e por que surgem dúvidas em vossos corações?' },
      { v: 39, en: 'See my hands and my feet, that it is truly me. Touch me and see, for a spirit doesn’t have flesh and bones, as you see that I have.”', pt: 'Olhai as minhas mãos e os meus pés, que sou eu mesmo; apalpai-me e vede; porque um espírito não tem carne nem ossos, como percebeis que eu tenho.' },
      { v: 40, en: 'When he had said this, he showed them his hands and his feet.', pt: 'E, dizendo isso, mostrou-lhes as mãos e os pés.' },
      { v: 41, en: 'While they still didn’t believe for joy, and wondered, he said to them, “Do you have anything here to eat?”', pt: 'Não acreditando eles ainda por causa da alegria, e estando admirados, perguntou-lhes Jesus: Tendes aqui alguma coisa que comer?' },
      { v: 42, en: 'They gave him a piece of a broiled fish and some honeycomb.', pt: 'Então lhe deram um pedaço de peixe assado,' },
      { v: 43, en: 'He took them, and ate in front of them.', pt: 'o qual ele tomou e comeu diante deles.' },
      { v: 44, en: 'He said to them, “This is what I told you, while I was still with you, that all things which are written in the law of Moses, the prophets, and the psalms, concerning me must be fulfilled.”', pt: 'Depois lhe disse: São estas as palavras que vos falei, estando ainda convosco, que importava que se cumprisse tudo o que de mim estava escrito na Lei de Moisés, nos Profetas e nos Salmos.' },
      { v: 45, en: 'Then he opened their minds, that they might understand the Scriptures.', pt: 'Então lhes abriu o entendimento para compreenderem as Escrituras;' },
      { v: 46, en: 'He said to them, “Thus it is written, and thus it was necessary for the Christ to suffer and to rise from the dead the third day,', pt: 'e disse-lhes: Assim está escrito que o Cristo padecesse, e ao terceiro dia ressurgisse dentre os mortos;' },
      { v: 47, en: 'and that repentance and remission of sins should be preached in his name to all the nations, beginning at Jerusalem.', pt: 'e que em seu nome se pregasse o arrependimento para remissão dos pecados, a todas as nações, começando por Jerusalém.' },
      { v: 48, en: 'You are witnesses of these things.', pt: 'Vós sois testemunhas destas coisas.' },
      { v: 49, en: 'Behold, I send out the promise of my Father on you. But wait in the city of Jerusalem until you are clothed with power from on high.”', pt: 'E eis que sobre vós envio a promessa de meu Pai; ficai porém, na cidade, até que do alto sejais revestidos de poder.' },
      { v: 50, en: 'He led them out as far as Bethany, and he lifted up his hands, and blessed them.', pt: 'Então os levou fora, até Betânia; e levantando as mãos, os abençoou.' },
      { v: 51, en: 'While he blessed them, he withdrew from them, and was carried up into heaven.', pt: 'E aconteceu que, enquanto os abençoava, apartou-se deles; e foi elevado ao céu.' },
      { v: 52, en: 'They worshiped him, and returned to Jerusalem with great joy,', pt: 'E, depois de o adorarem, voltaram com grande júbilo para Jerusalém;' },
      { v: 53, en: 'and were continually in the temple, praising and blessing God. Amen.', pt: 'e estavam continuamente no templo, bendizendo a Deus.' },
    ],
  },
};

export default book;
